/**
 * Derive the per-call search timeout from the host cap declared in
 * `.claude/settings.json`. Returns `{timeoutMs, warning?}` so callers can
 * surface fallback warnings to the debug log.
 *
 * Pattern: mt#1546 introduced `readHostCap` precisely to avoid the
 * hardcoded-timeout drift this PR's first round flagged. We use a single
 * 70% ratio rather than `deriveBudgets`'s git-tailored ratios because this
 * hook makes one external call (not a sequence of git probes).
 */
export function deriveSearchTimeoutMs(): { timeoutMs: number; warning?: string } {
  const cap = readHostCap(HOOK_FILENAME, undefined, { events: ["UserPromptSubmit"] });
  const timeoutMs = Math.max(
    MIN_SEARCH_TIMEOUT_MS,
    Math.floor(cap.hostCapSec * 1000 * SEARCH_TIMEOUT_RATIO)
  );
  return { timeoutMs, warning: cap.warning };
}

/**
 * Invoke `minsky memory search` and return the parsed response.
 *
 * Returns null when the CLI fails, times out, or produces unparseable output.
 * The caller treats null as "skip injection" — same posture as degraded results.
 *
 * The returned `warning` carries any host-cap fallback signal from
 * `deriveSearchTimeoutMs` (CLAUDE_PROJECT_DIR unset, settings.json missing,
 * no matcher entry). Operators see this in the debug log so misconfigured
 * `.claude/settings.json` is detectable. Per round-2 BLOCKING #2.
 *
 * `timeoutMs` defaults to the value derived from the host cap; tests can
 * override to exercise edge cases hermetically. When provided, no warning
 * is generated (the caller has already taken responsibility for the value).
 */
export function runMemorySearch(
  query: string,
  k: number = DEFAULT_K,
  timeoutMs?: number
): {
  response: MemorySearchResponseLite | null;
  latencyMs: number;
  error?: string;
  warning?: string;
} {
  // Truncate overlong queries — embeddings degrade past ~500 chars and we don't
  // want to ship multi-page prompts as the search input.
  const truncatedQuery = query.length > MAX_QUERY_LENGTH ? query.slice(0, MAX_QUERY_LENGTH) : query;

  // Canary stub seam (mt#3004): replace ONLY the subprocess call; everything
  // downstream (parse, degraded/empty branches, injection build) is the real
  // production path.
  const stubPath = process.env[CANARY_STUB_ENV];
  if (stubPath) {
    const stubStart = Date.now();
    let raw: string;
    try {
      raw = readFileSync(stubPath, "utf8");
    } catch (err) {
      return {
        response: null,
        latencyMs: Date.now() - stubStart,
        error: `canary-stub-read-failed: ${err instanceof Error ? err.message : String(err)}`,
      };
    }
    const stubParsed = parseSearchOutput(raw);
    if (!stubParsed) {
      return {
        response: null,
        latencyMs: Date.now() - stubStart,
        error: "canary-stub-unparseable",
      };
    }
    return { response: stubParsed, latencyMs: Date.now() - stubStart };
  }

  let effectiveTimeout: number;
  let derivationWarning: string | undefined;
  if (typeof timeoutMs === "number") {
    effectiveTimeout = timeoutMs;
  } else {
    const derived = deriveSearchTimeoutMs();
    effectiveTimeout = derived.timeoutMs;
    derivationWarning = derived.warning;
  }

  const start = Date.now();
  const result = execWithPath(
    ["minsky", "memory", "search", truncatedQuery, "--limit", String(k)],
    { timeout: effectiveTimeout }
  );
  const latencyMs = Date.now() - start;

  if (result.timedOut) {
    return { response: null, latencyMs, error: "timeout", warning: derivationWarning };
  }
  if (result.exitCode !== 0) {
    return {
      response: null,
      latencyMs,
      error: `exit ${result.exitCode}: ${(result.stderr || result.stdout).slice(0, 200)}`,
      warning: derivationWarning,
    };
  }

  const parsed = parseSearchOutput(result.stdout);
  if (!parsed) {

    typeof (lrp as Record<string, unknown>)["currentHead"] === "string"
  ) {
    return {
      lastReportedPair: {
        startCommit: (lrp as Record<string, unknown>)["startCommit"] as string,
        currentHead: (lrp as Record<string, unknown>)["currentHead"] as string,
      },
    };
  }
  return null;
}

/**
 * Write the session tracker atomically (write-then-rename).
 * Failures are swallowed — the hook is informational.
 */
export function writeTracker(
  trackerPath: string,
  tracker: SessionTracker,
  fs: FsDeps = REAL_FS
): void {
  try {
    fs.mkdirSync(dirname(trackerPath), { recursive: true });
    const tmp = `${trackerPath}.tmp.${process.pid}`;
    fs.writeFileSync(tmp, JSON.stringify(tracker), "utf8");
    fs.renameSync(tmp, trackerPath);
  } catch {
    // Best-effort
  }
}

// ---------------------------------------------------------------------------
// Warning construction
// ---------------------------------------------------------------------------

/**
 * Build the warning message injected as additionalContext.
 */
export function buildWarning(
  startCommit: string,
  startTimestamp: string,
  currentHead: string,
  changedSrcPaths: string[]
): string {
  const n = changedSrcPaths.length;
  const head = changedSrcPaths.slice(0, MAX_PATHS_LISTED);
  const overflow = n - head.length;

  const pathLines = head.map((p) => `  - ${p}`);
  if (overflow > 0) {
    pathLines.push(`  + ${overflow} more`);
  }

  const lines = [
    `⚠️ Minsky MCP daemon is stale. Daemon started at commit ${startCommit.slice(0, 9)} (${startTimestamp}); HEAD is now ${currentHead.slice(0, 9)}. ${n} file${n === 1 ? "" : "s"} under src/ have changed since startup.`,
    ...pathLines,
    `The next MCP tool call may return a single transport error as the stale daemon exits rather than serve stale code; the stdio respawn proxy then respawns it at the new HEAD automatically — just retry the call. Run \`/mcp\` only if retries keep failing. Do not block work waiting on a manual reconnect.`,
  ];

  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// Pure decision core (exported for tests)
// ---------------------------------------------------------------------------

export interface DecideResult {
  /** Warning to inject, or null for no injection. */
  injection: string | null;
  /** Updated tracker to write, or null if no update needed. */
  newTracker: SessionTracker | null;
  /** The resolved tracker path. */
  trackerPath: string;
  /** Log summary for debugging. */
  log: {
    sessionId: string;
    skipped: boolean;
    skipReason?: string;
    warned?: boolean;
    changedSrcCount?: number;
  };
}

export function decideAndUpdate(args: {
  projectDir: string;
  sessionId: string;
  env: NodeJS.ProcessEnv;
  fs?: FsDeps;
  git?: GitDeps;
  homeOverride?: string;
  trackerPathOverride?: string;
}): DecideResult {
  const fs = args.fs ?? REAL_FS;
  const git = args.git ?? REAL_GIT;
  const home = args.homeOverride ?? args.env[TRACKER_HOME_ENV] ?? homedir();
  const trackerPath =
    args.trackerPathOverride ?? resolveTrackerPath(args.projectDir, args.sessionId, home);

  // Opt-out short-circuit.
  const optOut = (args.env[OPT_OUT_ENV] ?? "").toLowerCase();
  if (optOut === "1" || optOut === "true" || optOut === "yes") {
    return {
      injection: null,
      newTracker: null,
      trackerPath,
      log: { sessionId: args.sessionId, skipped: true, skipReason: "opt-out" },
    };
  }

  // Read daemon state file.
  const statePath = getDaemonStatePath(args.env);
  const daemonState = readDaemonStateFile(statePath, fs);
  if (!daemonState) {
    return {
      injection: null,
      newTracker: null,
      trackerPath,
      log: { sessionId: args.sessionId, skipped: true, skipReason: "no-daemon-state" },
    };
  }

  // HTTP transport: skip staleness detection. HTTP sessions reconnect
  // automatically via Claude Code's exponential backoff; the /mcp click is
  // stdio-specific. State file field missing = pre-fix daemon = treat as stdio.
  if (daemonState.transport === "http") {
    return {
      injection: null,
      newTracker: null,
      trackerPath,
      log: { sessionId: args.sessionId, skipped: true, skipReason: "http-transport-out-of-scope" },
    };
  }

  // Use the minskyHomeDir embedded by the daemon — same path it used for
  // startCommit, so the comparison is symmetric (BLOCKING 1, PR #1035 R1).
  // If the field is absent (pre-fix daemon wrote the file), skip gracefully.
  const minskyHomeDir = daemonState.minskyHomeDir;
  if (!minskyHomeDir) {
    return {
      injection: null,
      newTracker: null,
      trackerPath,
      log: { sessionId: args.sessionId, skipped: true, skipReason: "no-minsky-home" },
    };
  }

  // Resolve current HEAD.
  const currentHead = git.resolveHead(minskyHomeDir);
  if (!currentHead) {
    return {
      injection: null,
      newTracker: null,
      trackerPath,
      log: { sessionId: args.sessionId, skipped: true, skipReason: "no-current-head" },
    };
  }

  // If commits match, nothing to do.
  if (currentHead === daemonState.startCommit) {
    return {
      injection: null,

      prompt_prefix: entry.promptPrefix,
      prompt_length: entry.promptLength,
    },
    output,
    metadata: {
      sessionId: entry.sessionId,
      variant,
      k: DEFAULT_K,
      tokenBudget: DEFAULT_TOKEN_BUDGET,
      minPromptLength: MIN_PROMPT_LENGTH,
      latencyMs: entry.latencyMs,
      hookVersion: HOOK_VERSION,
      warning: entry.warning,
      source: "minsky.hooks.memory-search",
    },
  });
}

