/**
 * Guard-dispatcher entry point. Mirrors `main()`'s orchestration but returns
 * a `GuardOutcome` instead of writing to stdout / calling `process.exit` —
 * the dispatcher owns stdout and aggregates every matched guard's output
 * (D1). Logging (`writeLog`) and Braintrust telemetry (`emitBraintrust`) are
 * preserved as side effects on every branch, matching `main()` exactly; this
 * guard has no calibration log — `additionalContext` only.
 */
export async function run(
  input: ClaudeHookInput,
  _ctx: DispatchContext
): Promise<GuardOutcome | null> {
  // Explicit event guard, matching the sibling injection hooks
  // (inject-current-time, inject-git-state, inject-prod-state,
  // inject-dispatch-watchdog) — in practice the dispatcher only invokes
  // UserPromptSubmit-registered guards for the UserPromptSubmit event, but
  // this keeps `run()` safe if ever called directly / matched differently.

  writeFileSync: (path: string, data: string, encoding: "utf8") => void;
  mkdirSync: (path: string, options: { recursive: true }) => void;
  renameSync: (from: string, to: string) => void;
}

const REAL_FS: FsDeps = {
  existsSync,
  readFileSync,
  writeFileSync,
  mkdirSync,
  renameSync,
};

// ---------------------------------------------------------------------------
// Git subprocess surface (for testability)
// ---------------------------------------------------------------------------

export interface GitDeps {
  /**
   * Run `git rev-parse HEAD` in `repoDir`.
   * Returns the full SHA string or null on failure.
   */
  resolveHead: (repoDir: string) => string | null;
  /**
   * Run `git diff --name-only <from>..<to>` in `repoDir`.
   * Returns array of changed file paths or null on failure.
   */
  diffNames: (repoDir: string, from: string, to: string) => string[] | null;
}

export const REAL_GIT: GitDeps = {
  resolveHead(repoDir: string): string | null {
    try {
      const result = execWithPath(["git", "rev-parse", "HEAD"], {
        cwd: repoDir,
        timeout: 5000,
      });
      if (result.exitCode !== 0) return null;
      const sha = result.stdout.trim();
      if (/^[0-9a-f]{7,}$/i.test(sha)) return sha;
      return null;
    } catch {
      return null;
    }
  },

  diffNames(repoDir: string, from: string, to: string): string[] | null {
    try {
      const result = execWithPath(["git", "diff", "--name-only", `${from}..${to}`], {
        cwd: repoDir,
        timeout: 5000,
      });
      if (result.exitCode !== 0) return null;
      const text = result.stdout.trim();
      if (text === "") return [];
      return text.split("\n").filter((p) => p.length > 0);
    } catch {
      return null;
    }
  },
};

// ---------------------------------------------------------------------------
// Inline daemon-state reader (mirrors readDaemonState in src/mcp/daemon-state.ts)
// ---------------------------------------------------------------------------

/**
 * Resolve the daemon state file path. Mirrors daemon-state.ts's
 * getDaemonStatePath(). Reads from MINSKY_STATE_DIR env override when set.
 */
export function getDaemonStatePath(env: NodeJS.ProcessEnv = process.env): string {
  const envDir = env["MINSKY_STATE_DIR"];
  if (envDir) return join(envDir, "mcp-daemon-state.json");
  return join(homedir(), ".local", "state", "minsky", "mcp-daemon-state.json");
}

/**
 * Read and validate the daemon state file. Returns null if missing,
 * unreadable, or shape-invalid. Mirrors readDaemonState() in daemon-state.ts
 * (inlined here to avoid a cross-boundary src/ import).
 */
export function readDaemonStateFile(statePath: string, fs: FsDeps = REAL_FS): DaemonState | null {
  if (!fs.existsSync(statePath)) return null;
  let raw: string;
  try {
    raw = fs.readFileSync(statePath, "utf8");
  } catch {
    return null;
  }
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return null;
  }
  if (!parsed || typeof parsed !== "object") return null;
  const obj = parsed as Record<string, unknown>;
  if (
    typeof obj["startCommit"] !== "string" ||
    typeof obj["startTimestamp"] !== "string" ||
    typeof obj["pid"] !== "number" ||
    typeof obj["serverName"] !== "string" ||
    typeof obj["minskyHomeDir"] !== "string" ||
    (obj["transport"] !== "stdio" && obj["transport"] !== "http")
  ) {
    return null;
  }
  return {
    startCommit: obj["startCommit"] as string,
    startTimestamp: obj["startTimestamp"] as string,
    pid: obj["pid"] as number,
    serverName: obj["serverName"] as string,
    minskyHomeDir: obj["minskyHomeDir"] as string,
    transport: obj["transport"] as "stdio" | "http",
  };
}

// ---------------------------------------------------------------------------
// Minsky home dir resolver (mirrors resolveMinskyHomeDir in daemon-state.ts)
// ---------------------------------------------------------------------------

/**
 * Resolve the Minsky working tree directory. Mirrors resolveMinskyHomeDir()
 * in daemon-state.ts (inlined here to avoid a cross-boundary src/ import).
 *
 * Priority:
 *   1. $MINSKY_HOME env var
 *   2. Standard bun global install symlink (~/.bun/install/global/node_modules/minsky)
 *   3. Fallback: null (caller must handle)
 */
export function resolveMinskyHomeDir(
  env: NodeJS.ProcessEnv = process.env,
  fs: FsDeps = REAL_FS
): string | null {
  const envOverride = env["MINSKY_HOME"];
  if (envOverride) return envOverride;

  const bunGlobal = join(homedir(), ".bun", "install", "global", "node_modules", "minsky");
  if (fs.existsSync(bunGlobal)) return bunGlobal;

  return null;
}

// ---------------------------------------------------------------------------
// Tracker file helpers
// ---------------------------------------------------------------------------

/**
 * Encode a project directory path into a stable directory name.
 * Mirrors the pattern used by skill-staleness-detector.ts.
 */
export function encodeProjectDir(absPath: string): string {
  return absPath.replace(/[/\\]/g, "-").replace(/^-/, "");
}

/**
 * Resolve the per-session tracker file path.
 * Layout: ~/.claude/mcp-daemon-staleness/<encoded-cwd>/<session_id>.json
 */
export function resolveTrackerPath(
  projectDir: string,

// to null (mirrors the `writeCwdMatchLink` precedence note above).
const resolvedProjectId = await resolveIngestProjectId(session.cwd, this.db);

// Fields restricted to insert-only (harness, cwd, project_dir, started_at)
// are not overwritten on conflict.
try {
  await this.db
    .insert(agentTranscriptsTable)
    .values({
      agentSessionId,
      harness,
      transcript: newLines,
      startedAt: startedAt ?? undefined,
      endedAt: endedAt ?? undefined,
      // mt#1445: use the session's recovered working directory if the
      // source could provide one; otherwise leave the column NULL rather
      // than substituting the JSONL path. Downstream consumers querying
      // `cwd` expect a working directory, not a transcript path.
      cwd: session.cwd ?? undefined,
      projectDir: deriveProjectDir(jsonlPath),
      projectId: resolvedProjectId ?? undefined,
      lastIngestedJsonlTimestamp: latestTs ?? undefined,
      ingestedAt: new Date(),
    })
    .onConflictDoUpdate({
      target: agentTranscriptsTable.agentSessionId,
      set: {
        transcript: sql`COALESCE(${agentTranscriptsTable.transcript}, '[]'::jsonb) || (
          SELECT COALESCE(jsonb_agg(new_elem ORDER BY ord), '[]'::jsonb)
          FROM jsonb_array_elements(EXCLUDED.transcript) WITH ORDINALITY AS t(new_elem, ord)
          WHERE (new_elem->>'uuid') IS NULL
            OR NOT EXISTS (
              SELECT 1
              FROM jsonb_array_elements(COALESCE(${agentTranscriptsTable.transcript}, '[]'::jsonb)) AS existing_elem
              WHERE existing_elem->>'uuid' = new_elem->>'uuid'
            )
        )`,
        endedAt: sql`EXCLUDED.ended_at`,
        // NULL-safety: Postgres GREATEST *ignores* NULL arguments (result
        // is NULL only when ALL args are NULL) — unlike MySQL, where any
        // NULL poisons the result. GREATEST(NULL, ts) = ts here, so a
        // NULL existing watermark advances and a NULL incoming one cannot
        // regress a stored value. Verified empirically on PG17.
        lastIngestedJsonlTimestamp: sql`GREATEST(${agentTranscriptsTable.lastIngestedJsonlTimestamp}, EXCLUDED.last_ingested_jsonl_timestamp)`,
        ingestedAt: sql`EXCLUDED.ingested_at`,
        projectId: sql`COALESCE(${agentTranscriptsTable.projectId}, EXCLUDED.project_id)`,
      },
    });
} catch (err) {
  log.error(`Failed to upsert transcript for session ${agentSessionId}`, {
    error: getErrorMessage(err),
  });
  return { ingested: 0, error: err instanceof Error ? err : new Error(String(err)) };
}

// ── 4b. Materialize per-turn rows for FTS (ADR-019, mt#2381) ──────────────
// Extraction rides with capture: read back the full MERGED transcript (the
// upsert just concatenated the new lines onto any prior transcript) and
// upsert text-only turn rows. This makes the session FTS-searchable with no
// embedding API call — `fts_text` is a GENERATED column populated on the
// text write. The embedding vector is filled later by the vector-only
// backfill (PerTurnEmbeddingPipeline); writeTurnsForTranscript never touches
// the `embedding` column, so an already-embedded turn is not clobbered.
// Turn ordering is assigned over the WHOLE transcript, so we extract from the
// full merged row, not from the incremental `newLines` slice.
let turnExtractError: Error | undefined;
let persistedCwd: string | null = null;
try {
  const fullRows = await this.db
    .select({
      transcript: agentTranscriptsTable.transcript,
      cwd: agentTranscriptsTable.cwd,
    })
    .from(agentTranscriptsTable)
    .where(eq(agentTranscriptsTable.agentSessionId, agentSessionId))
    .limit(1);
  const fullTranscript = fullRows[0]?.transcript ?? null;
  persistedCwd = fullRows[0]?.cwd ?? null;
  const { nonEmptyYieldedZero } = await writeTurnsForTranscript(
    this.db,
    agentSessionId,
    fullTranscript
  );
  if (nonEmptyYieldedZero) {
    // mt#2457 SC3: a non-empty transcript that yields zero turns is an
    // extraction failure, not a "nothing new to write" no-op — the throw-only
    // catch below can't see this case (writeTurnsForTranscript already logs a
