    agg.totalSec += tc.timeSec;
    agg.testCount += 1;
    if (tc.timeSec > agg.maxSec) {
      agg.maxSec = tc.timeSec;
      agg.maxTestName = tc.name;
    }
  }
  return [...byFile.values()].sort((a, b) => b.totalSec - a.totalSec);
}

