/**
 * Block a concurrent-migration collision or a journal-`when` mutation of an
 * already-shipped migration, checked against the `origin/main` baseline (mt#2948).
 *
 * This is the collision-PREVENTION complement to mt#2560 (auto-migrate default
 * OFF, the blast-radius fix). Unlike the sibling guards it reads the origin/main
 * journal to detect drift the LOCAL tree cannot reveal. Fails OPEN when there is
 * no baseline (fresh clone / detached / file absent on main).
 *
 * Override: `MINSKY_SKIP_MIGRATION_COLLISION_CHECK=1` (audit-logged).
 */
private async runMigrationCollisionCheck(): Promise<HookResult> {
  if (isMigrationCollisionOverrideTruthy(process.env[MIGRATION_COLLISION_CHECK_OVERRIDE_ENV])) {
    const ts = new Date().toISOString();
    log.cli(
      `[pre-commit:migration-collision] override ${MIGRATION_COLLISION_CHECK_OVERRIDE_ENV}=${process.env[MIGRATION_COLLISION_CHECK_OVERRIDE_ENV]} ` +
        `at ${ts} — migration collision check skipped`
    );
    return {
      success: true,
      message: "Migration collision check skipped via override",
      exitCode: 0,
      overridden: true,
    };
  }

  const journalRelPath = "packages/domain/src/storage/migrations/pg/meta/_journal.json";

  // Working-tree journal (the post-commit state).
  let headEntries: JournalEntry[];
  try {
    const raw = String(await readFile(join(this.projectRoot, journalRelPath), "utf-8"));
    const parsed = JSON.parse(raw) as { entries?: JournalEntry[] };
    headEntries = parsed.entries ?? [];
  } catch {
    return {
      success: true,
      message: "Migration collision check skipped (no local journal)",
      exitCode: 0,
    };
  }

  // origin/main baseline. Without it there is nothing to diff — fail OPEN
  // (this is a NEW-drift detector, not a first-commit correctness gate).
  let baseEntries: JournalEntry[];
  try {
    // journalRelPath is a hardcoded constant (no external input); still, shell-quote
    // the ref via the repo's shell-safety primitive (`safeShellQuote`, exec.ts) so
    // there is no shell-interpolation surface. The git-exec module runs via shell
    // (`execAsync`), not argv — there is no argv git helper — so quoting is the
    // established alignment with prior shell-safety fixes.
    const result = await execGitWithTimeout(
      "show",
      `show ${safeShellQuote(`origin/main:${journalRelPath}`)}`,
      {
        workdir: this.projectRoot,
        timeout: 5000,
      }
    );
    const parsed = JSON.parse(result.stdout.toString()) as { entries?: JournalEntry[] };
    baseEntries = parsed.entries ?? [];
  } catch {
    return {
      success: true,
      message: "Migration collision check skipped (no origin/main journal baseline)",
      exitCode: 0,
    };
  }

  const violations = detectMigrationJournalViolations(baseEntries, headEntries);
  if (violations.length === 0) {
    return { success: true, message: "Migration collision check passed", exitCode: 0 };
  }

  log.cli("");
  log.cli(
    `${violations.length} migration journal drift issue(s) vs origin/main. Commit blocked (mt#2948).`
  );
  log.cli("");
  for (const v of violations) {
    log.cli(`   [${v.kind}] ${v.tag}: ${v.detail}`);
  }
  log.cli("");
  log.cli("Why this is blocked:");
  log.cli("   Drizzle applies journal entries whose `when` exceeds the DB high-water-mark.");
  log.cli("   A renumber that mutates an already-shipped entry's `when`, a reused migration");
  log.cli("   number, or a non-monotonic `when` re-triggers an applied migration on boot");
  log.cli("   (the 2026-07-19 outage). See memory 0c2427e5.");
  log.cli("");
  log.cli("Fix: regenerate your migration against current main —");
  log.cli("   git fetch origin && git rebase origin/main, then `bun run db:generate:pg`");
  log.cli("   so your migration is numbered after main's latest with a fresh timestamp.");
  log.cli("");
  log.cli(`Override (rare, audited): set ${MIGRATION_COLLISION_CHECK_OVERRIDE_ENV}=1`);

  return {
    success: false,
    message: "Migration collision check failed",
    exitCode: 1,
  };

   */
  _overrideAutoMigrate?: boolean;
}): Promise<void> {
  if (this.isInitialized) {
    return;
  }

  const pgConfig = this.pgConfig;
  // Track whether we created the connection (vs injected) for cleanup
  let createdSql: ReturnType<typeof postgres> | null = null;

  try {
    log.debug("Initializing PostgreSQL persistence provider");

    // Resolve the factory — allows tests to inject a mock without mock.module()
    const pgFactory = deps?.postgresFactory ?? postgres;

    // Create PostgreSQL connection (use injected client or create new one).
    // `onnotice` routes NOTICEs through `log.debug` (via the shared handler at
    // postgres-notice-handler.ts). Pre-mt#1828 this site dropped silently with
    // `() => {}` to keep stdout clean (mt#1827); the helper preserves the
    // stdout-clean property AND captures the operational signal at debug
    // level. Six postgres-js sites in total go through this helper.
    const sql =
      deps?.sqlClient ??
      pgFactory(pgConfig.connectionString, {
        max: resolveMaxConnections(pgConfig.maxConnections),
        connect_timeout: pgConfig.connectTimeout || 10,
        idle_timeout: pgConfig.idleTimeout || 60,
        prepare: pgConfig.prepareStatements ?? false,
        onnotice: logPostgresNotice,
      });

    // Track only connections we created, so we can clean up on failure without
    // closing an injected client that the caller still owns
    if (!deps?.sqlClient) {
      createdSql = sql;
    }

    // Create Drizzle instance
    const db = drizzle(sql);

    // Verify connection — retry on pool saturation (mt#1193)
    await withPgPoolRetry(() => sql`SELECT 1`, "postgres-provider.initialize");

    // Cache the connection objects BEFORE running migrations. runMigrations
    // uses `this.db` / `this.sql`, but `this.isInitialized` stays false until
    // migrations succeed — per mt#1763 R1 BLOCKING #1, callers waiting on
    // initialize() must not see isInitialized=true while migrations are
    // still running (race window where they could read pre-migration schema).
    this.sql = sql;
    this.db = db;

    // mt#2560: auto-migrate-on-boot is OFF by default. It runs ONLY when the
    // MINSKY_AUTO_MIGRATE opt-in is set ("true"/"1") AND no deps were injected
    // (see `shouldAutoMigrate`). Prod is migrated by the deploy-keyed single
    // runner (mt#2505); no binary migrates a shared DB on boot. The
    // `_overrideAutoMigrate` test seam can force the branch (see initialize
    // signature for rationale).
    const autoMigrate = deps?._overrideAutoMigrate ?? shouldAutoMigrate(deps);
    if (autoMigrate) {
      // mt#2560 SC2: audit-log when the opt-in actually fires. This should
      // only happen for a local/dev/throwaway DB the caller solely owns —
      // NEVER a shared/prod DB.
      log.warn(
        "Auto-migrating on boot: MINSKY_AUTO_MIGRATE opt-in enabled. " +
          "Only safe for a local/dev/throwaway DB you solely own; " +
          "prod is migrated by the deploy-keyed runner (mt#2505)."
      );
      await this.runMigrations(resolveMigrationsFolder());
    } else if (deps?.sqlClient !== undefined || deps?.postgresFactory !== undefined) {
      log.debug("Skipping auto-migration: caller-injected deps (test seam)");
    } else {
      log.debug(
        "Skipping auto-migration (default OFF, mt#2560): MINSKY_AUTO_MIGRATE not opted in. " +
          "Migrations are applied out-of-band by the deploy-keyed runner (mt#2505)."
      );
    }

    // All checks passed AND migrations applied — now mark initialized.
    this.isInitialized = true;
    log.debug("Base PostgreSQL persistence provider initialized");
  } catch (error) {
    // Clean up connection we created to prevent pool leaks
    if (createdSql) {
      try {
        await createdSql.end();
      } catch {
        /* ignore cleanup errors */
      }
    }
    this.sql = null;
    this.guardedSql = null;
    this.db = null;
    this.isInitialized = false;
    log.error(
      "Failed to initialize PostgreSQL provider:",
      error instanceof Error ? error : { error: String(error) }
    );
    throw error;
  }
}

/**
 * Get provider capabilities
 */
getCapabilities(): PersistenceCapabilities {
  return this.capabilities;
}

/**
 * Get direct database connection
 */
async getDatabaseConnection(): Promise<PostgresJsDatabase> {
  if (!this.isInitialized) {
    throw new Error("PostgresPersistenceProvider not initialized");
  }

  if (!this.db) {
    throw new Error("Database connection not available");
  }

  return this.db;
}

/**
 * Get raw SQL connection for migrations and low-level operations.
 *
 * Returns the pooler-guarded view (mt#2773 / PR #1922 R1): `.unsafe()` is
 * capped at pool-max in-flight and returns plain rows — see GuardedRawSql.
 */
async getRawSqlConnection(): Promise<GuardedRawSql> {
  if (!this.isInitialized) {
    throw new Error("PostgresPersistenceProvider not initialized");
  }

  if (!this.sql) {
    throw new Error("Raw SQL connection not available");
  }

  // mt#2773: hand out a guarded view that bounds in-flight `.unsafe()`
  // queries at the pool's max — zero-bind raw queries submitted beyond pool
  // capacity wedge the Supavisor transaction pooler (connections destroyed
  // during ramp-up) and postgres-js never settles some of the destroyed
  // connection's promises. See raw-sql-pooler-guard.ts for the experiment
  // matrix and rationale. The underlying `this.sql` (used by drizzle and
  // sql.begin() transactions) is deliberately untouched.
  if (!this.guardedSql) {
    this.guardedSql = guardRawSqlAgainstPoolerWedge(this.sql);
  }
  return this.guardedSql;
}

/**
 * Get a session-mode-capable Sql instance for LISTEN/NOTIFY (mt#1852).
 *
 * The transaction-mode pooler (:6543) is incompatible with LISTEN — the pooler
 * may route each command to a different backend connection, breaking per-connection
 * LISTEN registrations. This method returns a connection over the session-mode pooler
 * (:5432 on Supabase/Supavisor), which preserves backend connections for the life of
 * the client session.

/**
 * CopyId — reusable copy-id affordance (mt#2943).
 *
 * Renders an entity id as selectable monospace text plus a small trigger that
 * opens a popover menu with two actions: "Copy ID" (bare id) and "Copy link"
 * (the entity's `minsky://` deeplink, via `entityToMinskyUri`). Generic over
 * `RoutableEntityType` — no per-entity string construction.
 *
 * Established as a shared convention: before this task NO entity detail page
 * had any copy-id affordance (every breadcrumb used the same
 * `font-mono` + `title={id}` + `shortenId()` pattern with no way to copy the
 * full id short of a manual triple-click). This component is the one place
 * that pattern now lives.
 *
 * Copied-state feedback matches the existing clipboard pattern in
 * `ConversationSearchPanel.tsx`'s `CopyResumeButton` (lucide `Copy`→`Check`
 * icon swap + a transient text label for ~2s via local `useState` +
 * `setTimeout`). There is no toast library in this app and none is added
 * here.
 *
 * Long ids (session/ask UUIDs) get their DISPLAY truncated via `shortenId`;
 * both copy actions always operate on the FULL id regardless of display
 * truncation. Short ids (e.g. a task's `mt#2410`) are rendered in full —
 * `truncateAt` only kicks in once `id.length` exceeds it.
 *
 * @see src/cockpit/web/lib/entity-codec.ts — `RoutableEntityType`, `entityToMinskyUri`
 * @see src/cockpit/web/lib/format.ts — `shortenId`
 * @see src/cockpit/web/widgets/ConversationSearchPanel.tsx:124 — copy-feedback style reference
 */
import { useCallback, useState } from "react";
import { Copy, Check, Link as LinkIcon } from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "./ui/popover";
import { shortenId } from "../lib/format";
import { entityToMinskyUri, type RoutableEntityType } from "../lib/entity-codec";
import { cn } from "../lib/utils";

export interface CopyIdProps {
  /** The entity type — drives the `minsky://<type>/<id>` deeplink. */
  type: RoutableEntityType;
  /** The full entity id (never truncated for copy purposes). */
  id: string;
  /**
   * Display-truncation threshold (code points). Ids at or below this length
   * are rendered in full regardless — this only shortens genuinely long ids
   * (session/ask UUIDs), never a short task id like `mt#2410`.
   */
  truncateAt?: number;
  className?: string;
}

type CopiedKind = "id" | "link" | null;

/** Human label for the trigger's aria-label / title, e.g. "ask id". */
function entityLabel(type: RoutableEntityType): string {
  return `${type} id`;
}

export function CopyId({ type, id, truncateAt = 8, className }: CopyIdProps) {
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState<CopiedKind>(null);

  const displayId = id.length > truncateAt ? shortenId(id, truncateAt) : id;

  const doCopy = useCallback((kind: Exclude<CopiedKind, null>, value: string) => {
    void navigator.clipboard.writeText(value).then(() => {
      setCopied(kind);
      setOpen(false);
      setTimeout(() => setCopied(null), 2000);
    });
  }, []);

  const handleCopyId = useCallback(() => doCopy("id", id), [doCopy, id]);
  const handleCopyLink = useCallback(
    () => doCopy("link", entityToMinskyUri(type, id)),
    [doCopy, type, id]
  );

  const label = entityLabel(type);

  return (
    <span className={cn("inline-flex items-center gap-1", className)}>
      <span className="font-mono select-all" title={id}>
        {displayId}
      </span>
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild>
          <button
            type="button"
            aria-label={`Copy ${label}`}
            title={`Copy ${label}`}
            className="inline-flex items-center gap-1 rounded p-0.5 text-muted-foreground hover:text-foreground hover:bg-accent transition-colors flex-shrink-0"
          >
            {copied ? (
              <>
                <Check className="h-3 w-3" />
                <span className="text-[11px]">Copied</span>
              </>
            ) : (
              <Copy className="h-3 w-3" />
            )}
          </button>
        </PopoverTrigger>
        <PopoverContent className="w-36" align="start">
          <button
            type="button"
            onClick={handleCopyId}
            className="w-full flex items-center gap-2 rounded-sm px-2 py-1.5 text-xs text-left text-foreground hover:bg-accent hover:text-accent-foreground transition-colors"
          >
            <Copy className="h-3 w-3" />
            Copy ID
          </button>
          <button
            type="button"
            onClick={handleCopyLink}
            className="w-full flex items-center gap-2 rounded-sm px-2 py-1.5 text-xs text-left text-foreground hover:bg-accent hover:text-accent-foreground transition-colors"
          >
            <LinkIcon className="h-3 w-3" />
            Copy link
          </button>
        </PopoverContent>
      </Popover>
    </span>
  );
}

/**
 * AskPage — detail view route for /ask/:id (mt#2410, mt#2398 PR2).
 *
 * URL-addressable ask detail in the entity-tab pattern (sibling of
 * /tasks/:id, /session/:id, /agents/:id). Retires AsksPage's local-state
 * full-page swap: the ask is addressed by URL and opens as a tab.
 *
 * Settle convention (PR #1668 R1): asks are CONSUMABLE — resolving,
 * deferring, or escalating removes the ask from the pending set, so the
 * entity this tab addresses ceases to exist. On settle the page therefore
 * closes its own tab and returns to /asks (via closeTab's navigateTo), in
 * the same single navigation. This intentionally diverges from durable
 * entities (task / memory / session), whose tabs persist across actions.
 * The Back affordance is plain navigation — the ask was not consumed, so
 * its tab stays in the working set like any other entity tab.
 *
 * Data (mt#2669): a dedicated per-id query (GET /api/asks/:id), seeded from
 * the shared pending-list cache per TanStack's initialData-from-list pattern
 * (initialDataUpdatedAt carries the seed's real age, so a stale seed still
 * refetches). The per-id endpoint returns terminal asks too, so this page
 * distinguishes three end states instead of one generic message: a terminal
 * ask says what happened (with the recorded response), an unknown id says
 * "not found" — and neither verdict renders before a fresh fetch settles.
 * Previously the page resolved the id by find-in-list over the pending
 * snapshot, which declared live asks "no longer pending" whenever the
 * snapshot was empty or stale (deeplink into a fresh cockpit boot).
 */
import { useParams, useNavigate, Link, useLocation } from "react-router-dom";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  AskDetail,
  fetchAskById,
  resolveAsk,
  deferAsk,
  escalateAsk,
  AskNotFoundError,
  type AskItem,
  type AskState,
  type AsksListResponse,
  composeResolvePayload,
} from "../widgets/AskDetail";
import { isTerminal } from "@minsky/domain/ask/state-machine";
import { LoadingState } from "../components/LoadingState";
import { ErrorState } from "../components/ErrorState";
import { CopyId } from "../components/CopyId";
import { useState } from "react";
import { useTabs } from "../lib/tabs";

/** Human phrasing for a terminal state. Terminal-vs-open classification itself
 * comes from the domain state machine's `isTerminal` (the single source of
 * truth — note "responded" is NOT terminal: the response is recorded but the
 * ask has not closed, so it still renders the actionable detail view).
 */
function terminalLabel(state: AskState): string {
  if (state === "expired") return "expired";
  if (state === "cancelled") return "cancelled";
  return "resolved";
}

export function AskPage() {
  const { id } = useParams<{ id: string }>();
  const askId = id ?? "";
  const navigate = useNavigate();
  const { pathname } = useLocation();
  const { closeTab } = useTabs();
  const queryClient = useQueryClient();
  const [resolving, setResolving] = useState(false);

  const query = useQuery<AskItem, Error>({
    queryKey: ["asks", askId],
    queryFn: () => fetchAskById(askId),
    enabled: askId !== "",
    initialData: () =>
      queryClient.getQueryData<AsksListResponse>(["asks"])?.asks.find((a) => a.id === askId),
    initialDataUpdatedAt: () => queryClient.getQueryState(["asks"])?.dataUpdatedAt,
  });

  const ask = query.data ?? null;
  const notFound = query.isError && query.error instanceof AskNotFoundError;
  const terminal = ask !== null && isTerminal(ask.state);

  /** Consumable-entity settle: close this ask's tab, landing on /asks. */
  function settle() {
    setResolving(false);
    void queryClient.invalidateQueries({ queryKey: ["asks"] });
    void queryClient.invalidateQueries({ queryKey: ["attention"] });
    closeTab(pathname, { navigateTo: "/asks" });
  }

  const resolveMutation = useMutation({
    mutationFn: async ({ target, optionLetter }: { target: AskItem; optionLetter: string }) => {
      // Shared payload composition (mt#2882 R3) — one contract definition in
      // AskDetail serves both the inline inbox actions and this detail page.
      await resolveAsk(target.id, composeResolvePayload(target, optionLetter, "inbox"));
    },
    onMutate: () => setResolving(true),
    onSettled: settle,
  });

  const deferMutation = useMutation({
    mutationFn: (targetId: string) => deferAsk(targetId),
    onMutate: () => setResolving(true),
    onSettled: settle,
  });

  const escalateMutation = useMutation({
    mutationFn: (targetId: string) => escalateAsk(targetId),
    onMutate: () => setResolving(true),
    onSettled: settle,
  });

  return (
    <div className="p-4 max-w-3xl mx-auto w-full">
      {/* Breadcrumb */}
      <nav
        className="flex items-center gap-1.5 text-xs text-muted-foreground mb-3"
        aria-label="Breadcrumb"
      >
        <Link to="/asks" className="hover:text-foreground transition-colors">
          Asks
        </Link>
        <span aria-hidden="true">/</span>
        <CopyId type="ask" id={askId} />
      </nav>

      {query.isPending ? (
        <LoadingState message="Loading ask…" />
      ) : notFound ? (
        <div className="flex flex-col gap-1 py-8 text-center">
          <p className="text-sm text-muted-foreground">No ask with this id was found.</p>
          <p className="text-xs text-muted-foreground/70">
            The link may be malformed, or the ask belongs to a different workspace.
          </p>
        </div>
      ) : query.isError ? (
        <ErrorState prefix="Failed to load ask" error={query.error} />
      ) : ask && terminal ? (
        <div className="flex flex-col gap-2 py-8 text-center">
          <p className="text-sm text-muted-foreground">
            This ask was {terminalLabel(ask.state)}.
          </p>
          <p className="text-xs text-muted-foreground/70">{ask.title}</p>
          {ask.response ? (
            <div className="mx-auto mt-2 max-w-lg text-left">
              <p className="text-xs text-muted-foreground mb-1">
                Response{ask.response.responder ? ` — by ${ask.response.responder}` : ""}

