/// Show + focus the cockpit window without reloading, creating it if needed.
///
/// Used by the deep-link handler so the navigation eval can land on the CURRENT
/// SPA state rather than after a reload. Contrast with `open_cockpit_window`,
/// which always reloads to recover after a daemon restart — that reload would
/// race with the deep-link eval if used here.
pub(crate) fn ensure_cockpit_window_visible(app: &AppHandle) {
    if let Some(window) = app.get_webview_window(COCKPIT_WINDOW_LABEL) {
        set_dock_presence(app, true);
        if let Err(e) = window.show() {
            eprintln!("[cockpit-tray] deep-link: failed to show cockpit window: {e}");
        }
        if let Err(e) = window.set_focus() {
            eprintln!("[cockpit-tray] deep-link: failed to focus cockpit window: {e}");
        }
        return;
    }
    // Window doesn't exist yet -- create it. Creation ONLY: the caller (the
    // deep-link/recovery loop, mt#2688) owns liveness healing; spawning
    // another recovery watch here would double-navigate the same window.
    create_cockpit_window(app);
}

/// Open the embedded cockpit window, or focus it if it already exists (mt#2219).
fn open_cockpit_window(app: &AppHandle) {
    if let Some(window) = app.get_webview_window(COCKPIT_WINDOW_LABEL) {
        set_dock_presence(app, true);
        if let Err(e) = window.show() {
            eprintln!("[cockpit-tray] failed to show cockpit window: {e}");
        }
        if let Err(e) = window.set_focus() {
            eprintln!("[cockpit-tray] failed to focus cockpit window: {e}");
        }
        // Heal or refresh (mt#2688): a LIVE document is reloaded (the daemon
        // Start/Restart recovery this branch has always done); a dead
        // (never-loaded) document is re-navigated by the recovery loop --
        // reload() on a failed document just reloads the blank page. The
        // probe runs off-main (DOM probe blocks on the eval callback).
        crate::deeplink::refresh_or_heal_window(app);
        return;
    }

    create_cockpit_window(app);
    // Cold-start heal (mt#2688): if the daemon is still booting, the fresh
    // window's initial load fails (connection refused). The recovery watch
    // re-navigates it as soon as the daemon accepts connections.
    crate::deeplink::spawn_window_recovery(app, None);
}

/// Create the cockpit webview window (creation only -- no show-if-exists, no
/// recovery). Callers own recovery semantics: `open_cockpit_window` pairs
/// this with a recovery watch; the deep-link loop calls it via
/// `ensure_cockpit_window_visible` and runs its own loop (mt#2688).
fn create_cockpit_window(app: &AppHandle) {
    let url: tauri::Url = match COCKPIT_URL.parse() {
        Ok(url) => url,
        Err(e) => {
            eprintln!("[cockpit-tray] invalid cockpit URL {COCKPIT_URL:?}: {e}");
            return;
        }
    };

    // Regular BEFORE build (mt#2675): the window must appear with Dock
    // presence already in place or macOS may refuse to front it.
    set_dock_presence(app, true);

    match WebviewWindowBuilder::new(app, COCKPIT_WINDOW_LABEL, WebviewUrl::External(url))
        .title("Minsky Cockpit")
        .inner_size(1200.0, 800.0)
        // Open external (non-cockpit) links in the OS browser instead of
        // silently dropping them (mt#2942). The SPA is an untrusted external-URL
        // webview with NO IPC bridge (ADR-023), so the frontend cannot call an
        // opener plugin -- this lives entirely in the tray. Paired with
        // EXTERNAL_LINK_SHIM, which funnels new-window (target="_blank") clicks
        // here. Canonical Tauri pattern (on_navigation -> cancel -> opener); see
        // https://v2.tauri.app/plugin/opener/ and tauri-apps/tauri#4756.
        .on_navigation(|url| {
            match url.scheme() {
                "http" | "https" => {
                    // The cockpit SPA's own origin loads in place (initial load,
                    // Cmd+R reload, deep-link recovery navigate); react-router
                    // nav is client-side and never reaches here.
                    if matches!(url.host_str(), Some("localhost") | Some("127.0.0.1")) {
                        return true;
                    }
                    // Any other web origin is external: open in the OS default
                    // browser and CANCEL the in-webview nav so the SPA is never
                    // navigated away. `open::that` is synchronous (it spawns the
                    // platform opener and returns); on failure we log and still
                    // cancel -- navigating the webview to the external site
                    // would lose the cockpit, which is worse than a no-op.
                    if let Err(e) = open::that(url.as_str()) {
                        eprintln!("[cockpit-tray] failed to open external URL {url} in browser: {e}");
                    }
                    false
                }
                // Webview-internal schemes used during normal operation -- allow.
                "about" | "blob" => true,
                // javascript:/data:/file:/mailto:/tel:/custom schemes: neither
                // the cockpit origin nor a web link to hand to the OS browser.
                // REFUSE the in-webview navigation and do NOT shell it out
                // (review R1: never let javascript:/file:/data: navigate the
                // webview).
                _ => false,
            }
        })
        .initialization_script(EXTERNAL_LINK_SHIM)
        .build()
    {
        Ok(window) => {
            // Hide-on-close (mt#2675): intercept CloseRequested so the red
            // button / Cmd+W hides the window (preserving SPA state) instead
            // of destroying it, and drop Dock + Cmd-Tab presence while
            // hidden. Destroyed is the defensive fallback for any destroy
            // path that bypasses CloseRequested (e.g. app teardown).
            let handle = app.clone();
            let window_for_events = window.clone();
            window.on_window_event(move |event| match event {
                tauri::WindowEvent::CloseRequested { api, .. } => {
                    api.prevent_close();
                    if let Err(e) = window_for_events.hide() {
                        eprintln!("[cockpit-tray] failed to hide cockpit window on close: {e}");
                    }
                    set_dock_presence(&handle, false);
                }
                tauri::WindowEvent::Destroyed => set_dock_presence(&handle, false),
                _ => {}
            });

            // Re-apply the tracked zoom (mt#2334 review): with hide-on-close
            // the window usually survives, but this create path still runs on
            // first open and after any genuine destroy — restore the stored
            // factor or the next zoom step would jump from 1.0 to the tracked
            // value.
            if let Some(zoom_state) = app.try_state::<ZoomLevel>() {
                let factor = *zoom_state.0.lock().unwrap();
                if (factor - 1.0).abs() > f64::EPSILON {
                    if let Err(e) = window.set_zoom(factor) {
                        eprintln!("[cockpit-tray] failed to apply saved cockpit zoom: {e}");
                    }
                }
            }
        }
        Err(e) => eprintln!("[cockpit-tray] failed to create cockpit window: {e}"),
    }
}

// early return, commit failure, CAS abort, push failure, success). Wrapping
// the entire post-workdir body in try/finally with cleanup in finally
// gives that guarantee — the previous inline cleanup only after a
// successful CAS check left stale markers on early returns.
try {
  // Detect clean working tree up front — skip Ask emission and return early when
  // there is nothing to commit. ADR §Detection: "every agent-initiated commit" means
  // actual commits, not attempts on a clean tree.
  //
  // Carve-out: when params.amend is true, the commit may legitimately update only
  // the commit message without new file changes. In that case the working tree is
  // clean by design, so we must NOT short-circuit — the amend must be allowed to
  // proceed even when hasUncommittedChanges returns false.
  const sessionIdToUse = params.session;
  let isCleanTree = false;
  try {
    const gitService = createGitService();
    const hasChanges = await gitService.hasUncommittedChanges(workdir);
    isCleanTree = !hasChanges;
  } catch (probeErr) {
    // If we cannot determine tree state (e.g. not a git repo yet), let the
    // downstream commit attempt proceed and handle NothingToCommitError there.
    // Surface the probe failure (don't silently swallow): if the tree turns out
    // to actually be clean, the Ask emitted below is a benign false positive
    // for that rare path, but operators need visibility into why detection failed.
    log.warn(
      `[session.commit] hasUncommittedChanges probe failed; proceeding with commit attempt: ${
        probeErr instanceof Error ? probeErr.message : String(probeErr)
      }`
    );
  }

  if (!params.amend && isCleanTree) {
    // When noFiles is true, the caller wants an empty commit to wake a webhook
    // or produce an audit-trail commit. Use --allow-empty and proceed to push.
    // When noFiles is false (default), return the existing no-op result.
    if (!params.noFiles) {
      log.debug("Nothing to commit in session (clean working tree)", { session: params.session });
      return {
        success: true,
        nothingToCommit: true,
        commitHash: null,
        message: "Nothing to commit, working tree clean",
        pushed: false,
      };
    }
    log.debug("Creating empty commit (noFiles=true, clean tree) for webhook wake", {
      session: params.session,
    });
  }

  // Detection-time policy consult (mt#2935; ADR-008 §Router moved to the
  // emit site). A routine commit under a standing auto-commit policy is a
  // statically-resolved decision point — record it as an audit EVENT, not
  // an authorization.approve Ask. The Ask is created ONLY when policy is
  // silent (the genuine escalation) or when the covered-path event row
  // could not actually be persisted (fail toward the ask — the action must
  // never go silently unrecorded). Everything here is best-effort and never
  // blocks the commit. mt#2593: on the uncovered path, capture the created
  // Ask's id so it can be closed once the commit lands (below).
  let commitAuthAskId: string | undefined;
  if (askRepository) {
    const requestor =
      sessionRecordForFreeze?.agentId ?? `minsky.session-commit:session:${sessionIdToUse}`;

    let policyCoveredAndRecorded = false;
    try {
      // The session workdir is a clone of the repo, so its CLAUDE.md and
      // project rules ARE the policy corpus for this action.
      const sources = await loadAllPolicySources(workdir);
      const coverage = isActionCovered(["commit", "push"], sources);
      if (coverage.covered && coverage.citation) {
        const recorded = await emitSystemEventFromProvider(persistenceProvider, {
          eventType: "authorization.policy_covered",
          payload: {
            action: "commit",
            citationSource: coverage.citation.source,
            ...(coverage.citation.lineRange
              ? { citationLines: coverage.citation.lineRange }
              : {}),
            commitMessage: params.message,
          },
          actor: requestor,
          relatedTaskId: sessionRecordForFreeze?.taskId,
          relatedSessionId: sessionRecordForFreeze?.sessionId,
        });
        if (recorded) {
          policyCoveredAndRecorded = true;
        } else {
          log.debug(
            "sessionCommit: policy covers commit but audit event was not persisted; falling back to Ask emission",
            { session: params.session, citationSource: coverage.citation.source }
          );
        }
      }
    } catch (policyErr: unknown) {
      log.warn(
        "sessionCommit: detection-time policy consult failed; falling back to Ask emission (best-effort)",
        {
          session: params.session,
          error: policyErr instanceof Error ? policyErr.message : String(policyErr),
        }
      );
    }

    if (!policyCoveredAndRecorded) {
      try {
        const commitAuthAsk = await askRepository.create({
          kind: "authorization.approve",
          classifierVersion: "v1",
          requestor,
          parentTaskId: sessionRecordForFreeze?.taskId,
          parentSessionId: sessionRecordForFreeze?.sessionId,
          title: `Commit authorization: ${params.message.slice(0, 80)}`,
          question: `Authorize commit in session ${params.session}: "${params.message}"`,
          metadata: {
            commitMessage: params.message,
            stagedFiles: params.all ? "all" : "manual-staged",
          },
        });
        commitAuthAskId = commitAuthAsk.id;
      } catch (askErr: unknown) {
        log.warn("sessionCommit: failed to emit authorization.approve Ask (best-effort)", {
          session: params.session,
          error: askErr instanceof Error ? askErr.message : String(askErr),
        });
      }
    }
  }

  try {
    // Commit changes using session-scoped git command
    let commitResult!: { commitHash: string; message: string };
    try {
      // When noFiles is true and tree is clean, use --allow-empty so that a real
      // commit is created even without staged changes. This is the webhook-wake
      // mechanism: the push triggers pull_request.synchronize.
      const allowEmpty = params.noFiles === true && isCleanTree && !params.amend;
      // mt#2635: route the empty-commit case through the SAME
      // commitChangesFromParams -> commitImpl path used for real commits,
      // instead of a bespoke `gitService.execInRepository(...)` call. The
      // prior bespoke call went through `execInRepositoryImpl`, which
      // catches any subprocess failure and re-throws a brand-new
      // `MinskyError` carrying only a one-line "cleaned" summary — NOT the
      // original error's `.stdout`/`.stderr`. That meant a hook failure on
      // the allow-empty path could never be classified by
      // `classifyHookFailure` (workflow-commands.ts), which requires
      // `.stdout`/`.stderr` on the caught error, so the operator only ever
      // saw an opaque one-liner with no diagnostic detail. `commitImpl`
      // re-throws the ORIGINAL execAsync error unmodified on failure, so
      // routing through it here restores full hook-output propagation for
      // the allow-empty path — same as the real-commit path already had.
      commitResult = await commitChangesFromParams({
        message: params.message,
        repo: workdir,
        all: params.all,
        amend: params.amend,
        // A clean tree has nothing to stage; skip the staging step outright
        // rather than let it run as a (harmless but pointless) no-op.
        noStage: allowEmpty ? true : params.noStage,
        allowEmpty,

// both `continue` / fall through BEFORE scrubValueDeep is ever called
// (see the loop above), so allRedactions only ever contains hits from
// lines that passed the HWM gate and matched a retained type. Best-effort
// logging; see credential-scrub-log.ts's own error-swallowing posture.
if (allRedactions.length > 0) {
  recordCredentialScrub(agentSessionId, allRedactions, realCredentialScrubLogDeps);
}

if (newLines.length === 0 && newAttachmentRows.length === 0) {
  log.debug(
    `No new lines for session ${agentSessionId} (high-water-mark: ${highWaterMark?.toISOString() ?? "none"})`
  );
  // Idempotent re-run. (mt#2789: a HWM-read failure aborts above, before
  // this point is reached, so there is no swallowed HWM error to surface
  // here anymore.)
  return { ingested: 0, error: undefined };
}

// ── 3. Derive metadata from the source's DiscoveredSession ───────────────
const startedAt = extractStartedAt(newLines, this.source);
const endedAt = latestTs ?? mtime;

// ── 4. Upsert into agent_transcripts ─────────────────────────────────────
// Single atomic statement: INSERT … ON CONFLICT (agent_session_id) DO UPDATE.
//
// mt#2789: the append is now idempotent BY LINE `uuid`, not just
// timestamp-gated. Diagnosis found the observed subagent-transcript
// duplication was a concurrent-ingest race: two actors (the cockpit
// watcher, the MCP boot sweep, the SessionEnd hook — any two of the N
// processes that can call ingestSession) both read the same
// high-water-mark, both collect the same "new" batch, and both append.
// The in-process HWM gate at step 2 is a cheap first-pass filter but
// can't see a concurrent actor's read; only the DB has the information
// needed to detect the race, and only at the moment of the write.
//
// The fix: filter `EXCLUDED.transcript` down to elements whose `uuid` is
// NOT already present in the stored `transcript` array, via a correlated
// subquery over `jsonb_array_elements`, before concatenating. This is
// race-free WITHOUT an advisory lock because the UPDATE's row lock
// already serializes concurrent writers to the same `agent_session_id`:
// under Postgres READ COMMITTED, a blocked `ON CONFLICT DO UPDATE`
// re-evaluates its SET expressions against the just-committed row once
// unblocked — so the second writer's uuid check sees the first writer's
// already-appended lines and correctly filters them out.
//
// Lines without a `uuid` are always appended (never treated as
// duplicates) — Claude Code's retained user/assistant lines always carry
// one, so this is a defensive default for a case that should not occur
// in practice, not a silent-drop.
//
// `lastIngestedJsonlTimestamp` uses GREATEST(existing, EXCLUDED) rather
// than a flat overwrite so a racing writer that read an OLDER
// high-water-mark (and is therefore behind) cannot regress the
// watermark below a value a faster concurrent writer already advanced
// it to — regressing it would cause the NEXT ingest to re-collect
// already-ingested lines (harmless now that the append is uuid-deduped,
// but wasteful).
//
// Project scoping (mt#2417, Phase 1.4): resolve from the recovered cwd.
// Unlike `cwd` (strictly insert-only), `project_id` IS refreshed on
// conflict via COALESCE-forward below — a session first ingested before
// its cwd was recoverable can still get scoped once a later ingest
// resolves it, without ever downgrading an already-resolved project back
// to null (mirrors the `writeCwdMatchLink` precedence note above).
const resolvedProjectId = await resolveIngestProjectId(session.cwd, this.db);

// Fields restricted to insert-only (harness, cwd, project_dir, started_at)
// are not overwritten on conflict.
try {
  await this.db
    .insert(agentTranscriptsTable)
    .values({
      agentSessionId,
      harness,
      transcript: newLines,
      startedAt: startedAt ?? undefined,
      endedAt: endedAt ?? undefined,
      // mt#1445: use the session's recovered working directory if the
      // source could provide one; otherwise leave the column NULL rather
      // than substituting the JSONL path. Downstream consumers querying
      // `cwd` expect a working directory, not a transcript path.
      cwd: session.cwd ?? undefined,
      projectDir: deriveProjectDir(jsonlPath),
      projectId: resolvedProjectId ?? undefined,
      lastIngestedJsonlTimestamp: latestTs ?? undefined,
      ingestedAt: new Date(),
    })
    .onConflictDoUpdate({
      target: agentTranscriptsTable.agentSessionId,
      set: {
        transcript: sql`COALESCE(${agentTranscriptsTable.transcript}, '[]'::jsonb) || (
          SELECT COALESCE(jsonb_agg(new_elem ORDER BY ord), '[]'::jsonb)
          FROM jsonb_array_elements(EXCLUDED.transcript) WITH ORDINALITY AS t(new_elem, ord)
          WHERE (new_elem->>'uuid') IS NULL
            OR NOT EXISTS (
              SELECT 1
              FROM jsonb_array_elements(COALESCE(${agentTranscriptsTable.transcript}, '[]'::jsonb)) AS existing_elem
              WHERE existing_elem->>'uuid' = new_elem->>'uuid'
            )
        )`,
        endedAt: sql`EXCLUDED.ended_at`,
        // NULL-safety: Postgres GREATEST *ignores* NULL arguments (result
        // is NULL only when ALL args are NULL) — unlike MySQL, where any
        // NULL poisons the result. GREATEST(NULL, ts) = ts here, so a
        // NULL existing watermark advances and a NULL incoming one cannot
        // regress a stored value. Verified empirically on PG17.
        lastIngestedJsonlTimestamp: sql`GREATEST(${agentTranscriptsTable.lastIngestedJsonlTimestamp}, EXCLUDED.last_ingested_jsonl_timestamp)`,
        ingestedAt: sql`EXCLUDED.ingested_at`,
        projectId: sql`COALESCE(${agentTranscriptsTable.projectId}, EXCLUDED.project_id)`,
      },
    });
} catch (err) {
  log.error(`Failed to upsert transcript for session ${agentSessionId}`, {
    error: getErrorMessage(err),
  });
  return { ingested: 0, error: err instanceof Error ? err : new Error(String(err)) };
}

// ── 4b. Materialize per-turn rows for FTS (ADR-019, mt#2381) ──────────────
// Extraction rides with capture: read back the full MERGED transcript (the
// upsert just concatenated the new lines onto any prior transcript) and
// upsert text-only turn rows. This makes the session FTS-searchable with no
// embedding API call — `fts_text` is a GENERATED column populated on the
// text write. The embedding vector is filled later by the vector-only
// backfill (PerTurnEmbeddingPipeline); writeTurnsForTranscript never touches
// the `embedding` column, so an already-embedded turn is not clobbered.
// Turn ordering is assigned over the WHOLE transcript, so we extract from the
// full merged row, not from the incremental `newLines` slice.
let turnExtractError: Error | undefined;
let persistedCwd: string | null = null;
try {
  const fullRows = await this.db
    .select({
      transcript: agentTranscriptsTable.transcript,
      cwd: agentTranscriptsTable.cwd,
    })
    .from(agentTranscriptsTable)
    .where(eq(agentTranscriptsTable.agentSessionId, agentSessionId))
    .limit(1);
  const fullTranscript = fullRows[0]?.transcript ?? null;
  persistedCwd = fullRows[0]?.cwd ?? null;
  await writeTurnsForTranscript(this.db, agentSessionId, fullTranscript);
} catch (err) {
  turnExtractError = err instanceof Error ? err : new Error(String(err));
  log.warn(`Failed to materialize turn rows for session ${agentSessionId}`, {
    error: getErrorMessage(err),
  });
  // Don't fail the whole ingest — the transcript upsert already succeeded.
  // Surface the error so the sweep can count degraded ingests.
}

// ── 4c. Write cwd_match link into minsky_session_links (mt#2441) ────────
// Runs from THIS shared ingest core so every ingest path — transcripts_ingest,
// the MCP boot sweep, the SessionEnd hook, and the cadence sweep — writes
// the same link with no per-consumer duplication (all four funnel through
// ingestSession). No-ops (no DB call) when the resolved cwd doesn't
// resolve to a session workspace path — the expected common case per the
// mt#2749 finding (subagents don't chdir), not an error. Never allowed to
// fail the ingest: writeCwdMatchLink swallows its own DB errors, and this
// try/catch is a defensive backstop only.
//

{
