// ---------------------------------------------------------------------------
// SubagentDispatchTracker
// ---------------------------------------------------------------------------

/**
 * Read-write layer for the `subagent_invocations` table.
 *
 * Instantiate once per composition context (MCP server, test). Inject a
 * `PostgresJsDatabase` instance at construction time.
 *
 * All public methods are async and fail-safe: a DB error causes a log warning
 * and a safe return (empty aggregates, "none" escalation), never a throw. This
 * matches the fail-safe contract of `DisconnectTracker`'s file I/O layer.
 */
export class SubagentDispatchTracker {
  /**
   * Process-lifetime singleton. Null until `setInstance(db)` is called.
   * `getInstance()` returns a no-op tracker when no instance has been set —
   * this mirrors `DisconnectTracker.getInstance` which creates one on first
   * call. The no-op path uses an empty fake DB so callers always get a typed
   * value without throwing.
   *
   * Set once from the MCP start-command after the DB connection is resolved
   * (same pattern as memory-enrichment and wake-enrichment middleware).
   */
  private static _instance: SubagentDispatchTracker | null = null;

  /**
   * Return the process-lifetime singleton.
   *
   * If no instance has been set via `setInstance`, returns a no-op tracker
   * whose DB always returns empty result sets. This matches the
   * `DisconnectTracker.getInstance` contract — callers never receive null.
   */
  static getInstance(): SubagentDispatchTracker {
    if (!SubagentDispatchTracker._instance) {
      // No-op tracker: create with a dummy DB that returns empty arrays.
      // This path fires on the CLI path (no Postgres) or if setInstance
      // hasn't been called yet. The fail-safe methods in getCadence/
      // getEscalation catch any DB errors and return safe defaults.
      SubagentDispatchTracker._instance = new SubagentDispatchTracker(createNullDatabase());
    }
    return SubagentDispatchTracker._instance;
  }

  /**
   * Set the process-lifetime singleton to a tracker backed by `db`.
   * Called from the MCP start-command once the DB connection is resolved.
   * Idempotent — subsequent calls replace the instance (useful for tests).
   */
  static setInstance(db: PostgresJsDatabase, eventEmitter?: EventEmitter): SubagentDispatchTracker {
    SubagentDispatchTracker._instance = new SubagentDispatchTracker(db, eventEmitter);
    return SubagentDispatchTracker._instance;
  }

  /**
   * Reset the singleton for tests — creates a fresh instance backed by the
   * provided `db`. Pass the fake DB from test fixtures.
   */
  static resetForTest(db: PostgresJsDatabase): SubagentDispatchTracker {
    SubagentDispatchTracker._instance = new SubagentDispatchTracker(db);
    return SubagentDispatchTracker._instance;
  }

  constructor(
    private readonly db: PostgresJsDatabase,
    private readonly eventEmitter?: EventEmitter
  ) {}

  /**
   * Insert a new invocation row, or update an existing one identified by
   * `subagentSessionId`.
   *
   * Upsert semantics:
   *   - When `input.subagentSessionId` is set: look for an existing row with
   *     that value. If found, UPDATE all mutable fields. If not found, INSERT.
   *   - When `input.subagentSessionId` is null/undefined: always INSERT a new row.
   *     The table has no unique constraint on `subagent_session_id` (it is a
   *     non-unique index), so null-keyed rows cannot be de-duplicated at the DB
   *     constraint layer — callers must manage their own deduplication.
   *
   * All fields present in `input` are written. Fields absent from `input`
   * (optional schema columns) are left as their DB defaults (NULL).
   *
   * Errors are swallowed and logged — this matches the fail-safe contract of
   * `DisconnectTracker`'s I/O layer.
   *
   * @param input  The invocation record to persist.
   */
  async recordSubagentInvocation(input: SubagentInvocationInput): Promise<void> {
    // mt#2653 R1: events must carry the PERSISTED agentType, not necessarily
    // `input.agentType` — when the UPDATE path omits the sentinel (see below),
    // the row keeps its EXISTING (dispatch-time) value, which can differ from
    // what this call's `input` carried. Defaults to `input.agentType` for the
    // INSERT paths, where "persisted" and "input" are the same value by
    // construction; reassigned below on the UPDATE path.
    let resolvedAgentType: string = input.agentType;
    try {
      if (input.subagentSessionId != null) {
        // Upsert path: check for an existing row by subagentSessionId.
        //
        // mt#2831: a subagentSessionId is no longer guaranteed unique across rows —
        // the dispatch-recovery command deliberately INSERTs a NEW row for a resumed
        // attempt sharing the SAME subagentSessionId (the resume reuses the existing
        // Minsky session workspace; see recordDispatchRecoveryAttempt below). Order by
        // startedAt DESC so this upsert always targets the MOST RECENT attempt in the
        // retry chain — the one whose lifecycle is actually still open — rather than an
        // arbitrary row picked by unspecified DB order.
        const existing = await this.db
          .select({
            id: subagentInvocationsTable.id,
            agentType: subagentInvocationsTable.agentType,
          })
          .from(subagentInvocationsTable)
          .where(eq(subagentInvocationsTable.subagentSessionId, input.subagentSessionId))
          .orderBy(desc(subagentInvocationsTable.startedAt))
          .limit(1);

        const [firstExisting] = existing;
        if (firstExisting) {
          // UPDATE the existing row by primary key (NOT by subagentSessionId).
          // The schema intentionally has no UNIQUE constraint on subagent_session_id;
          // if two rows ever share it (concurrent writes, replayed events), updating
          // by subagentSessionId would mutate both. Target the specific row id we
          // just selected.
          //
          // Also preserve `startedAt`: an upsert that lands later in the dispatch
          // lifecycle (SubagentStop classifying the outcome) must not overwrite
          // the dispatch-time timestamp, which `lastDispatch` and `byHourLast24h`
          // depend on for chronology.
          const { id: _id, startedAt: _startedAt, agentType, ...restFields } = input;

          // mt#2653: also preserve `agentType` when the caller only has the
          // `UNKNOWN_AGENT_TYPE` sentinel. The SubagentStop hook writes this
          // sentinel unconditionally (it has no way to recover the real
          // dispatch-time agentType from the workspace alone), but the
          // dispatch-time INSERT already wrote the real value
          // (`promptResult.agentType`) — an unconditional `.set({ agentType })`
          // on UPDATE would clobber it with "unknown" on every SubagentStop.
          // Omitting the field here leaves the existing column value
          // untouched; a caller that genuinely has a real (non-sentinel)
          // agentType still updates it normally.
          const updateFields: Partial<SubagentInvocationInput> =
            agentType === UNKNOWN_AGENT_TYPE ? restFields : { ...restFields, agentType };

          // The value that will actually be PERSISTED after this UPDATE: the
          // existing row's agentType when the sentinel is omitted, otherwise
          // the new value being written. Events below must use this, not the
          // raw `input.agentType`, or they'd report "unknown" even though the
          // DB row (and thus every future read of it) preserves the real
          // dispatch-time value — the exact DB-vs-telemetry divergence this
          // fixes (mt#2653 R1).
          resolvedAgentType =
            agentType === UNKNOWN_AGENT_TYPE ? firstExisting.agentType : agentType;

          await this.db
            .update(subagentInvocationsTable)
            .set(updateFields)

/**
 * Current-invocation marker (mt#2831 R1 BLOCKING #1) — the "thread the invocation
 * id" mechanism that lets the SubagentStop hook bind a Stop-time update to the
 * EXACT `subagent_invocations` row it belongs to, instead of guessing by
 * `subagentSessionId` (ambiguous once a dispatch has been auto-resumed and a
 * session hosts more than one attempt's row).
 *
 * Convention: a plain-text file at
 * `<sessionDir>/.minsky/sessions/<sessionId>/current-invocation-id`, sibling to
 * the `handoff.md` convention the dispatch-recovery probe already reads
 * (`packages/domain/src/session/dispatch-recovery-probe.ts`). Written at
 * dispatch time (the ORIGINAL attempt) and overwritten at recovery time (each
 * RESUMED attempt) — the file always names whichever invocation is currently
 * "the one running in this workspace." The SubagentStop hook reads it once at
 * Stop time and passes the id through as `SubagentInvocationInput.id`, which
 * `SubagentDispatchTracker.recordSubagentInvocation`'s strong-binding path
 * consumes directly (see that method's docstring).
 *
 * Fail-safe by design: a missing or unreadable marker is not an error — it just
 * means the caller falls back to the tracker's heuristic (subagentSessionId +
 * open-row-first) upsert path, same as before this mechanism existed.
 *
 * @see mt#2831 — this task
 * @see src/mcp/subagent-dispatch-tracker.ts — the strong-binding consumer
 * @see .minsky/hooks/record-subagent-invocation.ts — the SubagentStop reader
 * @see src/adapters/shared/commands/tasks/dispatch-command.ts — dispatch-time writer
 * @see src/adapters/shared/commands/tasks/dispatch-recover-command.ts — recovery-time writer
 */

/**
 * Resolve the marker file's path for a given session workspace + session id.
 * Exported for testing and for callers that need the path without performing I/O.
 */
export function getCurrentInvocationMarkerPath(sessionDir: string, sessionId: string): string {
  return `${sessionDir}/.minsky/sessions/${sessionId}/current-invocation-id`;
}

/**
 * Write (or overwrite) the current-invocation marker. Fail-safe: swallows any
 * write error and returns `false` rather than throwing — writing this marker is
 * a best-effort deterministic-attribution aid, not a correctness-critical write
 * (the tracker's heuristic fallback still functions if this never lands).
 */
export async function writeCurrentInvocationMarker(
  sessionDir: string,
  sessionId: string,
  invocationId: string
): Promise<boolean> {
  try {
    const path = getCurrentInvocationMarkerPath(sessionDir, sessionId);
    await Bun.write(path, invocationId);
    return true;
  } catch {
    return false;
  }
}

/**
 * Read the current-invocation marker. Returns `null` when the file is absent,
 * unreadable, or empty — callers treat that as "no strong binding available,"
 * not an error.
 */
export async function readCurrentInvocationMarker(
  sessionDir: string,
  sessionId: string
): Promise<string | null> {
  try {
    const path = getCurrentInvocationMarkerPath(sessionDir, sessionId);
    const file = Bun.file(path);
    if (!(await file.exists())) return null;
    const content = (await file.text()).trim();
    return content.length > 0 ? content : null;
  } catch {
    return null;
  }
}

const startedAtMs = latest.startedAt.getTime();
const staleness = computeDispatchStaleness(
  startedAtMs,
  lastCommitAtMs,
  now().getTime(),
  staleMs
);

if (!staleness.stale) {
  return {
    success: true,
    status: "healthy" as const,
    taskId,
    sessionId: subagentSessionId,
    staleForMs: staleness.staleForMs,
    message:
      `Dispatch for ${taskId} has recent activity (last activity ${staleness.staleForMs}ms ` +
      `ago, below the ${staleMs}ms stale window) — treated as healthy, no action taken.`,
  };
}

// ── 2-attempt bound: refuse a 3rd attempt, return an escalation package. ─────────
const attemptNumber = latest.attemptNumber ?? 1;
if (attemptNumber >= 2) {
  const chain = await tracker.getInvocationChainForTask(taskId);
  const attempts: DispatchRecoveryEscalationAttempt[] = (
    chain.length > 0 ? chain : [latest]
  ).map((row) => ({
    invocationId: row.id,
    attemptNumber: row.attemptNumber ?? 1,
    startedAt: row.startedAt.toISOString(),
    outcome: row.outcome ?? null,
  }));
  return {
    success: true,
    status: "escalate" as const,
    taskId,
    sessionId: subagentSessionId,
    escalation: {
      taskId,
      attempts,
      message:
        `Dispatch for ${taskId} has gone silent again after a prior auto-resume ` +
        `(attempt ${attemptNumber}). The 2-attempt bound is reached — no further ` +
        `auto-resume will be attempted. An operator/orchestrator decision is needed: ` +
        `diagnose why this dispatch keeps stalling (repeated infra failure? a task ` +
        `that genuinely exceeds a single dispatch's capacity? rate-limiting — check ` +
        `SubagentDispatchTracker.getEscalation() before assuming death) before retrying ` +
        `manually.`,
    },
  };
}

// ── Build the probe (git-diff presence, commits-ahead, handoff.md). ─────────────
const gitStatus = await gitOps.status(sessionDir);
const baseBranch =
  sessionRecord?.pullRequest?.baseBranch ?? (await gitOps.detectDefaultBranch(sessionDir));
const commitsAheadOfBase = baseBranch
  ? await gitOps.commitsAheadOfBase(sessionDir, baseBranch)
  : null;
const handoffFileContent = await gitOps.readHandoff(sessionDir, subagentSessionId);

const probe: DispatchRecoveryProbeResult = buildDispatchRecoveryProbe({
  session: subagentSessionId,
  gitStatus,
  commitsAheadOfBase,
  baseBranch,
  pr: {
    number: sessionRecord?.pullRequest?.number ?? null,
    url: sessionRecord?.pullRequest?.url ?? null,
    state: sessionRecord?.pullRequest?.state ?? null,
    // Live review-thread fetch is intentionally out of scope for this on-demand
    // command (see module header "Does NOT cover") — the continuation prompt
    // instructs the resumed agent to check review state itself once redispatched.
    latestReview: null,
    reviewFetchError: null,
  },
  handoffFileContent,
  handoffMaxLines: DISPATCH_RECOVERY_PROBE_HANDOFF_MAX_LINES,
});

const classification = classifyDispatchRecoveryState({
  dirtyFileCount: probe.dirtyFileCount,
  commitsAheadOfBase: probe.commitsAheadOfBase,
  handoffExists: probe.handoff.exists,
});

const continuationPrompt = buildDispatchRecoveryContinuationPrompt({
  taskId,
  sessionId: subagentSessionId,
  sessionDir,
  agentType: latest.agentType,
  classification,
  dirtyFileCount: probe.dirtyFileCount,
  commitsAheadOfBase: probe.commitsAheadOfBase,
  handoffExists: probe.handoff.exists,
  handoffFirstLines: probe.handoff.firstLines,
  prNumber: probe.pr.number,
  prUrl: probe.pr.url,
  latestReviewState: probe.pr.latestReview?.state ?? null,
  attemptNumber: attemptNumber + 1,
  originalStartedAt: latest.startedAt.toISOString(),
});

// Close out the ORIGINAL row: it has now been classified as died/stalled. The
// classification describes the ORIGINAL attempt's final state, not the new
// (about-to-be-redispatched) attempt's — record it there, and mark the row
// ended (mt#2831 R1 BLOCKING #1). This is also what makes the tracker's
// heuristic upsert path's "prefer the OPEN row" selection meaningful: once
// this UPDATE lands, at most one row per subagentSessionId is open at a time
// in the common (non-racing) case.
await tracker.recordSubagentInvocation({
  id: latest.id,
  taskId,
  subagentSessionId,
  agentType: latest.agentType,
  suggestedModel: latest.suggestedModel,
  startedAt: latest.startedAt,
  endedAt: now(),
  outcome: classification,
  summary: `Classified as ${classification} by tasks.dispatch-recover; superseded by attempt ${attemptNumber + 1}.`,
});

// Insert the NEW (resumed) row. Pessimistic default outcome + no endedAt —
// mirrors the dispatch-time convention in tasks.dispatch Step 5: this row
// describes the worst-case observed state until the eventual SubagentStop
// classifies it for real. It must NOT carry `classification`, which describes
// the ORIGINAL attempt (recorded above), not this brand-new one.
const newInvocationId = await tracker.recordDispatchRecoveryAttempt({
  taskId,
  subagentSessionId,
  agentType: latest.agentType,
  suggestedModel: latest.suggestedModel,
  startedAt: now(),
  outcome: "crashed-no-output",
  resumedFromInvocationId: latest.id,
  attemptNumber: attemptNumber + 1,
  summary: `Auto-resumed via tasks.dispatch-recover from invocation ${latest.id} (attempt ${attemptNumber}, classified ${classification}).`,
});

if (!newInvocationId) {
  log.warn("[tasks.dispatch-recover] Failed to record recovery attempt row", { taskId });
} else {
  // mt#2831 R1 BLOCKING #1: overwrite the current-invocation marker so the
  // NEXT SubagentStop event for this session binds to THIS (resumed) row —
  // not the just-closed original. Best-effort; a write failure here just
  // means the eventual Stop event falls back to the heuristic upsert path.
  const { writeCurrentInvocationMarker } = await import(
    "@minsky/domain/session/current-invocation-marker"
  );
  await writeCurrentInvocationMarker(sessionDir, subagentSessionId, newInvocationId);
}

return {
  success: true,
  status: "recover" as const,
  taskId,
  sessionId: subagentSessionId,
  sessionDir,
  agentType: latest.agentType,
  suggestedModel: latest.suggestedModel,

