  guardName: string,
  fn: () => Promise<HookResult>,
  overrideEnvVar?: string,
  deps: RunInstrumentedStepDeps = {}
): Promise<HookResult> {
  const recordFireLog = deps.recordFireLog ?? recordPreCommitFireLogEntry;
  const now = deps.now ?? Date.now;
  const startMs = now();
  return fn().then((result) => {
    const durationMs = now() - startMs;
    const overridden = result.overridden === true && overrideEnvVar !== undefined;
    recordFireLog({

      error: getErrorMessage(err),
      sessionId,
    });
  }
}

/**
 * Begin a staleness-driven shutdown (mt#1315 mechanism, mt#2701 drain, mt#2830
 * idle-gap sequencing): emit a notifications/message at level=alert, tag the
 * upcoming exit as `staleness_exit`, set `pendingStaleExit` (NOT `draining` —
 * see the field comment), then wait for the first IDLE GAP — the moment
 * `inFlightRequests` reaches 0 — before scheduling `process.exit(0)` after a
 * 200ms flush buffer. A hard cap (`staleDrainCapMs`) force-exits if the server
 * is never idle for that long.
 *
 * Only fires once per process lifetime (guarded by hasTriggeredStaleSignal).
 *
 * mt#2830: requests already in flight when staleness is detected are waited
 * on (mt#2701's original guarantee — the detecting call is itself in flight
 * until its `finally` runs, so the drain waits for it and every concurrent
 * sibling to respond first). NEW requests that arrive DURING the drain window
 * are also served normally — they are NOT rejected — because `draining`
 * (the flag the `tools/call` handler gates on) is intentionally left false.
 * This closes the -32603 "Server is shutting down" gap: a caller issuing a
 * tool call while a staleness exit is pending gets a normal response on the
 * still-loaded ("old") code, exactly as it would have moments earlier. The
 * freshness guarantee is unchanged for the POST-exit world — the next call
 * after the process actually exits and is respawned gets the new HEAD.
 *
 * See scheduleStaleExitAfterDrain.
 */
private triggerStaleSignal(server: Server): void {
  if (this.hasTriggeredStaleSignal) return;
  this.hasTriggeredStaleSignal = true;

  // Extract 8-char head slices from the detector's cached stale message.
  // The detector already has startupHead/currentHead as private fields used
  // to build staleMessage; we re-derive them by reading the stale message
  // text rather than adding new public surface to StalenessDetector.
  const staleMessage = this.stalenessDetector.getStaleWarning() ?? "";
  const startupHeadMatch = /commit ([0-9a-f]{7,8})/i.exec(staleMessage);
  const currentHeadMatch = /now at ([0-9a-f]{7,8})/i.exec(staleMessage);
  const startupHead = startupHeadMatch ? startupHeadMatch[1] : "unknown";
  const currentHead = currentHeadMatch ? currentHeadMatch[1] : "unknown";

  server
    .sendLoggingMessage({
      level: "alert",
      logger: "minsky-staleness",
      data: {
        text: "Minsky source has changed since this server started; reconnect via /mcp.",
        startupHead,
        currentHead,
      },
    })
    .catch((err) => {
      log.debug("Failed to send staleness notification (non-blocking)", {
        error: getErrorMessage(err),
      });
    });

  // mt#1682: tag the upcoming exit as `staleness_exit` BEFORE process.exit
  // fires. Without this, the SDK's onclose handler (chained via
  // wireDisconnectHooks) records `stdin_close` during stdio teardown,
  // conflating the by-design staleness exit with harness-initiated
  // closures. Append-only persistence (mt#1682) guarantees the event hits
  // disk before the 200ms timeout completes.
  this.disconnectTracker.recordDisconnect("staleness_exit", {
    sessionKey: STDIO_SESSION_KEY,
    errorMessage: staleMessage || undefined,
  });

  // mt#2830: set pendingStaleExit (NOT draining) so the exit is sequenced
  // into the first idle gap while new tool calls keep being served normally
  // in the meantime. See the field comments and this method's docstring.
  this.pendingStaleExit = true;
  this.scheduleStaleExitAfterDrain();
}

/**
 * Poll until no tool call is in flight (or `staleDrainCapMs` elapses), then
 * schedule the process exit after a short flush buffer so the final response
 * reaches the transport before the process dies (mt#2701).
 *
 * mt#2830: `inFlightRequests` counts BOTH requests that were already
 * executing when staleness was detected AND new requests that arrive while
 * `pendingStaleExit` is true (the `tools/call` handler does not reject them
 * — see `pendingStaleExit`'s field comment). So a steady trickle of new
 * calls naturally extends the drain past a single request's lifetime; this
 * is intentional ("first idle gap", not "first response"). `staleDrainCapMs`
 * is the backstop: if the server is never idle for that long, the exit
 * fires anyway so staleness cannot be starved indefinitely by continuous
 * traffic.
 */
private scheduleStaleExitAfterDrain(): void {
  const POLL_INTERVAL_MS = 50;
  const FLUSH_BUFFER_MS = 200;
  const start = Date.now();

  const scheduleExit = (wedgedRequests: number): void => {
    if (wedgedRequests > 0) {
      log.warn("MCP staleness drain cap reached — exiting with requests still in flight", {
        wedgedRequests,
        capMs: this.staleDrainCapMs,
      });
    } else {
      log.debug("MCP staleness drain complete — all in-flight requests finished", {
        drainMs: Date.now() - start,
      });
    }
    setTimeout(() => this.exit(0), FLUSH_BUFFER_MS);
  };

  const poll = (): void => {
    const inFlight = this.inFlightRequests.size;
    if (inFlight === 0) {
      scheduleExit(0);
      return;
    }
    if (Date.now() - start >= this.staleDrainCapMs) {
      scheduleExit(inFlight);
      return;
    }
    setTimeout(poll, POLL_INTERVAL_MS);
  };
  poll();
}

/**
 * Install SIGTERM / SIGINT / SIGHUP listeners that record a cause-tagged
 * disconnect event before the process exits. Without these, signal-driven
 * shutdowns surface as generic `stdin_close` (because the SDK's onclose
 * fires during stdio teardown) — losing the distinction between by-design
 * shutdowns and harness-initiated closures.
 *
 * The handler is a no-op if a previous MinskyMCPServer instance in the same
 * process already installed listeners. Multiple servers per process is
 * unusual but possible (tests); the singleton DisconnectTracker means the
 * recorded events are still correctly attributed.
 *
 * The handler explicitly does NOT call process.exit. After recording the
 * cause, control returns to Node's default signal handling (or any
 * additional listeners installed by other parts of the application), which
 * is what eventually terminates the process. This avoids interfering with
 * graceful-shutdown paths that other code may have wired up.
 *
 * @see mt#1682 — cause classification
 */
private installSignalHandlers(): void {
  if (MinskyMCPServer.signalHandlersInstalled) return;
  MinskyMCPServer.signalHandlersInstalled = true;

  // The project's narrowed `process` type omits EventEmitter methods.
  // Cast to a Node-shaped surface for the signal-handling APIs we need —
  // intentional escape from the narrow type to access on/removeListener/kill.
  type ProcSignal = "SIGTERM" | "SIGINT" | "SIGHUP";
  // eslint-disable-next-line custom/no-excessive-as-unknown
  const proc = process as unknown as {
    pid: number;
    on(event: ProcSignal, listener: () => void): void;
    removeListener(event: ProcSignal, listener: () => void): void;

 * Block until the proxy process exits. The CLI entrypoint calls this
 * after `start()` resolves; the proxy stays alive as a daemon until
 * SIGTERM/SIGINT (handled in `setupSignalHandlers`) or an unrecoverable
 * crash (handled in `onChildClose`).
 *
 * Split from `start()` in PR #1216 R2: prior to the split, `start()`
 * itself awaited this lifetime promise, which made it impossible for
 * callers to do anything after the proxy was up. See R2 reviewer
 * BLOCKING 3 for the original concern.
 */
async waitForExit(): Promise<void> {
  await new Promise<void>((resolve) => {
    proc.once("exit", resolve);
  });
}

/**
 * Spawn the inner server child process and wire stdio pipes.
 * Called on initial start and on each respawn.
 *
 * Returns a Promise that resolves when the post-spawn readiness probe
 * (mt#2011) completes — either because the inner responded to the
 * synthesized `ping` request (semantic readiness signal: the inner's
 * protocol layer is operational), or because the
 * `READY_PROBE_TIMEOUT_MS` fallback elapsed. On respawns (spawnCount > 1)
 * the probe completion also writes `notifications/tools/list_changed`
 * upstream so Claude Code refreshes its `tools/list` cache without
 * needing `/mcp` reconnect.
 *
 * The async return shape lets `handleProxyRestart()` `await spawnChild()`
 * and send its tool-call success response only after the notification has
 * been emitted (ensuring Claude Code sees notification-then-response, not
 * response-then-notification with a race window in between). `start()`
 * and `onChildClose()` ignore the returned promise (fire-and-forget) since
 * they do not need to sequence anything after probe completion.
 */
async spawnChild(): Promise<void> {
  if (this.isShuttingDown) return;

  // Cancel any probe outstanding from a prior child (mt#2011). The prior
  // child's stdio is being replaced; that probe will never receive a
  // response. Cancelling clears its timeout, resolves the prior
  // spawnChild() promise, and DOES NOT emit a stale notification — the
  // new probe will emit one if appropriate.
  if (this.pendingProbe !== null) {
    log.debug("[proxy] Cancelling pending probe from prior child", {
      probeId: this.pendingProbe.id,
    });
    this.pendingProbe.cancel();
  }

  log.debug("[proxy] Spawning inner MCP server", {
    command: this.childCommand,
    args: this.childArgs,
  });

  // mt#2830: reset the diagnostic buffers for the new child. Stale data
  // from a prior child must never be attributed to this one.
  this.stderrTail = "";
  this.lastTransportEvent = "";

  const child = spawn(this.childCommand, this.childArgs, {
    // stdin: pipe so we can write to it
    // stdout: pipe so we can read and intercept
    // stderr: pipe (mt#2830, was "inherit") so we can capture a bounded
    // tail for unknown-cause disconnect diagnostics WHILE STILL forwarding
    // every byte to the proxy's own stderr below — operators lose no
    // visibility, we just also keep a ring buffer.
    stdio: ["pipe", "pipe", "pipe"],
  });

  this.child = child;

  // Wire the inbound path: stdin → inbound-transform → child.stdin
  this.inboundTransform = this.createInboundTransform();
  (proc.stdin as Readable).pipe(this.inboundTransform).pipe(child.stdin as Writable);

  // Wire the outbound path: child.stdout → outbound-transform → stdout
  this.outboundTransform = this.createOutboundTransform();
  (child.stdout as Readable).pipe(this.outboundTransform).pipe(proc.stdout as Writable);

  // mt#2830: capture stderr into the bounded tail AND forward it verbatim
  // to the proxy's own stderr (equivalent to the old `"inherit"` behavior
  // for operator-visible logs).
  if (child.stderr) {
    (child.stderr as Readable).on("data", (chunk: Buffer | string) => {
      const chunkStr = String(chunk);
      this.stderrTail = (this.stderrTail + chunkStr).slice(-STDERR_TAIL_MAX_CHARS);
      try {
        process.stderr.write(chunkStr);
      } catch {
        // Best-effort forwarding only — never let a write failure here
        // affect child lifecycle handling.
      }
    });
  }

  child.on("error", (err) => {
    log.error("[proxy] Child process error", { error: err.message });
  });

  // Store close handler reference so handleProxyRestart can remove it before
  // killing the child. Without removal, killing fires close → onChildClose →
  // schedules a respawn PLUS handleProxyRestart calls spawnChild directly =
  // double-spawn. See BLOCKING 1 in PR #1039 R1 reviewer findings.
  const closeHandler = (code: number | null, signal: NodeJS.Signals | null) => {
    this.onChildClose(code, signal);
  };
  child.on("close", closeHandler);
  // Attach the handler reference so handleProxyRestart can detach it before
  // killing the child (preventing the double-spawn race). ChildProcess has no
  // _proxyCloseHandler field in its type definition; the as-unknown cast is the
  // only way to attach this side-channel without modifying the ChildProcess type.
  // eslint-disable-next-line custom/no-excessive-as-unknown -- side-channel property on ChildProcess, no alternative
  (child as unknown as { _proxyCloseHandler: typeof closeHandler })._proxyCloseHandler =
    closeHandler;

  this.spawnCount += 1;
  log.debug("[proxy] Inner MCP server spawned", {
    pid: child.pid,
    spawnCount: this.spawnCount,
  });

  // Send the ping readiness probe and await its completion (response or
  // timeout). On respawns (spawnCount > 1), completion also writes
  // `notifications/tools/list_changed` upstream.
  const emitToolsListChanged = this.spawnCount > 1;
  await this.runReadyProbe(child, emitToolsListChanged);
}

/**
 * Send a `ping` request to the freshly-spawned child and resolve when the
 * matching response arrives (the outbound transform intercepts it and calls
 * `pendingProbe.complete("response")`) or when `READY_PROBE_TIMEOUT_MS`
 * elapses. When `emitNotification` is true, completion writes
 * `notifications/tools/list_changed` to `process.stdout` so Claude Code
 * refreshes its tools cache (mt#2011).
 *
 * The probe id carries the reserved `__proxy_ready_probe_<spawnCount>`
 * prefix; the outbound transform recognises it by prefix and discards
 * the response (it is never forwarded upstream).
 */
private runReadyProbe(child: ChildProcess, emitNotification: boolean): Promise<void> {
  return new Promise<void>((resolve) => {
    if (this.isShuttingDown) {
      resolve();
      return;
    }

    const probeId = `${PROXY_READY_PROBE_ID_PREFIX}${this.spawnCount}`;
    let completed = false;

    const complete = (reason: "response" | "timeout"): void => {
      if (completed) return;
      completed = true;

      // Clear pendingProbe iff it still refers to this probe (defensive:
      // a subsequent respawn may have already overwritten it).
      if (this.pendingProbe?.id === probeId) {
        clearTimeout(this.pendingProbe.timeoutHandle);
        this.pendingProbe = null;

/**
 * Override the recorded process start time for test purposes. Lets uptime-
 * filtering tests record disconnects with arbitrary `uptimeMs` values
 * without sleeping. Only call from test code.
 */
setProcessStartTimeForTest(timestamp: number): void {
  this.processStartTime = timestamp;
}

/**
 * Increment the tool-call counter for the given session (mt#1705).
 * Called from the `CallToolRequestSchema` handler in `server.ts` on each
 * tool invocation (before the handler runs, so the count is accurate even
 * if the tool throws). The count is read at `recordDisconnect(cause, { sessionKey })`
 * time to classify the session as `"helper"` (0 calls) or `"main_session"`
 * (1+ calls).
 *
 * `sessionKey` is `STDIO_SESSION_KEY` for stdio mode (one server per process)
 * or a per-session UUID for HTTP mode (multiple per-session Servers in one
 * process). Defaults to `DEFAULT_SESSION_KEY` for back-compat with callers
 * that don't yet pass a key (legacy tests, ad-hoc callers).
 */
incrementToolCallCount(sessionKey: string = DEFAULT_SESSION_KEY): void {
  this.toolCallCounts.set(sessionKey, (this.toolCallCounts.get(sessionKey) ?? 0) + 1);
}

/**
 * Return the current tool-call count for a session. For use by tests and
 * diagnostics. If `sessionKey` is omitted, returns the sum across all
 * tracked sessions (useful for "did this process see any work at all"
 * diagnostics).
 */
getToolCallCount(sessionKey?: string): number {
  if (sessionKey !== undefined) {
    return this.toolCallCounts.get(sessionKey) ?? 0;
  }
  let total = 0;
  for (const n of this.toolCallCounts.values()) total += n;
  return total;
}

/**
 * Record the start of this MCP server process. Called from the
 * `MinskyMCPServer` constructor before any tool can be invoked. The
 * `process_start` lifecycle marker lets log readers count actual server
 * processes (including those that lived <1s and never recorded a disconnect)
 * and correlate disconnect events back to the specific process that
 * produced them.
 */
recordProcessStart(): McpDisconnectEvent {
  const event: McpDisconnectEvent = {
    timestamp: new Date(this.processStartTime).toISOString(),
    serverName: this.serverName,
    kind: "process_start",
    cause: "process_start",
    pid: this.processPid,
  };
  this.push(event);
  log.info("mcp_process_start", {
    serverName: event.serverName,
    pid: event.pid,
  });
  this.appendEvent(event);
  return event;
}

/**
 * Record a disconnect event. Emits a structured log line and durably
 * appends to disk before returning.
 *
 * Process role classification (mt#1705): at disconnect time, the tool-call
 * count is read from `this.toolCallCounts.get(sessionKey)` (incremented by
 * `incrementToolCallCount(sessionKey)` on each tool invocation in that
 * session). 0 calls → "helper", 1+ calls → "main_session". Helper sessions
 * are excluded from escalation eligibility regardless of uptime.
 *
 * The map entry for `sessionKey` is evicted after the role is computed,
 * keeping `toolCallCounts` bounded to live sessions only.
 *
 * Backward-compat: callers may pass `errorMessage` as the second positional
 * argument (legacy two-arg form) or the new `{ sessionKey?, errorMessage? }`
 * options object. The legacy form falls back to `DEFAULT_SESSION_KEY`,
 * matching the pre-mt#1705-per-session-counter behavior.
 *
 * mt#2830: the options object also accepts `exitCode`/`signal`/`stderrTail`
 * (best-effort child-process diagnostics, populated by the stdio proxy's
 * child-close observation — see `McpDisconnectEvent`'s field docs) and
 * `processRoleOverride`. The proxy runs in a SEPARATE process from the
 * inner server and has no tool-call-count visibility, so the default
 * `toolCallCounts`-derived helper/main_session heuristic would always
 * classify its events as "helper" (0 calls) and silently exclude them from
 * escalation — including the SIGKILL case this instrumentation exists to
 * surface. `processRoleOverride` lets such a caller supply the correct
 * classification directly instead of relying on the inapplicable heuristic.
 */
recordDisconnect(
  cause: McpDisconnectCause,
  errorMessageOrOptions?:
    | string
    | {
        sessionKey?: string;
        errorMessage?: string;
        exitCode?: number | null;
        signal?: string | null;
        stderrTail?: string;
        lastTransportEvent?: string;
        processRoleOverride?: McpProcessRole;
      }
): McpDisconnectEvent {
  // Normalize the two call shapes.
  let sessionKey: string;
  let errorMessage: string | undefined;
  let exitCode: number | null | undefined;
  let signal: string | null | undefined;
  let stderrTail: string | undefined;
  let lastTransportEvent: string | undefined;
  let processRoleOverride: McpProcessRole | undefined;
  if (typeof errorMessageOrOptions === "string") {
    sessionKey = DEFAULT_SESSION_KEY;
    errorMessage = errorMessageOrOptions;
  } else if (errorMessageOrOptions) {
    sessionKey = errorMessageOrOptions.sessionKey ?? DEFAULT_SESSION_KEY;
    errorMessage = errorMessageOrOptions.errorMessage;
    exitCode = errorMessageOrOptions.exitCode;
    signal = errorMessageOrOptions.signal;
    stderrTail = errorMessageOrOptions.stderrTail;
    lastTransportEvent = errorMessageOrOptions.lastTransportEvent;
    processRoleOverride = errorMessageOrOptions.processRoleOverride;
  } else {
    sessionKey = DEFAULT_SESSION_KEY;
    errorMessage = undefined;
  }

  const uptimeMs = Date.now() - this.processStartTime;
  // mt#1705: classify process role from PER-SESSION tool-call count at
  // disconnect time. Reading the process-wide counter (the original mt#1705
  // approach) misclassified HTTP per-session disconnects when any session
  // in the process had made a tool call — see R1 review on PR #1027.
  // 0 calls → "helper" (harness helper: hook spawner, probe, pre-flight check).
  // 1+ calls → "main_session" (substantive working session).
  // mt#2830: `processRoleOverride` bypasses this heuristic entirely — see
  // the method docstring above.
  const sessionToolCalls = this.toolCallCounts.get(sessionKey) ?? 0;
  const processRole: McpProcessRole =
    processRoleOverride ?? (sessionToolCalls === 0 ? "helper" : "main_session");
  // Evict the entry — the session is closing and we've captured what we need.
  this.toolCallCounts.delete(sessionKey);
  const event: McpDisconnectEvent = {
    timestamp: new Date().toISOString(),
    serverName: this.serverName,
    kind: "disconnect",
    cause,
    uptimeMs,
    processRole,
    ...(errorMessage ? { error: errorMessage } : {}),
    ...(exitCode !== undefined ? { exitCode } : {}),
    ...(signal !== undefined ? { signal } : {}),
    ...(stderrTail ? { stderrTail } : {}),
    ...(lastTransportEvent ? { lastTransportEvent } : {}),
  };
  this.push(event);

      projectId,
      pid,
      entrypoint,
      terminalContext: Object.keys(terminalContext).length > 0 ? terminalContext : undefined,
    });
    log.debug("session attachment written", { sessionId, actorId, pid });
  } catch (err) {
    log.debug("session attachment write failed (non-blocking)", {
      error: getErrorMessage(err),
      sessionId,
    });
  }
}

