// ---------------------------------------------------------------------------
// Read path
// ---------------------------------------------------------------------------

export type AskGrantStoreReadResult =
  | { status: "ok"; grants: AskGrant[] }
  | { status: "error"; message: string };

/**
 * Read + parse the grant store. File absent -> confirmed zero-grants state.
 * Unreadable/malformed -> `{ status: "error" }` — the BRIDGE treats this as
 * "no grant" (falls through to the normal permission flow, which is the safe
 * direction for an allow-emitting hook; contrast the D8 read path where
 * fail-open means permitting).
 */
export function readAskGrantStore(
  storePath: string,
  fsDeps: AskGrantStoreFsDeps = defaultFsDeps
): AskGrantStoreReadResult {
  let raw: string;
  try {
    raw = fsDeps.readFileSync(storePath);
  } catch (err) {
    const code = (err as NodeJS.ErrnoException)?.code;
    if (code === "ENOENT") {
      return { status: "ok", grants: [] };
    }
    return { status: "error", message: err instanceof Error ? err.message : String(err) };
  }

  const grants = parseAskGrantStoreContent(raw);
  if (grants === null) {
    return { status: "error", message: `malformed ask grant store JSON at ${storePath}` };
  }
  return { status: "ok", grants };
}

// ---------------------------------------------------------------------------
// Matching
// ---------------------------------------------------------------------------

/**
 * True when `grant` is currently valid for `ctx`: unconsumed, unexpired,
 * same tool, and `commandPattern` matches the pending command. A pattern
 * that fails to compile as a RegExp never matches (conservative).
 */
export function isAskGrantValid(
  grant: AskGrant,
  ctx: AskGrantMatchContext,
  nowMs: number
): boolean {
  if (grant.consumedAt !== undefined) return false;
  const issuedMs = Date.parse(grant.issuedAt);
  if (Number.isNaN(issuedMs)) return false;
  if (nowMs >= issuedMs + grant.ttlMs) return false; // expired
  if (grant.tool !== ctx.tool) return false;

  let re: RegExp;
  try {
    re = new RegExp(grant.commandPattern);
  } catch {
    return false;
  }
  return re.test(ctx.command);
}

/** Return the first grant valid for `ctx` at `nowMs`, or null. */
export function findValidAskGrant(
  grants: AskGrant[],
  ctx: AskGrantMatchContext,
  nowMs: number
): AskGrant | null {
  return grants.find((g) => isAskGrantValid(g, ctx, nowMs)) ?? null;
}

// ---------------------------------------------------------------------------
// Write paths
// ---------------------------------------------------------------------------

function pruneExpired(grants: AskGrant[], nowMs: number): AskGrant[] {
  return grants.filter((g) => {
    const issuedMs = Date.parse(g.issuedAt);
    return !Number.isNaN(issuedMs) && nowMs < issuedMs + g.ttlMs;
  });
}

/**
 * Append `grant` to the store, pruning expired grants (consumed grants are
 * retained until expiry as an audit trace). Creates the state dir/store if
 * absent. A corrupt existing store starts fresh — issuance is an explicit
 * action; the read side's conservatism is what protects the bridge.
 */
export function appendAskGrant(
  storePath: string,
  grant: AskGrant,
  fsDeps: AskGrantStoreFsDeps = defaultFsDeps,
  nowMs: number = Date.now()
): void {
  fsDeps.mkdirSync(path.dirname(storePath));

  const existing = readAskGrantStore(storePath, fsDeps);
  const currentGrants = existing.status === "ok" ? existing.grants : [];
  const unexpired = pruneExpired(currentGrants, nowMs);

  unexpired.push(grant);
  fsDeps.writeFileSync(storePath, `${JSON.stringify({ grants: unexpired }, null, 2)}\n`);
}

/**
 * Mark `grant` consumed (one-shot). Identity is (askId, tool, commandPattern,
 * issuedAt) — the tuple that uniquely identifies an issuance. Returns true
 * when a matching unconsumed grant was found and marked; false otherwise
 * (caller must then NOT emit an allow — losing the race means the grant was
 * already spent).
 */
export function consumeAskGrant(
  storePath: string,
  grant: AskGrant,
  fsDeps: AskGrantStoreFsDeps = defaultFsDeps,
  nowMs: number = Date.now()
): boolean {
  const existing = readAskGrantStore(storePath, fsDeps);
  if (existing.status !== "ok") return false;

  let marked = false;
  const updated = existing.grants.map((g) => {
    if (
      !marked &&
      g.consumedAt === undefined &&
      g.askId === grant.askId &&
      g.tool === grant.tool &&
      g.commandPattern === grant.commandPattern &&
      g.issuedAt === grant.issuedAt
    ) {
      marked = true;
      return { ...g, consumedAt: new Date(nowMs).toISOString() };
    }
    return g;
  });

  if (!marked) return false;
  fsDeps.mkdirSync(path.dirname(storePath));
  fsDeps.writeFileSync(storePath, `${JSON.stringify({ grants: updated }, null, 2)}\n`);
  return true;
}

