#!/usr/bin/env bun
// Approved-Ask ↔ harness-permission bridge (mt#2823).
//
// PreToolUse hook on `Bash` + `mcp__minsky__session_exec`: when the pending
// command matches a live, unconsumed, TTL-bound ask-grant
// (`.minsky/hooks/ask-grant-store.ts`) AND the referenced
// `authorization.approve` Ask verifies server-side as operator-approved,
// emit the harness `permissionDecision: "allow"` — so an approval routed
// through the Ask substrate authorizes the action without a SECOND manual
// approval at the harness classifier (the c01f89af double-approval
// round-trip this task exists to close).
//
// ## Decision ladder (fail-safe by construction)
//
//   1. subagent invocation (agent_id present)      → silent defer (exit 0)
//   2. tool not Bash/session_exec, or no command   → silent defer
//   3. store unreadable                            → defer + stderr warning
//   4. no matching grant                           → silent defer (the
//      overwhelmingly common path — normal permission flow applies; per the
//      vendor hook contract, exit 0 with no output is "no decision")
//   5. grant matched, ask verification UNAVAILABLE → defer + warning (never
//      allow on unverifiable state)
//   6. grant matched, ask verification NEGATIVE    → DENY + loud warning
//      (fabrication signal — a grant whose ask is absent/unapproved/non-
//      operator-attributed; the grant is left unconsumed for inspection)
//   7. grant matched + ask verified               → consume the grant
//      (one-shot, BEFORE emitting the decision; losing the consume race
//      defers), emit best-effort `hook.fired {decision:"overridden"}`
//      audit event, then `permissionDecision: "allow"` with an audit reason
//      naming the askId.
//
// Deny-precedence: the harness combines PreToolUse decisions with deny
// outranking allow, so this bridge structurally cannot bypass other guards
// (git/gh CLI ban, bypass-merge guard) — it only preempts the permission
// classifier when no other hook denies.
//
// Authoritative source (recorded in the mt#2823 spec's Plan decision):
// https://code.claude.com/docs/en/hooks — PreToolUse `hookSpecificOutput`
// `permissionDecision: "allow" | "deny" | "ask"`; exit 0 with no output
// defers to the normal permission flow.
//
// @see .minsky/hooks/ask-grant-store.ts — grant store (one-shot, TTL)
// @see .minsky/hooks/ask-verification.ts — server-side ask verification
// @see scripts/grant-ask-action.ts — issuance surface
// @see docs/architecture/hooks/ask-permission-bridge.md

import { readInput, writeOutput, execWithPath } from "./types";
import type { ToolHookInput } from "./types";
import {
  getAskGrantStorePath,
  readAskGrantStore,
  findValidAskGrant,
  consumeAskGrant,
  type AskGrant,
} from "./ask-grant-store";
import { verifyApprovedAsk, type AskVerificationResult } from "./ask-verification";

const BRIDGE_TOOLS = new Set(["Bash", "mcp__minsky__session_exec"]);

/** Extract the command string the grant pattern is matched against. */
export function extractCommand(
  toolName: string,
  toolInput: Record<string, unknown>
): string | null {
  if (!BRIDGE_TOOLS.has(toolName)) return null;
  const command = toolInput?.command;
  return typeof command === "string" && command.length > 0 ? command : null;
}

/** Build the allow-decision audit reason. Exported for tests. */
export function buildAllowReason(grant: AskGrant): string {
  return (
    `[ask-permission-bridge] allowed by operator-approved ask ${grant.askId} ` +
    `(one-shot grant issued ${grant.issuedAt} consumed; reason: ${grant.reason})`
  );
}

/** Build the deny-decision reason for a verification-failed grant. Exported for tests. */
export function buildDenyReason(grant: AskGrant, verification: AskVerificationResult): string {
  return (
    `[ask-permission-bridge] grant referencing ask ${grant.askId} FAILED server-side ` +

const ASKS_CLI_TIMEOUT_MS = 20000;
/**
 * Recency window: grants reference asks responded within the grant TTL
 * (minutes), so a newest-first page of this size always contains the target.
 */
const ASKS_LOOKUP_LIMIT = 200;

export interface AskVerificationResult {
  verdict: "approved" | "not-approved" | "unavailable";
  detail: string;
}

/** Minimal row shape read from `tools asks list` JSON output. */
export interface AskRow {
  id?: unknown;
  kind?: unknown;
  state?: unknown;
  response?: { responder?: unknown; payload?: unknown };
}

export type ExecFn = (
  cmd: string[],
  options?: { timeout?: number }
) => { exitCode: number; stdout: string; stderr: string };

/**
 * True when a kind-specific response payload expresses approval. Handles the
 * `{ approved: boolean }` cockpit-resolve shape plus approve-shaped option
 * values; everything else — including absent payloads — is NOT approval.
 */
export function isApprovingPayload(payload: unknown): boolean {
  if (payload === null || payload === undefined) return false;
  if (typeof payload === "string") return /^(approved?|yes)$/i.test(payload.trim());
  if (typeof payload === "object") {
    const rec = payload as Record<string, unknown>;
    if (rec.approved === true) return true;
    if (typeof rec.value === "string") return /^(approved?|yes)$/i.test(rec.value.trim());
  }
  return false;
}

/** Pure evaluation of fetched ask rows against the approval criteria. */
export function evaluateAskRows(rows: AskRow[], askId: string): AskVerificationResult {
  const ask = rows.find((r) => typeof r.id === "string" && r.id === askId);
  if (!ask) {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} not found among recent responded/closed authorization.approve asks`,
    };
  }
  if (ask.kind !== "authorization.approve") {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} has kind "${String(ask.kind)}", not authorization.approve`,
    };
  }
  const responder = ask.response?.responder;
  if (responder !== "operator") {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} responder is "${String(responder ?? "absent")}", not operator`,
    };
  }
  if (!isApprovingPayload(ask.response?.payload)) {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} response value is not an approval`,
    };
  }
  return { verdict: "approved", detail: `ask ${askId} approved by operator` };
}

function fetchState(state: string, exec: ExecFn): AskRow[] | { error: string } {
  const result = exec(
    [
      "minsky",
      "tools",
      "asks",
      "list",
      "--state",
      state,
      "--kind",
      "authorization.approve",
      "--limit",
      String(ASKS_LOOKUP_LIMIT),
    ],
    { timeout: ASKS_CLI_TIMEOUT_MS }
  );
  if (result.exitCode !== 0) {
    return { error: `minsky tools asks list --state ${state} exited ${result.exitCode}` };
  }
  try {
    const parsed = JSON.parse(result.stdout) as { asks?: unknown };
    if (!Array.isArray(parsed.asks))
      return { error: `unexpected asks list shape (state ${state})` };
    return parsed.asks as AskRow[];
  } catch (err) {
    return {
      error: `unparseable asks list JSON (state ${state}): ${err instanceof Error ? err.message : String(err)}`,
    };
  }
}

/**
 * Verify `askId` is an operator-approved `authorization.approve` Ask,
 * reading both "responded" (answered, pre-close) and "closed" (resolved)
 * states server-side.
 *
 * Partial-failure resilience (PR #2015 R1): a verdict grounded in a state
 * that WAS readable stands — if the ask is found in a readable state, its
 * evaluation (approved or not-approved) is definitive since an ask lives in
 * exactly one state. Only the not-found case escalates to "unavailable"
 * when a fetch failed, because absent-vs-in-the-failed-state cannot be
 * distinguished. Both fetches failing is always "unavailable".
 */
export function verifyApprovedAsk(
  askId: string,
  exec: ExecFn = execWithPath
): AskVerificationResult {
  const rows: AskRow[] = [];
  const errors: string[] = [];
  for (const state of ["responded", "closed"]) {
    const fetched = fetchState(state, exec);
    if ("error" in fetched) {
      errors.push(fetched.error);
    } else {
      rows.push(...fetched);
    }
  }

  if (errors.length === 2) {
    return { verdict: "unavailable", detail: errors.join("; ") };
  }

  const found = rows.some((r) => typeof r.id === "string" && r.id === askId);
  if (!found && errors.length > 0) {
    return {
      verdict: "unavailable",
      detail: `ask ${askId} not found in readable states, and one state fetch failed (${errors.join(
        "; "
      )}) — cannot distinguish absent from unreadable`,
    };
  }

  return evaluateAskRows(rows, askId);
}

export interface AskVerificationResult {
  verdict: "approved" | "not-approved" | "unavailable";
  detail: string;
}

/** Minimal row shape read from `tools asks list` JSON output. */
export interface AskRow {
  id?: unknown;
  kind?: unknown;
  state?: unknown;
  response?: { responder?: unknown; payload?: unknown };
}

export type ExecFn = (
  cmd: string[],
  options?: { timeout?: number }
) => { exitCode: number; stdout: string; stderr: string };

/**
 * True when a kind-specific response payload expresses approval. Handles the
 * `{ approved: boolean }` cockpit-resolve shape plus approve-shaped option
 * values; everything else — including absent payloads — is NOT approval.
 */
export function isApprovingPayload(payload: unknown): boolean {
  if (payload === null || payload === undefined) return false;
  if (typeof payload === "string") return /^(approved?|yes)$/i.test(payload.trim());
  if (typeof payload === "object") {
    const rec = payload as Record<string, unknown>;
    if (rec.approved === true) return true;
    if (typeof rec.value === "string") return /^(approved?|yes)$/i.test(rec.value.trim());
  }
  return false;
}

/** Pure evaluation of fetched ask rows against the approval criteria. */
export function evaluateAskRows(rows: AskRow[], askId: string): AskVerificationResult {
  const ask = rows.find((r) => typeof r.id === "string" && r.id === askId);
  if (!ask) {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} not found among recent responded/closed authorization.approve asks`,
    };
  }
  if (ask.kind !== "authorization.approve") {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} has kind "${String(ask.kind)}", not authorization.approve`,
    };
  }
  const responder = ask.response?.responder;
  if (responder !== "operator") {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} responder is "${String(responder ?? "absent")}", not operator`,
    };
  }
  if (!isApprovingPayload(ask.response?.payload)) {
    return {
      verdict: "not-approved",
      detail: `ask ${askId} response value is not an approval`,
    };
  }
  return { verdict: "approved", detail: `ask ${askId} approved by operator` };
}

function fetchState(state: string, exec: ExecFn): AskRow[] | { error: string } {
  const result = exec(
    [
      "minsky",
      "tools",
      "asks",
      "list",
      "--state",
      state,
      "--kind",
      "authorization.approve",
      "--limit",
      String(ASKS_LOOKUP_LIMIT),
    ],
    { timeout: ASKS_CLI_TIMEOUT_MS }
  );
  if (result.exitCode !== 0) {
    return { error: `minsky tools asks list --state ${state} exited ${result.exitCode}` };
  }
  try {
    const parsed = JSON.parse(result.stdout) as { asks?: unknown };
    if (!Array.isArray(parsed.asks))
      return { error: `unexpected asks list shape (state ${state})` };
    return parsed.asks as AskRow[];
  } catch (err) {
    return {
      error: `unparseable asks list JSON (state ${state}): ${err instanceof Error ? err.message : String(err)}`,
    };
  }
}

/**
 * Verify `askId` is an operator-approved `authorization.approve` Ask,
 * reading both "responded" (answered, pre-close) and "closed" (resolved)
 * states server-side.
 *
 * Partial-failure resilience (PR #2015 R1): a verdict grounded in a state
 * that WAS readable stands — if the ask is found in a readable state, its
 * evaluation (approved or not-approved) is definitive since an ask lives in
 * exactly one state. Only the not-found case escalates to "unavailable"
 * when a fetch failed, because absent-vs-in-the-failed-state cannot be
 * distinguished. Both fetches failing is always "unavailable".
 */
export function verifyApprovedAsk(
  askId: string,
  exec: ExecFn = execWithPath
): AskVerificationResult {
  const rows: AskRow[] = [];
  const errors: string[] = [];
  for (const state of ["responded", "closed"]) {
    const fetched = fetchState(state, exec);
    if ("error" in fetched) {
      errors.push(fetched.error);
    } else {
      rows.push(...fetched);
    }
  }

  if (errors.length === 2) {
    return { verdict: "unavailable", detail: errors.join("; ") };
  }

  const found = rows.some((r) => typeof r.id === "string" && r.id === askId);
  if (!found && errors.length > 0) {
    return {
      verdict: "unavailable",
      detail: `ask ${askId} not found in readable states, and one state fetch failed (${errors.join(
        "; "
      )}) — cannot distinguish absent from unreadable`,
    };
  }

  return evaluateAskRows(rows, askId);
}

// Canary runner core — mt#2889 (evaluation-loop Phase 1 completion).
//
// The RFC's load-bearing broken-vs-dormant disambiguator: a guard that has
// never fired in the real fire-log is indistinguishable from "nobody has
// tripped this guard's real-world trigger condition yet" UNLESS there is a
// separate, synthetic-input check proving the guard's DECISION LOGIC still
// works. This module runs each GUARD_REGISTRY entry's declared `canary`
// (registry.ts's `GuardRegistration.canary` field) through the REAL guard
// module's exported `run()` — the exact function the dispatcher invokes in
// production — and reports whether the outcome matches the declared
// `expects` kind.
//
// Two historical incidents this closes: mt#2057 (retrospective-trigger-
// scanner's calibration log went silent for 9 days before an operator
// noticed by hand) and mt#2835 (auto-session-title's ungated module-level
// main() killed the whole UserPromptSubmit dispatcher process for 7 days,
// invisible because exit code stayed 0). Both would have been caught within
// a single run of this canary suite.
//
// Dependency-free (per `.minsky/hooks/SPEC.md`'s invariant): only imports
// from sibling files in this tree. The CLI wrapper (`scripts/run-guard-
// canaries.ts`) imports from here — `scripts/` already has precedent for
// importing directly from `.minsky/hooks/` (see `grant-guard-override.ts`,
// `grant-subagent-merge.ts`).
//
// @see mt#2889 — this task
// @see .minsky/hooks/registry.ts — GUARD_REGISTRY, GuardRegistration.canary
// @see docs/architecture/evaluation-loop-fire-log.md
// @see scripts/run-guard-canaries.ts — CLI entrypoint consuming this module

import { GUARD_REGISTRY } from "./registry";
import type { GuardRegistration, GuardOutcome, DispatchContext, GuardModule } from "./registry";
import { deriveBudgets, DEFAULT_HOST_CAP_SEC } from "./types";
import type { ToolHookInput } from "./types";

// ---------------------------------------------------------------------------
// Canary evaluation (pure — no I/O)
// ---------------------------------------------------------------------------

export type CanaryExpectation = NonNullable<GuardRegistration["canary"]>["expects"];

/**
 * True iff `outcome` satisfies `expects`. Pure function — the sole seam
 * exercised directly by the sabotage-detection unit tests (see
 * `canary-runner.test.ts`), independent of any guard module or fs access.
 */
export function evaluateCanaryOutcome(
  outcome: GuardOutcome | null | undefined,
  expects: CanaryExpectation
): boolean {
  if (!outcome) return false;
  switch (expects) {
    case "deny":
      return outcome.deny !== undefined;
    case "warn":
      return typeof outcome.additionalContext === "string" && outcome.additionalContext.length > 0;
    case "calibration":
      return outcome.calibration !== undefined;
    case "sessionTitle":
      return outcome.sessionTitle !== undefined;
    default: {
      // Exhaustiveness guard — if a new `expects` variant is ever added to
      // the registry's canary type without a matching case here, fail
      // loudly (as "not satisfied") rather than silently reporting a false
      // pass.
      const _exhaustive: never = expects;
      return false;
    }
  }
}

// ---------------------------------------------------------------------------
// Dispatcher-registry canary execution
// ---------------------------------------------------------------------------

export interface CanaryResult {
  guardName: string;
  /** "registry" (GUARD_REGISTRY entry, run via its exported run()) or "standalone" (a non-dispatcher guard's exported pure decision function). */
  source: "registry" | "standalone";
  expects: CanaryExpectation;
  /** Undefined when the guard has no declared canary yet (reported separately from pass/fail). */
  passed: boolean | undefined;
  /** Populated when the guard module threw, or when resolving/invoking it failed. */
  error?: string;
}

/** Build a minimal synthetic DispatchContext for a canary invocation. */
function buildCanaryContext(
  event: GuardRegistration["event"],
  transcriptLines: DispatchContext["transcriptLines"]
): DispatchContext {
  return {
    event,
    hostCapSec: DEFAULT_HOST_CAP_SEC,
    budgets: deriveBudgets(DEFAULT_HOST_CAP_SEC),
    transcriptCandidates: [],
    transcriptLines: transcriptLines ?? [],
  };
}

/** Minimal base ClaudeHookInput every canary's declared `input` fragment is merged onto. */
function baseCanaryInput(event: GuardRegistration["event"]): ToolHookInput {
  return {
    session_id: "mt2889-canary-session",
    cwd: process.cwd(),
    hook_event_name: event,
    tool_name: "",
    tool_input: {},
  };
}

/**
 * Run ONE `GUARD_REGISTRY` entry's declared canary through the REAL guard
 * module's exported `run()` — dynamically imported via the SAME `reg.module()`
 * loader the dispatcher itself uses, so a canary failure reflects the exact
 * production entry point, not a hand-copied stand-in.
 *
 * `moduleLoader` is injectable (defaults to `reg.module`) so tests can
 * substitute a SABOTAGED module (a synthetic "test copy" whose `run()`
 * always returns null/allow) without touching any real guard file on disk —
 * this is the seam `canary-runner.test.ts`'s sabotage-detection test uses.
 */
export async function runGuardCanary(
  reg: GuardRegistration,
  moduleLoader?: () => Promise<GuardModule>
): Promise<CanaryResult> {
  if (!reg.canary) {
    return { guardName: reg.name, source: "registry", expects: "deny", passed: undefined };
  }
  const { canary } = reg;
  try {
    const mod = await (moduleLoader ?? reg.module)();
    const ctx = buildCanaryContext(reg.event, canary.transcriptLines);
    let inputPatch: Record<string, unknown> = {};
    if (canary.setup) {
      inputPatch = (await canary.setup(mod, ctx)) ?? {};
    }
    const input: ToolHookInput = {
      ...baseCanaryInput(reg.event),
      ...canary.input,
      ...inputPatch,
    } as ToolHookInput;
    const outcome = await mod.run(input, ctx);
    return {
      guardName: reg.name,
      source: "registry",
      expects: canary.expects,
      passed: evaluateCanaryOutcome(outcome, canary.expects),
    };
  } catch (err) {
    return {
      guardName: reg.name,
      source: "registry",
      expects: canary.expects,
      passed: false,
      error: err instanceof Error ? err.message : String(err),
    };
  }
}

     * Optional pre-invocation priming hook for STATEFUL guards whose real
     * outcome depends on a prior invocation (e.g. `skill-staleness-detector`
     * only warns on its SECOND call for a given session — the first
     * establishes a baseline). Receives the SAME dynamically-imported guard
     * module and synthetic `DispatchContext` the real canary check will use,
     * so it can call `mod.run()` itself as many times as needed to prime
     * state before the canary runner's own (checked) invocation. May
     * optionally RETURN a partial input patch (e.g. a dynamically-generated
     * temp `cwd`/`session_id` the checked invocation must reuse) — merged
     * onto `canary.input` after `setup` completes, so the checked call sees
     * whatever state `setup` just primed. Most guards don't need this — omit
     * for anything whose outcome is determined by a single `run()` call.
     */
    setup?: (
      mod: GuardModule,
      ctx: DispatchContext
    ) => Record<string, unknown> | void | Promise<Record<string, unknown> | void>;
  };
}

