/**
 * Log per-target compile diagnostics (size report, staleness, and mt#2802
 * size-budget status) for a single target's `CompileRulesResult`. Extracted
 * from the original single-target inline logic so the bare-invocation
 * multi-target loop (mt#2803) can call it once per probed target. Returns a
 * short failure descriptor when --check mode failed for this target (stale
 * or size-budget exceeded) so callers can aggregate failures across ALL
 * probed targets instead of throwing on the first one found. Returns
 * undefined when the target passed (or when not in --check mode).
 */
function reportSingleTargetCompile(target: string, result: CompileRulesResult): string | undefined {
  // Report output size on every compile (mt#2802 success criterion #1).
  if (result.sizeChars !== undefined) {
    log.cli(`[rules compile] Target "${target}" output size: ${result.sizeChars} chars`);
  }

  // --check mode: report + fail when output is stale so CI/hooks can detect it.
  if (result.check && result.stale) {
    const staleFile = result.staleFile || "(unknown file)";
    log.cli(`[rules compile --check] Target "${target}" is STALE`);
    log.cli(`  Stale file: ${staleFile}`);
    log.cli(`  Run "minsky rules compile --target ${target}" to regenerate.`);
    return `target "${target}" is stale (${staleFile})`;
  }

  // --check mode: report + fail when output exceeds its fail threshold (mt#2802).
  // Only reachable when NOT stale — a stale target is fixed by regenerating first,
  // at which point the next --check run evaluates the budget against fresh content.
  if (result.check && result.sizeBudgetStatus === "fail" && result.sizeBudget) {
    log.cli(`[rules compile --check] Target "${target}" EXCEEDS SIZE BUDGET`);
    log.cli(
      `  Size: ${result.sizeChars} chars (fail threshold: ${result.sizeBudget.failChars} chars)`
    );
    log.cli(`  Top contributing rules:`);
    for (const line of formatTopContributors(result.topContributors ?? [])) {
      log.cli(`    ${line}`);
    }
    if (result.ruleContentChars !== undefined) {
      log.cli(
        `  (rule content: ${result.ruleContentChars} of ${result.sizeChars} chars; ` +
          `remainder is target scaffolding — banner/headers)`
      );
    }
    log.cli(
      `  Trim the rules above, or override via target options / MINSKY_SKIP_SIZE_BUDGET=1 (pre-commit only).`
    );
    return (
      `target "${target}" exceeds size budget ` +
      `(${result.sizeChars} > ${result.sizeBudget.failChars} chars)`
    );
  }

  // --check mode: report + fail when any alwaysApply:true rule's OWN compiled
  // contribution exceeds the per-rule ceiling (mt#2874 — makes mt#1877's per-rule
  // 15KB budget mechanical). Independent of the aggregate budget check above — a
  // target can pass the aggregate budget while still having one oversized always-on
  // rule. Only reachable when the aggregate check above did not already fail (same
  // "fix the bigger problem first" precedence as the stale-vs-budget check above).
  if (result.check && result.perRuleViolations && result.perRuleViolations.length > 0) {
    log.cli(`[rules compile --check] Target "${target}" HAS RULE(S) EXCEEDING PER-RULE CEILING`);
    for (const violation of result.perRuleViolations) {
      log.cli(`  Rule "${violation.id}": ${violation.size} chars`);
    }
    log.cli(
      `  Trim the rule(s) above, or override via MINSKY_SKIP_SIZE_BUDGET=1 (pre-commit only).`
    );
    const violationsList = result.perRuleViolations.map((v) => `${v.id} (${v.size} chars)`);
    return `target "${target}" has rule(s) exceeding the per-rule ceiling: ${violationsList.join(", ")}`;
  }

  // Non-check compiles never fail on budget — warn loudly instead (mt#2802 criterion #6),
  // for either threshold crossed (warn or fail) since only --check hard-fails.
  if (
    !result.check &&
    (result.sizeBudgetStatus === "warn" || result.sizeBudgetStatus === "fail") &&
    result.sizeBudget
  ) {
    const thresholdChars =
      result.sizeBudgetStatus === "fail"
        ? result.sizeBudget.failChars
        : result.sizeBudget.warnChars;
    log.cli(
      `[rules compile] WARNING: target "${target}" output (${result.sizeChars} chars) ` +
        `exceeds its ${result.sizeBudgetStatus} threshold (${thresholdChars} chars).`
    );
    log.cli(`  Top contributing rules:`);
    for (const line of formatTopContributors(result.topContributors ?? [])) {
      log.cli(`    ${line}`);
    }
    if (result.ruleContentChars !== undefined) {
      log.cli(
        `  (rule content: ${result.ruleContentChars} of ${result.sizeChars} chars; ` +
          `remainder is target scaffolding — banner/headers)`
      );
    }
  }

  return undefined;
}

export function registerCompileMigrateCommands(targetRegistry: {
  registerCommand: <T extends CommandParameterMap>(cmd: CommandDefinition<T>) => void;
}): void {
  targetRegistry.registerCommand({
    id: "rules.compile",
    category: CommandCategory.RULES,
    name: "compile",
    description: "Compile rules into a monolithic file (e.g., AGENTS.md or CLAUDE.md)",
    parameters: rulesCompileCommandParams,
    execute: async (params, _ctx?: CommandExecutionContext) => {
      log.debug("Executing rules.compile command", { params });
      try {
        const workspacePath = await resolveWorkspacePath({});

        // Read memory.loadingMode from config; fall back gracefully if config unavailable
        let memoryLoadingMode: MemoryLoadingMode | undefined;
        try {
          const { getConfigurationProvider } = await import("@minsky/domain/configuration/index");
          const config = getConfigurationProvider().getConfig();
          memoryLoadingMode = config.memory?.loadingMode;
        } catch {
          // Config not yet initialized or unavailable — use target default (on_demand)
        }

        // mt#2802: build the override with ONLY the fields actually supplied —
        // never `{ warnChars: undefined, failChars: undefined }` (reviewer R1);
        // an absent field falls back to the target default in resolveSizeBudget.
        const sizeBudgetOverride: { warnChars?: number; failChars?: number } = {};
        if (params.warnChars !== undefined) sizeBudgetOverride.warnChars = params.warnChars;
        if (params.failChars !== undefined) sizeBudgetOverride.failChars = params.failChars;

/**
 * Bulk task-edit primitives (mt#2819).
 *
 * Pure change-set computation plus a deterministic dry-run token for the
 * `tasks.bulk-edit` command. The token binds the exact approved change set:
 * the execute path recomputes per-record state and refuses on drift, so a
 * diverged change set structurally invalidates the approval (the mt#2785
 * dry-run scope-match rule, enforced in code rather than discipline).
 *
 * Token contract note (shared with mt#2823): the token is a deterministic
 * sha256 over the canonical change set — no nonce. Durability comes from the
 * append-only `task.bulk_edit.dry_run` audit event that carries the change
 * set; one-shot consumption is the presence of a matching
 * `task.bulk_edit.executed` event.
 */

import { createHash } from "crypto";

/** Edit operations bulk mode supports (v1): kind reclassification + tag add/remove. */
export interface BulkEditOps {
  kind?: string;
  addTag?: string;
  removeTag?: string;
}

/** Minimal task state the change-set computation reads. */
export interface BulkEditTaskState {
  id: string;
  kind?: string | null;
  tags?: string[] | null;
}

/**
 * One record of the change set: a single field transition on a single task.
 * `before`/`after` are the kind string for `field: "kind"` and the full tags
 * array for `field: "tags"`.
 */
export interface BulkChangeRecord {
  taskId: string;
  field: "kind" | "tags";
  before: string | string[];
  after: string | string[];
}

/** Per-record verdict when re-checking a change record against current state. */
export type DriftVerdict = "pending" | "applied" | "drift";

/**
 * Tasks with no stored kind are treated as the system default so that a bulk
 * `kind: "implementation"` op is a no-op for them rather than a phantom change.
 */
const DEFAULT_KIND = "implementation";

/** Canonical string form of a record value, for hashing and drift comparison. */
export function canonicalValue(value: string | string[]): string {
  return typeof value === "string" ? value : JSON.stringify(value);
}

/**
 * Compute the change set for applying `ops` to `tasks`. Records are emitted
 * only for actual transitions (before differs from after) and are sorted by
 * (taskId, field) so the set — and therefore the token — is order-independent
 * of the caller's id list.
 */
export function computeChangeSet(tasks: BulkEditTaskState[], ops: BulkEditOps): BulkChangeRecord[] {
  const records: BulkChangeRecord[] = [];

  for (const task of tasks) {
    if (ops.kind !== undefined) {
      const before = task.kind ?? DEFAULT_KIND;
      if (before !== ops.kind) {
        records.push({ taskId: task.id, field: "kind", before, after: ops.kind });
      }
    }

    if (ops.addTag !== undefined || ops.removeTag !== undefined) {
      const before = task.tags ?? [];
      let after = [...before];
      if (ops.addTag !== undefined && !after.includes(ops.addTag)) {
        after.push(ops.addTag);
      }
      if (ops.removeTag !== undefined) {
        after = after.filter((t) => t !== ops.removeTag);
      }
      if (canonicalValue(before) !== canonicalValue(after)) {
        records.push({ taskId: task.id, field: "tags", before, after });
      }
    }
  }

  records.sort((a, b) =>
    a.taskId === b.taskId ? a.field.localeCompare(b.field) : a.taskId.localeCompare(b.taskId)
  );
  return records;
}

/**
 * Deterministic token over the canonical change set. Key order is fixed
 * explicitly (not object-literal order) so the hash is stable across
 * serializers.
 */
export function computeDryRunToken(changeSet: BulkChangeRecord[]): string {
  const canonical = changeSet.map((r) =>
    JSON.stringify([r.taskId, r.field, canonicalValue(r.before), canonicalValue(r.after)])
  );
  return createHash("sha256").update(canonical.join("\n")).digest("hex");
}

/**
 * Re-check one approved change record against the task's CURRENT state:
 *   - current == before → "pending"  (safe to apply)
 *   - current == after  → "applied"  (already in desired state; skip)
 *   - anything else     → "drift"    (state changed since dry-run; abort)
 */
export function checkRecordDrift(
  record: BulkChangeRecord,
  current: BulkEditTaskState
): DriftVerdict {
  const currentValue: string | string[] =
    record.field === "kind" ? (current.kind ?? DEFAULT_KIND) : (current.tags ?? []);
  const canonical = canonicalValue(currentValue);
  if (canonical === canonicalValue(record.before)) return "pending";
  if (canonical === canonicalValue(record.after)) return "applied";
  return "drift";
}

