/**
 * List system events with optional filters.
 *
 * Results are ordered by `created_at` DESC (most recent first).
 * Default limit is 50; maximum is 500.
 */
export async function listEvents(
  db: PostgresJsDatabase,
  options: ListEventsOptions = {}
): Promise<SystemEvent[]> {
  const limit = Math.min(options.limit ?? 50, 500);
  const conditions = buildConditions(options);

  const query = db
    .select()
    .from(systemEventsTable)
    .orderBy(desc(systemEventsTable.createdAt))
    .limit(limit);

  const rows =
    conditions.length > 0
      ? await query.where(conditions.length === 1 ? conditions[0] : and(...conditions))
      : await query;

  return rows.map(toSystemEvent);
}

/**
 * Count system events matching the same filters as `listEvents` (mt#2817),
 * WITHOUT the limit — used to compute loud-cap truncation metadata
 * (`{returned, total, truncated}`). Deliberately shares `buildConditions`
 * with `listEvents` so the two queries can never drift apart on filter
 * semantics.
 */
export async function countEvents(
  db: PostgresJsDatabase,
  options: Omit<ListEventsOptions, "limit"> = {}
): Promise<number> {
  const conditions = buildConditions(options);

  const query = db.select({ value: count() }).from(systemEventsTable);

  const rows =
    conditions.length > 0
      ? await query.where(conditions.length === 1 ? conditions[0] : and(...conditions))
      : await query;

  return rows[0]?.value ?? 0;
}

/**
 * Find the most recent event of `eventType` whose payload carries the given
 * dry-run token (`payload->>'token'`, mt#2819). Used by `tasks.bulk-edit`'s
 * execute path to load the approved change set (dry_run event) and to detect
 * prior execution (executed event — the one-shot consumption marker).
 */
export async function findEventByToken(
  db: PostgresJsDatabase,
  eventType: SystemEventType,
  token: string
): Promise<SystemEvent | null> {
  const rows = await db
    .select()
    .from(systemEventsTable)
    .where(
      and(
        eq(systemEventsTable.eventType, eventType),
        sql`${systemEventsTable.payload}->>'token' = ${token}`
      )
    )
    .orderBy(desc(systemEventsTable.createdAt))
    .limit(1);

  const row = rows[0];
  return row ? toSystemEvent(row) : null;
}

