 *
 * Renders the open entity tabs (IDE model: entities only, never list pages).
 * Hidden entirely while the working set is empty so the default landing stays
 * clean. Overflow: horizontal scroll (craft decision recorded in the spec). The
 * scroll container hides its scrollbar chrome via `.scrollbar-none` and pins
 * overflow-y hidden, so no scrollbar (horizontal or vertical) renders inside
 * the fixed h-9 strip at any zoom level — with overflow-x auto, the y-axis
 * would otherwise compute to auto and flash a vertical bar at extreme
 * zoom/DPI.
 *
 * Semantics: these are URL-driven LINKS, not ARIA tabs — each "tab" navigates
 * to its entity route, so the honest pattern is a <nav> of links with
 * `aria-current` on the active one. We deliberately do NOT use
 * role="tablist"/"tab": those roles promise a roving-tabindex + arrow-key
 * keyboard contract that link navigation doesn't have (reviewer R1 finding).
 * Links and the close buttons are natively focusable and keyboard-operable.
 */
import { Link } from "react-router-dom";
import {
  X,
  Network,
  Bot,
  GitBranch,
  CircleHelp,
  Brain,
  GitPullRequest,
  AlertCircle,
} from "lucide-react";
import { useTabs, type EntityTab, type EntityTabKind } from "../lib/tabs";
import { useEntityLabel } from "../lib/entity-labels";
import { cn } from "../lib/utils";

const KIND_ICONS: Record<EntityTabKind, React.ComponentType<{ className?: string }>> = {
  task: Network,
  session: Bot,
  agent: GitBranch,
  ask: CircleHelp,
  memory: Brain,
  changeset: GitPullRequest,
};

const FALLBACK_ICON: React.ComponentType<{ className?: string }> = Bot;

/**
 * Resolve a tab kind to its icon, degrading to a generic icon for any kind
 * missing from KIND_ICONS. `loadTabs()` filters kinds it doesn't recognize,
 * so the realistic gap this guards is a kind ACCEPTED by the loader but
 * missing from this map — exactly how mt#2440 happened: mt#1919 added
 * "agent" to the loader's accept-list without a map entry, the undefined
 * component threw React #130, and (TabBar rendering outside the page
 * ErrorBoundaries) the whole shell blanked on every load while the tab was
 * persisted in localStorage.
 */
export function resolveKindIcon(kind: EntityTabKind): React.ComponentType<{ className?: string }> {
  return KIND_ICONS[kind] ?? FALLBACK_ICON;
}

/**
 * Derived tab label (mt#2883): resolves the tab's human-legible name via the
 * shared entity-label resolver, degrading to the persisted shortened-id label
 * while data loads. Enriched titles render in the UI sans face; the id
 * fallback keeps its monospace treatment (it IS an identifier). Split out as
 * a child component so the resolver hook runs per tab.
 */
function TabLabel({ tab }: { tab: EntityTab }) {
  const { primary, enriched } = useEntityLabel(tab);
  return (
    <span
      className={cn(
        "max-w-[220px] truncate text-xs",
        enriched ? "font-sans" : "font-mono",
        tab.error && "text-destructive"
      )}
      title={primary}
    >
      {primary}
    </span>
  );
}

export function TabBar() {
  const { tabs, activePath, closeTab } = useTabs();

  if (tabs.length === 0) return null;

  return (
    <nav
      aria-label="Open entities"
      className="flex h-9 flex-shrink-0 items-stretch gap-0.5 overflow-x-auto overflow-y-hidden scrollbar-none border-b border-border bg-background px-1"
    >
      {tabs.map((tab) => {
        const active = tab.path === activePath;
        const Icon = resolveKindIcon(tab.kind);
        return (
          <div
            key={tab.path}
            className={cn(
              "group flex items-center gap-1.5 rounded-t-md border-b-2 px-2.5 text-sm transition-colors",
              active
                ? "border-primary bg-muted font-medium text-foreground"
                : "border-transparent text-muted-foreground hover:bg-muted/40 hover:text-foreground"
            )}
          >
            <Link
              to={tab.path}
              className="flex min-w-0 items-center gap-1.5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-ring rounded-sm"
              aria-current={active ? "location" : undefined}
              title={tab.error ? `${tab.entityId} (not found)` : tab.entityId}
            >
              {/* Error chip (mt#2769): the tab's entity 404'd. Swaps the kind
                  icon for an alert glyph — the tab is not persisted across
                  reload (see tabs.tsx's persist effect), so this state is
                  visible only for the current visit. */}
              {tab.error ? (
                <AlertCircle
                  aria-hidden
                  className="h-3.5 w-3.5 flex-shrink-0 text-destructive"
                />
              ) : (
                <Icon
                  aria-hidden
                  className={cn("h-3.5 w-3.5 flex-shrink-0", active && "text-primary")}
                />
              )}
              <TabLabel tab={tab} />
            </Link>
            <button
              type="button"
              aria-label={`Close ${tab.entityId}`}
              onClick={() => closeTab(tab.path)}
              className={cn(
                "rounded p-0.5 transition-opacity hover:bg-muted focus-visible:opacity-100 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-ring",
                active ? "opacity-70 hover:opacity-100" : "opacity-0 group-hover:opacity-70"
              )}
            >
              <X aria-hidden className="h-3 w-3" />
            </button>
          </div>
        );
      })}
    </nav>
  );
}

/**
 * Format an ask requestor for display. Ascribed `unknown:hash:` actors render
 * as "unattributed agent", contextualized by the ask's parent task when one
 * exists (e.g. "unattributed agent · mt#2505"); declared identities pass
 * through unchanged.
 */
export function formatRequestor(requestor: string, parentTaskId?: string | null): RequestorDisplay {
  if (ASCRIBED_ACTOR_RE.test(requestor)) {
    return {
      label: parentTaskId ? `unattributed agent · ${parentTaskId}` : "unattributed agent",
      raw: requestor,
      isAscribed: true,
    };
  }
  return { label: requestor, raw: requestor, isAscribed: false };
}

/**
 * Distinguishable dropdown-option label for a requestor: ascribed actors all
 * share the "unattributed agent" display name, so filter options (which must
 * stay 1:1 with raw values) append the hash prefix for disambiguation.
 */
export function formatRequestorOption(requestor: string): string {
  if (!ASCRIBED_ACTOR_RE.test(requestor)) return requestor;
  const markerIdx = requestor.indexOf(ASCRIBED_MARKER);
  if (markerIdx >= 0) {
    const start = markerIdx + ASCRIBED_MARKER.length;
    return `unattributed (${requestor.slice(start, start + 8)})`;
  }
  // Terminal-`unknown` form (e.g. "minsky.agent:unknown") — disambiguate by
  // the issuing prefix instead of a hash.
  const prefix = requestor.replace(/:?unknown$/, "");
  return prefix ? `unattributed (${prefix})` : "unattributed";
}

// ---------------------------------------------------------------------------
// Task index — shared fetcher (also consumed by CommandPalette)
// ---------------------------------------------------------------------------

export interface TaskIndexRow {
  id: string;
  title: string;
  status: string;
}

/**
 * Query key shared with the CommandPalette's task source — one cache serves
 * both the palette rows and task tab labels. (Key string predates this
 * module; kept verbatim so existing caches stay warm.)
 */
export const TASK_INDEX_QUERY_KEY = ["command-palette-tasks"] as const;

export async function fetchTaskIndex(): Promise<TaskIndexRow[]> {
  try {
    const res = await fetch("/api/tasks");
    if (!res.ok) return [];
    const data = (await res.json()) as { tasks?: TaskIndexRow[] };
    if (!Array.isArray(data.tasks)) return [];
    return data.tasks.map((t) => ({ id: t.id, title: t.title, status: t.status }));
  } catch {
    return [];
  }
}

// ---------------------------------------------------------------------------
// Pure per-kind resolution (exported for tests)
// ---------------------------------------------------------------------------

export interface EntityLabel {
  /** Human-legible primary label. Falls back to the tab's existing label. */
  primary: string;
  /** True when `primary` is an enriched title rather than the id fallback. */
  enriched: boolean;
}

export interface LabelSources {
  tasks: TaskIndexRow[];
  /** `agents` widget rows — workspace sessionId → bound task title/id. */
  agentRows: { sessionId: string; taskId: string | null; taskTitle: string | null }[];
  /** Context-inspector conversation rows (harness agentSessionId → ladder label). */
  conversationRows: { agentSessionId: string; label: string }[];
  /** Attention cohort rows (ask id → subject). */
  askRows: { id: string; title: string }[];
  /** Memories-list rows (memory id → name). */
  memoryRows: { id: string; name: string }[];
  /** Changesets rows (PR number → title). */
  changesetRows: { number: number | null; title: string | null }[];
}

export const EMPTY_LABEL_SOURCES: LabelSources = {
  tasks: [],
  agentRows: [],
  conversationRows: [],
  askRows: [],
  memoryRows: [],
  changesetRows: [],
};

/**
 * Resolve a tab's display label from whatever sources have data. Pure —
 * `useEntityLabel` supplies live query data; tests supply fixtures.
 */
export function resolveTabLabel(
  tab: Pick<EntityTab, "kind" | "entityId" | "label">,
  sources: LabelSources
): EntityLabel {
  const fallback: EntityLabel = { primary: tab.label, enriched: false };

  switch (tab.kind) {
    case "task": {
      const row = sources.tasks.find((t) => t.id === tab.entityId);
      // Anchor + title: the mt#X anchor is load-bearing (cockpit-design
      // §entity IDs) and stays in the label for tasks.
      return row?.title ? { primary: `${tab.entityId} · ${row.title}`, enriched: true } : fallback;
    }
    case "agent": {
      const row = sources.agentRows.find((a) => a.sessionId === tab.entityId);
      if (row?.taskTitle) return { primary: row.taskTitle, enriched: true };
      if (row?.taskId) return { primary: row.taskId, enriched: true };
      return fallback;
    }
    case "session": {
      // Conversation tabs (kind "session" pending the broader tab-kind
      // rename — see tabs.tsx): the server-derived ladder label.
      const row = sources.conversationRows.find((c) => c.agentSessionId === tab.entityId);
      return row?.label ? { primary: row.label, enriched: true } : fallback;
    }
    case "ask": {
      const row = sources.askRows.find((a) => a.id === tab.entityId);
      return row?.title ? { primary: row.title, enriched: true } : fallback;
    }
    case "memory": {
      const row = sources.memoryRows.find((m) => m.id === tab.entityId);
      return row?.name ? { primary: row.name, enriched: true } : fallback;
    }
    case "changeset": {
      const n = Number(tab.entityId);
      const row = Number.isFinite(n)
        ? sources.changesetRows.find((c) => c.number === n)
        : undefined;
      return row?.title ? { primary: `#${n} · ${row.title}`, enriched: true } : fallback;
    }
    default:
      return fallback;
  }
}

