 * Attempt an inline merge of `mainRef` into the current branch when the
 * working tree is clean, so a clean-tree/no-conflict freshness block can be
 * resolved without a manual session_update round-trip. Only called from the
 * entrypoint when `checkBranchFreshness` already returned `blocked: true`.
 *
 * Never leaves a MERGE_HEAD behind: any non-zero-exit merge attempt is
 * aborted before this function returns (see header comment above for why
 * that matters).
 */
export function attemptCleanTreeAutoMerge(
  repoDir: string,
  branchRef: string | undefined,
  mainRef: string | undefined,
  aheadCount: number,
  hookStart: number,
  deps: AutoMergeDeps = DEFAULT_AUTO_MERGE_DEPS
): AutoMergeOutcome {
  if (!branchRef || !mainRef) {
    return {
      attempted: false,
      reason: "missing branchRef/mainRef — comparison did not fully run",
    };
  }

  // Budget-guard the merge attempt itself — a merge of already-fetched refs
  // is comparable in cost to any other local git probe in this file.
  if (!budgetAllows(hookStart, GIT_TIMEOUT_MS * 2)) {
    return { attempted: false, reason: "overall budget exhausted before auto-merge attempt" };
  }

  if (!deps.isWorkingTreeClean(repoDir, GIT_TIMEOUT_MS)) {
    return {
      attempted: false,
      reason: "working tree is not clean — auto-merge skipped, falling back to block",
    };
  }

  const mergeResult = deps.runMerge(repoDir, mainRef, FETCH_TIMEOUT_MS);
  if (mergeResult.exitCode === 0) {
    return { attempted: true, merged: true, mergedCommitCount: aheadCount };
  }

  // Merge failed — conflicts (the expected failure mode on a clean tree) or
  // something else entirely (e.g. a lock file race). Either way: abort
  // defensively so no MERGE_HEAD survives for the NEXT hook invocation to
  // misread as an operator-driven mid-merge (mt#1739's carve-out).

        return new Response(
          JSON.stringify({ error: "alert sink threw during send", sinkType: sinkConfig.type }),
          { status: 503, headers: { "content-type": "application/json" } }
        );
      }
      log.info("alert_test.sent", {
        event: "alert_test.sent",
        sinkType: sinkConfig.type,
      });
      return new Response(
        JSON.stringify({ ok: true, sinkType: sinkConfig.type, deliveryAttempted: true }),
        { status: 200, headers: { "content-type": "application/json" } }
      );
    }

    if (request.method === "POST" && url.pathname === "/webhook") {
      // mt#2799 Layer 1: reject new work once draining has started. Return
      // 503 (not a hard connection close) so GitHub's delivery-retry logic
      // treats this as a transient failure and redelivers — the newly
      // active deployment (up during Railway's overlap window) picks it up.
      if (draining) {
        log.info("webhook_rejected_draining", { event: "webhook_rejected_draining" });
        return new Response("service draining", { status: 503 });
      }

      const signature = request.headers.get("x-hub-signature-256");
      // R2 BLOCKING fix: previously fell back to the literal "unknown".
      // Combined with DO NOTHING upsert semantics, that collapsed every
      // missing-header POST into a single row — silently dropping events
      // after the first. Synthesize a UUID per request instead. The
      // "synthetic-" prefix is queryable so operators can distinguish
      // GitHub-supplied IDs from server-synthesized ones.
      const deliveryId =
        request.headers.get("x-github-delivery") ?? `synthetic-${crypto.randomUUID()}`;
      const eventName = request.headers.get("x-github-event");

      // Read body BEFORE the missing-headers check so we can include `action`
      // in the webhook_received log. Body reads are cheap for legitimate
      // payloads; malicious-volume attacks are handled downstream by signature
      // verification rejecting invalid payloads.
      const body = await request.text();

      // Best-effort extract `action` from the JSON body for observability.
      // If the body is not valid JSON or has no `action` field, we emit null.
      let parsedBody: Record<string, unknown> | null = null;
      let action: string | null = null;
      try {
        parsedBody = JSON.parse(body) as Record<string, unknown>;
        if (typeof parsedBody["action"] === "string") {
          action = parsedBody["action"];
        }
      } catch {
        // Non-JSON or malformed body — action stays null, parsedBody stays null.
      }

      // Log webhook_received BEFORE the missing-headers check so that requests
      // with absent headers (signature_present: false) still produce a log line.
      // This is the primary diagnostic signal for bad-actor or misconfigured senders.
      log.info("webhook_received", {
        event: "webhook_received",
        delivery_id: deliveryId,
        github_event: eventName ?? null,
        action,
        signature_present: Boolean(signature),
      });

      // Persist webhook receipt for forensic investigation (mt#1372) AND,
      // as of mt#2799, as the durable row boot-time recovery reads to
      // resume a review interrupted by a redeploy. AWAITED (not
      // fire-and-forget) so the row is guaranteed to exist BEFORE the 200
      // ACK returns below (mt#2799 SC#3) — a process killed in the window
      // between "GitHub got its 200" and "the async insert lands" would
      // otherwise lose the row boot recovery depends on.
      // recordWebhookReceipt swallows its own errors internally (never
      // throws), so awaiting it cannot turn a persistence failure into a
      // webhook-handling failure.
      //
      // R1 BLOCKING #3 fix: persist EVERY webhook the reviewer receives,
      // not just those with x-github-event header. Webhooks with missing
      // or malformed headers are exactly the cases most worth investigating
      // (misconfigured senders, GitHub API changes, malicious probes).
      // Use "unknown" sentinel when eventName is null.
      if (db !== undefined) {
        await recordWebhookReceipt(
          db,
          deliveryId,
          eventName ?? "unknown",
          extractPersistedHeaders((name) => request.headers.get(name)),
          parsedBody ?? { raw: safeTruncate(body, 1000, "head") }
        );
      }

      if (!signature || !eventName) {
        return new Response("missing signature or event headers", { status: 400 });
      }

      try {
        // verifyAndReceive validates the signature and dispatches to the
        // registered webhook handlers. The handlers call startDetachedReview
        // which returns immediately (fire-and-forget). So this await only
        // blocks for signature verification + event dispatch, not the review.
        await webhooks.verifyAndReceive({
          id: deliveryId,
          name: eventName,
          payload: body,
          signature,
        });
        return new Response("ok", { status: 200 });
      } catch (error) {
        // verifyAndReceive throws on signature-verification failure.
        // Handler errors no longer propagate here since reviews are detached.
        const message = error instanceof Error ? error.message : String(error);
        const isSignatureError = /signature/i.test(message);
        log.error(isSignatureError ? "webhook_signature_invalid" : "webhook_dispatch_error", {
          event: isSignatureError ? "webhook_signature_invalid" : "webhook_dispatch_error",
          delivery_id: deliveryId,
          deliveryId, // deprecated: kept for log-consumer backward compatibility; remove after consumers migrate to delivery_id
          github_event: eventName,
          eventName, // deprecated: kept for log-consumer backward compatibility; remove after consumers migrate to github_event
          error: message,
        });

        // Persist failure outcome and surface as operator-visible alert (mt#1372).
        // Signature failures are expected from misconfigured senders — only non-signature
        // errors (dispatch failures) surface as webhook_processing_failed alerts.
        if (db !== undefined) {
          void updateOutcome(
            db,
            deliveryId,
            isSignatureError ? "failed_at_signature" : "failed_at_tier_resolve",
            { message, stage: isSignatureError ? "signature" : "dispatch" }
          );
        }
        if (!isSignatureError) {
          // Dispatch errors are unexpected — alert the operator (Railway logs).
          log.error("webhook_processing_failed", {
            event: "webhook_processing_failed",
            delivery_id: deliveryId,
            github_event: eventName,
            stage: "dispatch",
            error: message,
          });
        }

        return new Response(isSignatureError ? "invalid signature" : "internal error", {
          status: isSignatureError ? 401 : 500,
        });
      }
    }

    return new Response("not found", { status: 404 });
  },
});

/**
 * Graceful shutdown for this server instance (mt#2799 Layer 1 drain).
 *
 * 1. Sets `draining = true` (synchronously, before any await) so the
 *    /webhook route starts rejecting new work with 503 immediately.
 * 2. Logs drain start with current inflight count.
 * 3. Waits for all in-flight reviews to settle, bounded by

 *
 * ## Coordination with the mt#1907 in-flight marker (no new dedup)
 *
 * `runReview` (review-worker.ts) already acquires the `reviewer_inflight_reviews`
 * marker for (owner, repo, prNumber, headSha) BEFORE doing any real work, and
 * returns `{ status: "skipped", reason: "concurrent_inflight" }` when another
 * process already holds it. During Railway's overlap window the OLD process
 * may still be genuinely mid-review when the NEW process boots and runs this
 * recovery pass — in that case runReview's existing marker check is what
 * prevents a duplicate review, and this module does NOT touch the
 * `reviewer_webhook_events` row's outcome in that specific case (the row
 * belongs to whichever process actually finishes the review; overwriting it
 * here would just get clobbered by that process's own `updateOutcome` call
 * moments later, but skipping it entirely is cleaner and avoids the
 * transient-inconsistent-state window). Per the bridge memory's explicit
 * instruction: "existing inflight-marker check is sufficient... do NOT build
 * new dedup" — this module adds none.
 *
 * ## Scope
 *
 * Recovery covers `pull_request` webhook events only (opened / synchronize /
 * reopened — the events `handlePullRequestEvent` in server.ts dispatches to
 * `startDetachedReview`). `issue_comment` (/review, /resolve) command
 * recovery is out of scope for mt#2799 (see its spec's Scope section) —
 * those commands are operator-triggered and re-issuing them is cheap; the
 * durability gap this task closes is specifically "a GitHub-delivered PR
 * event's review vanishes on redeploy," which is the primary/automatic path.
 */

