const CALIBRATION_LOG = ".minsky/causal-premise-calibration.jsonl";

// ---------------------------------------------------------------------------
// Causal phrase patterns — retrodictive
// ---------------------------------------------------------------------------

/**
 * Retrodictive causal patterns: "X happened because Y", "the reason is Y",
 * "X blocks/causes Y because of Z", etc.
 *
 * These cover volunteered explanations of WHY something happened — the
 * agent is asserting a causal mechanism for past behavior.
 */
export const RETRODICTIVE_PATTERNS: RegExp[] = [
  /\bbecause\s+of\s+(the\s+)?(identity|permission|config(?:uration)?|algorithm|data[- ]shape|ownership|token|role|flag|schema|scope|encoding|mechanism)\b/i,
  /\bthe\s+reason\s+(is|was|it\s+(?:is|was))\b/i,
  /\b(block(?:ed|s)?|prevent(?:ed|s)?|cause[sd]?|fail(?:ed|s)?)\s+because\b/i,
  /\b(due\s+to|owing\s+to)\s+(the\s+)?(identity|permission|config(?:uration)?|algorithm|ownership|token|role|flag|schema|scope|mechanism|policy|encoding)\b/i,
  /\bshares?\s+(the\s+)?(same|author[''']?s?|bot[''']?s?)\s+(identity|token|app|account)\b/i,
  /\b(it[''']?s?|this)\s+(happens?|fails?|blocks?|breaks?|errors?)\s+because\b/i,
  /\bthe\s+(cause|culprit|issue|problem|reason|root\s+cause)\s+(is|was)\b/i,
  /\b(explain|explains?)\s+why\s+(it|the|this)\b/i,
  /\b(mangled|corrupted|truncated|dropped|lost)\s+(by|due\s+to|because)\b/i,
  /\bgot\s+mangled\b/i,
  /\bthe\s+(filter|query|api|request|call)\s+(is\s+)?(ignoring|dropping|mangling|silently)\b/i,
];

// ---------------------------------------------------------------------------
// Causal phrase patterns — forward predictive
// ---------------------------------------------------------------------------

/**
 * Forward predictive causal patterns: "running X will do Y", "X is unsafe
 * because Z", "X would cause Y".
 *
 * These cover the R5 class: the agent predicts future tool behavior based
 * on an unverified mechanism model.
 */
export const FORWARD_PATTERNS: RegExp[] = [
  /\b(running|executing|calling|applying)\s+\S+\s+will\s+(cause|trigger|result\s+in|break|fail|crash|error)\b/i,
  /\bis\s+(unsafe|dangerous|risky)\s+because\b/i,
  /\bwould\s+(cause|trigger|break|fail|crash)\s+(if|when|because|since)\b/i,
  /\b(migrate|apply|run|execute)\s+is\s+(unsafe|dangerous)\b/i,
  /\bwill\s+(no[- ]?op|throw|abort|reject|block)\s+(then|before|and)\b/i,
];

// ---------------------------------------------------------------------------
// Causal phrase patterns — inductive / correlational A/B generalization
// ---------------------------------------------------------------------------

/**
 * Inductive/correlational patterns (mt#2832, R12 gap): a causal conclusion
 * drawn from a small, un-isolated A/B comparison — "N in a row while Y",
 * "the one remaining/only difference is Y" — rather than an explicit
 * "because"/"due to" mechanism phrase. This is the exact shape of the
 * mt#2765 misdiagnosis (memory b0b294ab R12): "tray-spawned hangs three
 * times in a row, shell-spawned works — the one remaining structural
 * difference is the working directory" attributed causation to spawn
 * context when the real confound (which port had live traffic) was never
 * isolated.
 */
export const INDUCTIVE_GENERALIZATION_PATTERNS: RegExp[] = [
  /\bthe\s+(one\s+)?(remaining|only)\s+(structural\s+)?difference\b/i,
  /\b(in\s+a\s+row)\b[^.]{0,100}\bwhile\b/i,
  /\bevery\s+time\b[^.]{0,100}\b(but|while|whereas)\b/i,
];

// ---------------------------------------------------------------------------
// Mechanism indicator patterns (Y must invoke a structural mechanism)
// ---------------------------------------------------------------------------

/**
 * These patterns match the "Y" in "X blocked because Y" — the mechanism
 * part of the claim. The detector only fires when a causal phrase matches
 * AND the same turn references a structural mechanism.
 *
 * We use presence in the SAME PARAGRAPH (≤500 chars proximity) for scope.
 */
export const MECHANISM_PATTERNS: RegExp[] = [
  /\b(identit|owner|permission|authori[sz]|token|role|scope|policy)\b/i,
  /\b(config(?:uration)?|setting|flag|env\s*var|variable|schema|data[- ]shape|algorithm|encoding)\b/i,
  /\b(App\s+id|installation|bot\s+id|agent\s+id|user\s+id|service\s+account)\b/i,
  /\b(high[- ]?water[- ]?mark|ledger|journal|timestamp|migration)\b/i,
  /\b(cach[ei]|memoriz|remember|stored|retained|inherit)\b/i,
  // mt#2832 R12 gap: process/spawn-context mechanism vocabulary — narrow
  // compound terms only (not bare "spawn"/"environment", which are too
  // common in this codebase's discourse and would broaden the mechanism
  // gate for every OTHER causal-phrase category, not just this one).
  /\b(spawn\s+context|working\s+director(?:y|ies)|process\s+environment)\b/i,
];

// ---------------------------------------------------------------------------
// Verification presence patterns
// ---------------------------------------------------------------------------

/**
 * Patterns that, when present in the assistant turn, indicate the claim
 * has same-turn backing — tool result, file:line citation, or node_modules
 * reference.
 */
export const VERIFICATION_CITATION_PATTERNS: RegExp[] = [
  // file:line citation (e.g., "compose-review.ts:159-174")
  /\b\w[\w./\\-]+\.\w{1,10}:\d+\b/,
  // node_modules reference
  /node_modules\//,
  // explicit "verified by reading" / "confirmed by" phrasing
  /\bverified\s+by\s+(reading|checking|inspecting|running|calling|looking)\b/i,
  /\bconfirmed\s+by\s+(reading|checking|inspecting|running|calling)\b/i,
  /\bas\s+(shown|confirmed|verified)\s+(by|in)\s+(the\s+)?(tool|output|result)\b/i,
];

/**
 * Tool names that, when present in the same turn's tool_use calls, indicate
 * the agent backed its claim with an actual tool invocation (not just assertion).
 *
 * Any tool call is a potential backing — but we specifically recognize these
 * as strong backing signals since they involve reading real system state.
 */
export const BACKING_TOOL_PREFIXES: string[] = [
  "mcp__github__",
  "mcp__minsky__",
  "Read",
  "Grep",
  "Glob",
  "Bash",
  "mcp__",
];

// ---------------------------------------------------------------------------
// Detection result type
// ---------------------------------------------------------------------------

export interface CausalDetectionResult {
  matched: boolean;
  matchedPhrases: string[];
  hadSameTurnVerification: boolean;
}

// ---------------------------------------------------------------------------
// Core detector function (pure, exported for testing)
// ---------------------------------------------------------------------------

/**
 * Detect volunteered causal/mechanism claims without same-turn verification.
 *
 * @param assistantText - full concatenated text from the prior assistant turn
 * @param toolUseNames - list of tool_use names in the same turn
 * @returns detection result with matched phrases and verification flag
 */
export function detectCausalPremise(
  assistantText: string,
  toolUseNames: string[]
): CausalDetectionResult {
  if (!assistantText) {
    return { matched: false, matchedPhrases: [], hadSameTurnVerification: false };
  }

  // Apply markdown-aware filtering FIRST so all checks run on the same elided text.
  // This prevents a file:line citation inside a code block from acting as "backing"

  checked: boolean;
  /** Whether a dependency-manifest file (bun.lock or any package.json) changed in the range. */
  changed: boolean;
  /** Whether `bun install` (root) completed successfully. */
  installed: boolean;
  /** Present when the root install was attempted and failed. */
  installError?: string;
  /** Present when one or more nested-package installs failed after a successful root install. */
  nestedFailedPaths?: string[];
}

/** True for `bun.lock` (root lockfile) or any `package.json` at any depth. */
function isDependencyManifestPath(path: string): boolean {
  return path === "bun.lock" || /(^|\/)package\.json$/.test(path);
}

/**
 * Detect whether the commit range from `preUpdateSha` to the session's
 * current HEAD changed a dependency-lockfile-affecting file (`bun.lock` or
 * any `package.json`) and, if so, refresh `node_modules` via
 * `installDependencies` / `installNestedDependencies` — the SAME mechanism
 * `session_start` already runs (unattended) after a fresh clone (mt#1379).
 *
 * ## mt#2821 finding: why auto-run, not a blocking notice
 *
 * Observed failure: 3 parallel sessions failed identically post-rebase with
 * `Cannot find module '@minsky/shared/logger'` until a manual `bun install`
 * (conversation c01f89af) — a merge/rebase that pulls in a lockfile or
 * package.json change leaves `node_modules` stale relative to the new
 * dependency graph, and nothing surfaced that until the next command failed
 * with a misleading module-resolution error.
 *
 * This function auto-runs the install rather than only emitting a notice,
 * because the mutation is entirely local to the SESSION's own
 * `node_modules` — not shared or production state — so the `--execute`
 * dry-run-first discipline (`operational-safety-dry-run-first.mdc`) does
 * not apply here: there is nothing to preview, and the operation is
 * idempotent and side-effect-free outside the workspace. It is exactly the
 * install `session_start` already performs unattended; running it again
 * after `session_update` closes the same gap for the update path.
 *
 * If the install itself fails (network, disk, a broken postinstall
 * script), this function does NOT throw — it returns the failure in the
 * result so the caller can emit an explicit, actionable notice instead.
 * That notice is the "blocking, actionable notice" half of the task's
 * either/or: reserved for when auto-install could not complete, not used
 * as a substitute for attempting it.
 */
export async function refreshDependenciesIfLockfileChanged(
  workdir: string,
  gitService: GitServiceInterface,
  preUpdateSha: string | undefined,
  installDeps: DependencyInstallDeps = defaultDependencyInstallDeps
): Promise<DependencyRefreshResult> {
  if (!preUpdateSha) {
    return { checked: false, changed: false, installed: false };
  }

  let postUpdateSha: string;
  try {
    postUpdateSha = (await gitService.execInRepository(workdir, "git rev-parse HEAD")).trim();
  } catch (error) {
    log.debug("Failed to resolve post-update HEAD for dependency-refresh check", {
      error: getErrorMessage(error),
      workdir,
    });
    return { checked: false, changed: false, installed: false };
  }

  if (!postUpdateSha || postUpdateSha === preUpdateSha) {
    return { checked: true, changed: false, installed: false };
  }

  let changedFiles: string[];
  try {
    const diffOutput = await gitService.execInRepository(
      workdir,
      `git diff --name-only ${preUpdateSha} ${postUpdateSha}`
    );
    changedFiles = diffOutput.trim().split("\n").filter(Boolean);
  } catch (error) {
    log.debug("Failed to diff pulled range for dependency-refresh check", {
      error: getErrorMessage(error),
      workdir,
      preUpdateSha,
      postUpdateSha,
    });
    return { checked: true, changed: false, installed: false };
  }

  if (!changedFiles.some(isDependencyManifestPath)) {
    return { checked: true, changed: false, installed: false };
  }

  log.cli(
    "📦 Dependency lockfile/manifest changed in the pulled range — running `bun install` " +
      "to keep node_modules in sync..."
  );

  const { success, error } = await installDeps.installDependencies(workdir, { quiet: false });
  if (!success) {
    log.cli(
      "⚠️  `bun install` failed after a dependency-lockfile change was pulled in. " +
        "node_modules may be stale — module resolution can fail on the next session_exec " +
        `call. Run \`bun install\` manually in the session workspace before continuing.\n` +
        `   Error: ${error}`
    );
    return { checked: true, changed: true, installed: false, installError: error };
  }

  log.cli("✅ Dependencies refreshed (`bun install` completed).");

  const nestedSummary = await installDeps.installNestedDependencies(workdir, { quiet: false });
  const nestedFailedPaths = nestedSummary.results.filter((r) => !r.success).map((r) => r.path);
  if (nestedFailedPaths.length > 0) {
    log.cli(
      `⚠️  ${nestedFailedPaths.length} nested package install(s) failed after the dependency ` +
        `refresh. Run install manually in: ${nestedFailedPaths.join(", ")}`
    );
  }

  return {
    checked: true,
    changed: true,
    installed: true,
    nestedFailedPaths: nestedFailedPaths.length > 0 ? nestedFailedPaths : undefined,
  };
}

