} from "../../../../cockpit/conversation-label";

// ── Output shape ─────────────────────────────────────────────────────────────

export interface TranscriptListEntry {
  conversationId: string;
  harness: string;
  startedAt: string | null;
  endedAt: string | null;
  firstTurnAt: string | null;
  lastTurnAt: string | null;
  turnCount: number;
  /** mt#2770 content-derived label (task title / first-prompt snippet / subagent descriptor / fallback). */
  label: string;
  /** LLM-generated session summary, when the summary pipeline has run for this conversation. */
  summary: string | null;
  relatedTaskIds: string[];
  relatedPrNumbers: string[];
  /** Bound Minsky task id (display form), when `minsky_session_links` resolved one. */
  linkedTaskId: string | null;
  /** Ingest high-water-mark — see the module docblock's coverage-honesty section. */
  lastIngestedJsonlTimestamp: string | null;
}

export interface TranscriptListDiskCoverage {
  count: number;
  sampleConversationIds: string[];
}

export interface TranscriptListCoverage {
  /** Whether the (opt-in, disk-touching) discovery sweep ran — see module docblock. */
  diskCoverageChecked: boolean;
  /** Present only when `diskCoverageChecked` and disk sessions were found with zero DB rows. */
  unIngestedOnDisk?: TranscriptListDiskCoverage;
  note: string;
}

export interface TranscriptListResponse {
  conversations: TranscriptListEntry[];
  coverage: TranscriptListCoverage;
}

const DEFAULT_NOTE =
  "No on-disk discovery sweep was performed (zero disk access — see checkDiskCoverage). " +
  "Per-conversation lastIngestedJsonlTimestamp shows ingest freshness for already-known conversations.";

const DISK_SAMPLE_LIMIT = 10;

// ── Registration ──────────────────────────────────────────────────────────────

export function registerTranscriptListCommand(
  _container?: AppContainerInterface,
  registry?: SharedCommandRegistry
): void {
  const targetRegistry = registry ?? sharedCommandRegistry;

  targetRegistry.registerCommand({
    id: "transcripts.list",
    category: CommandCategory.TRANSCRIPTS,
    name: "list",
    description:
      "List recent harness conversations, most-recent-first, with summary metadata: " +
      "turn count, first/last turn timestamps, an mt#2770 content-derived label, " +
      "LLM summary (when generated), and workspace/task linkage where known. " +
      "Zero disk access by default (see checkDiskCoverage for the opt-in disk-discovery sweep). " +
      "Loud-cap truncation metadata (mt#2817): { returned, total, truncated }. " +
      "Coverage: reports whether a disk-discovery sweep ran, and surfaces lastIngestedJsonlTimestamp " +
      "per conversation so staleness is never silently invisible.",
    parameters: {
      limit: {
        schema: z.number().int().positive(),
        description:
          "Maximum number of conversations to return (default: DEFAULT_LIST_CAP, currently 500)",
        required: false,
      },
      checkDiskCoverage: {
        schema: z.boolean(),
        description:
          "Opt into a live on-disk discovery sweep (reuses the same discovery the ingest sweep " +
          "uses) to detect conversations that exist on disk but have never been ingested. " +
          "Off by default — this touches disk (stats every project dir, reads JSONL heads for " +
          "cwd recovery) and is NOT part of the tool's zero-disk-access default contract.",
        required: false,
        defaultValue: false,
      },
    },

    async execute(params, context): Promise<TranscriptListResponse> {
      const limit = params.limit as number | undefined;
      const checkDiskCoverage = (params.checkDiskCoverage as boolean | undefined) ?? false;

      // ── Resolve DB from DI container ─────────────────────────────────────
      const persistenceProvider = (() => {
        if (context.container?.has("persistence")) {
          return context.container.get(
            "persistence"
          ) as import("@minsky/domain/persistence/types").SqlCapablePersistenceProvider;
        }
        return null;
      })();

      if (!persistenceProvider) {
        throw new Error(
          "DI container missing 'persistence'. " +
            "Ensure the container was initialized before running this command."
        );
      }

      const db = await persistenceProvider.getDatabaseConnection();
      if (!db) {
        throw new Error(
          "getDatabaseConnection() returned null. " +
            "transcripts.list requires a PostgreSQL backend with Drizzle ORM."
        );
      }

      // ── Fetch base list + enrichment (zero disk access) ──────────────────
      const { TranscriptListService } = await import(
        "@minsky/domain/transcripts/transcript-list-service"
      );
      const svc = new TranscriptListService(
        db as import("drizzle-orm/postgres-js").PostgresJsDatabase
      );
      const { conversations: rows, truncation } = await svc.listConversations({ limit });

      // ── Resolve task titles for tier-1/tier-3 label inputs (best-effort) ──
      const taskTitles = await resolveTaskTitles(rows, context);

      const conversations: TranscriptListEntry[] = rows.map((row) => buildEntry(row, taskTitles));

      // ── Coverage ──────────────────────────────────────────────────────────
      const coverage = checkDiskCoverage
        ? await buildDiskCoverage(rows.map((r) => r.agentSessionId))
        : { diskCoverageChecked: false, note: DEFAULT_NOTE };

      log.debug("transcripts.list complete", {
        returned: truncation.returned,
        total: truncation.total,
        truncated: truncation.truncated,
        diskCoverageChecked: coverage.diskCoverageChecked,
      });

      return { conversations, coverage, ...truncation } as TranscriptListResponse &
        ListTruncationMetadata;
    },
  });

  // ── Enrichment ────────────────────────────────────────────────────────────

  private async fetchEnrichment(
    ids: string[]
  ): Promise<Map<string, Omit<TranscriptListRow, TranscriptListBaseFields>>> {
    type Enrichment = Omit<TranscriptListRow, TranscriptListBaseFields>;
    if (ids.length === 0) return new Map<string, Enrichment>();

    try {
      const [turnStats, turnCandidates, links, spawns, invocations] = await Promise.all([
        this.db
          .select({
            agentSessionId: agentTranscriptTurnsTable.agentSessionId,
            turnCount: sql<number>`count(*)::int`,
            firstTurnAt: sql<Date | null>`min(${agentTranscriptTurnsTable.startedAt})`,
            lastTurnAt: sql<Date | null>`max(coalesce(${agentTranscriptTurnsTable.endedAt}, ${agentTranscriptTurnsTable.startedAt}))`,
          })
          .from(agentTranscriptTurnsTable)
          .where(inArray(agentTranscriptTurnsTable.agentSessionId, ids))
          .groupBy(agentTranscriptTurnsTable.agentSessionId),
        this.db
          .select({
            agentSessionId: agentTranscriptTurnsTable.agentSessionId,
            turnIndex: agentTranscriptTurnsTable.turnIndex,
            userText: agentTranscriptTurnsTable.userText,
          })
          .from(agentTranscriptTurnsTable)
          .where(
            and(
              inArray(agentTranscriptTurnsTable.agentSessionId, ids),
              isNotNull(agentTranscriptTurnsTable.userText)
            )
          ),
        this.db
          .select({
            agentSessionId: minskySessionLinksTable.agentSessionId,
            minskySessionId: minskySessionLinksTable.minskySessionId,
            confidence: minskySessionLinksTable.confidence,
            detectedAt: minskySessionLinksTable.detectedAt,
          })
          .from(minskySessionLinksTable)
          .where(inArray(minskySessionLinksTable.agentSessionId, ids)),
        this.db
          .select({
            childAgentSessionId: agentSpawnsTable.childAgentSessionId,
            agentKind: agentSpawnsTable.agentKind,
          })
          .from(agentSpawnsTable)
          .where(inArray(agentSpawnsTable.childAgentSessionId, ids)),
        this.db
          .select({
            agentSessionId: subagentInvocationsTable.agentSessionId,
            taskId: subagentInvocationsTable.taskId,
            agentType: subagentInvocationsTable.agentType,
            startedAt: subagentInvocationsTable.startedAt,
          })
          .from(subagentInvocationsTable)
          .where(inArray(subagentInvocationsTable.agentSessionId, ids)),
      ]);

      // Tier 1: best link per session -> minskySessionId -> taskId (display form).
      const bestLinkBySession = pickBestLinks(links);
      const minskySessionIds = Array.from(new Set(bestLinkBySession.values()));
      const sessionTaskIds =
        minskySessionIds.length > 0
          ? await this.db
              .select({ sessionId: postgresSessions.sessionId, taskId: postgresSessions.taskId })
              .from(postgresSessions)
              .where(inArray(postgresSessions.sessionId, minskySessionIds as WorkspaceId[]))
          : [];
      const taskIdByMinskySessionId = new Map<string, string>();
      for (const row of sessionTaskIds) {
        if (row.taskId)
          taskIdByMinskySessionId.set(row.sessionId, formatTaskIdForDisplay(row.taskId));
      }
      const linkedTaskIdBySession = new Map<string, string>();
      for (const [agentSessionId, minskySessionId] of bestLinkBySession) {
        const taskId = taskIdByMinskySessionId.get(minskySessionId);
        if (taskId) linkedTaskIdBySession.set(agentSessionId, taskId);
      }

      // Tier 2: earliest-N non-null user-turn candidates, ordered by turnIndex.
      const turnCandidatesBySession = new Map<string, { turnIndex: number; userText: string }[]>();
      for (const turn of turnCandidates) {
        if (!turn.userText) continue;
        const list = turnCandidatesBySession.get(turn.agentSessionId) ?? [];
        list.push({ turnIndex: turn.turnIndex, userText: turn.userText });
        turnCandidatesBySession.set(turn.agentSessionId, list);
      }
      for (const list of turnCandidatesBySession.values()) {
        list.sort((a, b) => a.turnIndex - b.turnIndex);
      }

      // Tier 3 inputs.
      const spawnKindBySession = new Map<string, string>();
      for (const spawn of spawns) {
        if (spawn.childAgentSessionId && spawn.agentKind) {
          spawnKindBySession.set(spawn.childAgentSessionId, spawn.agentKind);
        }
      }
      const invocationBySession = new Map<
        string,
        { taskId: string | null; agentType: string | null; startedAt: number }
      >();
      for (const inv of invocations) {
        if (!inv.agentSessionId) continue;
        const startedAt = inv.startedAt instanceof Date ? inv.startedAt.getTime() : 0;
        const existing = invocationBySession.get(inv.agentSessionId);
        if (!existing || startedAt > existing.startedAt) {
          invocationBySession.set(inv.agentSessionId, {
            taskId: inv.taskId ? formatTaskIdForDisplay(inv.taskId) : null,
            agentType: inv.agentType ?? null,
            startedAt,
          });
        }
      }

      const turnStatsBySession = new Map(turnStats.map((r) => [r.agentSessionId, r]));

      const result = new Map<string, Enrichment>();
      for (const id of ids) {
        const stats = turnStatsBySession.get(id);
        const candidates = (turnCandidatesBySession.get(id) ?? [])
          .slice(0, FIRST_USER_TURN_CANDIDATE_LIMIT)
          .map((c) => c.userText);
        const invocation = invocationBySession.get(id);

        result.set(id, {
          turnCount: stats?.turnCount ?? 0,
          firstTurnAt: coerceDate(stats?.firstTurnAt),
          lastTurnAt: coerceDate(stats?.lastTurnAt),
          linkedTaskId: linkedTaskIdBySession.get(id) ?? null,
          firstUserTurnCandidates: candidates,
          subagentSpawnAgentKind: spawnKindBySession.get(id) ?? null,
          subagentInvocationAgentType: invocation?.agentType ?? null,
          subagentInvocationTaskId: invocation?.taskId ?? null,
        });
      }
      return result;
    } catch (err) {
      // Enrichment is best-effort — a failure here degrades every row to
      // zeroed turn stats + no label inputs (tier 4 fallback), never a
      // failed `transcripts.list` call.
      log.warn(
        `TranscriptListService.fetchEnrichment: enrichment query failed: ${getErrorMessage(err)}`
      );
      return new Map<string, Enrichment>();
    }
  }
}

/**
 * Coerce a `min()`/`max()` raw-SQL aggregate result to a `Date`.
 *
 * Unlike a plain typed column (e.g. `agentTranscriptsTable.startedAt`), a
 * `sql<Date | null>` template built over an aggregate function is NOT run
 * through Drizzle's column-type mapping — postgres.js returns it as an ISO
 * timestamp STRING, not a `Date` instance. Without this coercion,
 * `firstTurnAt`/`lastTurnAt` silently read as non-Date values downstream
 * (e.g. `list-command.ts`'s `toIso()`'s `instanceof Date` check would fail
 * and drop the value to `null` even though real data was returned).

 *   sessionId      Required. The agent session UUID.
 *   turnRange      Optional. Inclusive index range in "start-end" format (e.g. "10-20").
 *   role           Optional (mt#2818). Filter to turns by role: 'user' or 'assistant'.
 *   projection     Optional (mt#2818). 'full' (default) returns the structured
 *                  TranscriptTurnResult[] shape; 'text' returns a lean array of
 *                  { turnIndex, role, text, injected } — see the projection section below.
 *
 * DI pattern mirrors search-command.ts: persistence provider resolved from
 * `context.container` at execute time (not at registration time).
 *
 * ## Text projection (mt#2818)
 *
 * `projection: "text"` strips the response to just the role/text pairs a bulk
 * extraction workflow needs (the exact pattern the 2026-07-15 gap-analysis
 * session's 11 subagents reached for via disk `jq` instead). Tool-call
 * payloads are ALREADY excluded from `userText`/`assistantText` by
 * construction (`turn-extractor.ts`'s `extractUserText`/`extractAssistantText`
 * only join `text`-type content blocks — `tool_use`/`tool_result` blocks never
 * enter these columns), so no additional stripping is needed for that class.
 *
 * The remaining noise class is harness-injected TEXT markup embedded inside a
 * `text` block — slash-command wrappers (`<command-message>`), hook output
 * (`<local-command-stdout>`), and injected `<system-reminder>` blocks. This
 * projection reuses `stripHarnessMarkup` (mt#2784, `src/cockpit/text-snippet.ts`)
 * to detect and strip those specific tags:
 *
 *   - A turn's text that is ENTIRELY markup (nothing left after stripping) is
 *     EXCLUDED from the projected output.
 *   - A turn's text that MIXES real content with markup is INCLUDED with the
 *     markup stripped and `injected: true`, so a caller can filter further if
 *     it wants pure-clean-only.
 *   - A turn with no markup detected is included verbatim with `injected: false`.
 *
 * **Heuristic limits** (documented per mt#2818's requirement, not a general
 * claim of completeness): this is a fixed marker-tag allowlist
 * (`command-message`, `command-name`, `local-command-stdout`,
 * `system-reminder`), not a general parser. A harness-injected wrapper using a
 * tag name outside that list is NOT detected and will pass through unflagged.
 * It is also a regex match, not a real XML/HTML parser, so pathological
 * malformed/nested tags could mismatch. See `stripHarnessMarkup`'s own
 * docblock for the exact tag list and matching rules.
 *
 * @see mt#1355 — this file
 * @see mt#1352 — agent_transcript_turns schema
 * @see mt#1313 §Search tools — transcripts.get
 * @see mt#2818 — role + projection params, text-projection heuristic
 * @see mt#2784 — stripHarnessMarkup (reused here, not re-derived)
 */

import { z } from "zod";
import { sharedCommandRegistry, CommandCategory } from "../../command-registry";
import type { SharedCommandRegistry } from "../../command-registry";
import { log } from "@minsky/shared/logger";
import type { AppContainerInterface } from "@minsky/domain/composition/types";
import type { TranscriptTurnResult } from "@minsky/domain/transcripts/transcript-fts-service";
import type { AgentSessionId } from "@minsky/domain/transcripts/transcript-source";
import {
  conversationIdParam,
  deprecatedConversationAlias,
  resolveConversationId,
} from "./conversation-id-param";
// mt#2818: reuse the mt#2784 harness-markup heuristic rather than re-deriving
// it — both call sites (this projection and mt#2770's label snippets) must
// agree on what counts as injected markup.
import { stripHarnessMarkup } from "../../../../cockpit/text-snippet";

// ── Text projection types ────────────────────────────────────────────────────

export type TranscriptTurnRole = "user" | "assistant";

/** One text-projected turn entry (mt#2818, `projection: "text"`). */
export interface TranscriptTextProjectionEntry {
  turnIndex: number;
  role: TranscriptTurnRole;
  /** Cleaned text — harness-markup blocks stripped when `injected` is true. */
  text: string;
  /**
   * True when the raw stored text contained detectable harness-injected
   * markup (see the module docblock's "Heuristic limits" section) that was
   * stripped to produce `text`.
   */
  injected: boolean;
}

/**
 * Project a set of full turn rows down to role/text pairs, applying the
 * mt#2818 injected-markup heuristic. `role` narrows which side(s) of each
 * turn are projected: omitted means both userText and assistantText (when
 * present) each become their own entry.
 */
export function projectTurnsToText(
  turns: Pick<TranscriptTurnResult, "turnIndex" | "userText" | "assistantText">[],
  role?: TranscriptTurnRole
): TranscriptTextProjectionEntry[] {
  const entries: TranscriptTextProjectionEntry[] = [];
  for (const turn of turns) {
    const candidates: { role: TranscriptTurnRole; raw: string | null }[] = [];
    if (!role || role === "user") candidates.push({ role: "user", raw: turn.userText });
    if (!role || role === "assistant")
      candidates.push({ role: "assistant", raw: turn.assistantText });

    for (const candidate of candidates) {
      if (!candidate.raw) continue;
      const stripped = stripHarnessMarkup(candidate.raw);
      const injected = stripped !== candidate.raw;
      const text = stripped.trim();
      if (text.length === 0) continue; // entirely injected markup — excluded
      entries.push({ turnIndex: turn.turnIndex, role: candidate.role, text, injected });
    }
  }
  return entries;
}

// ── Registration ──────────────────────────────────────────────────────────────

/**
 * Register the `transcripts.get` shared command.
 *
 * @param _container Optional DI container (resolved at execute time).
 * @param registry   Defaults to global sharedCommandRegistry. Pass a fresh
 *                   registry in tests to avoid global state mutation.
 */
export function registerTranscriptGetCommand(
  _container?: AppContainerInterface,
  registry?: SharedCommandRegistry
): void {
  const targetRegistry = registry ?? sharedCommandRegistry;

  targetRegistry.registerCommand({
    id: "transcripts.get",
    category: CommandCategory.TRANSCRIPTS,
    name: "get",
    description:
      "Return all turns for a harness conversation in turn_index order. " +
      "Optionally slice to a turn range using the turnRange parameter (format: 'start-end', e.g. '10-20'). " +
      "Optionally filter to a role ('user' or 'assistant', mt#2818) and/or request a lean " +
      "text-only projection (projection: 'text') that excludes tool-call payloads (already " +
      "excluded from userText/assistantText by construction) and strips/flags detectable " +
      "harness-injected markup (system-reminder / command wrappers — heuristic, see docs). " +
      "Throws if the conversation is not found. " +
      "Coverage: conversations are auto-ingested on MCP server boot; " +
      "if a conversation is missing, run `transcripts_ingest --all` to force a full sweep.",
    parameters: {
      // NOTE (mt#2526): the conversation id is REQUIRED, but enforced at execute time
      // (resolveConversationId below) rather than via the schema `required` flag — so the
      // deprecated `sessionId` alias still satisfies it. Schema/MCP consumers should NOT
      // read `required: false` as "optional": exactly one of conversationId / sessionId
      // must be supplied (the execute path throws otherwise).
      conversationId: conversationIdParam(
        "The harness conversation id (agent-session UUID) to retrieve turns for"
      ),
      sessionId: deprecatedConversationAlias("sessionId"),
      turnRange: {
        schema: z
          .string()
          .regex(/^\d+-\d+$/, "turnRange must be in 'start-end' format, e.g. '10-20'"),
        description:
          "Inclusive turn index range in 'start-end' format (e.g. '10-20'). " +
          "Returns only turns with turn_index between start and end (inclusive).",
        required: false,
      },

      };

      for (const el of turn.elements) {
        switch (el.kind) {
          case "text":
            textRun += el.text;
            hasTextRun = true;
            break;
          case "tool-call": {
            flushTextRun();
            const result = el.id ? resultById.get(el.id) : undefined;
            elements.push({ kind: "tool-invocation", call: el, result });
            break;
          }
          case "tool-result": {
            flushTextRun();
            const pairedInWindow = el.toolUseId ? callById.has(el.toolUseId) : false;
            if (pairedInWindow) break;
            elements.push({
              kind: "tool-result-orphan",
              result: el,
              callName: el.toolUseId ? callNameByToolUseId.get(el.toolUseId) : undefined,
            });
            break;
          }
          default:
            flushTextRun();
            elements.push(el);
        }
      }
      flushTextRun();
    }

    return {
      blockId: turn.blockId,
      role: turn.role,
      timestamp: turn.timestamp,
      elements,
      isSpawnBoundary: turn.isSpawnBoundary,
      spawnAgentKind: turn.spawnAgentKind,
    };
  });
}

function hasRenderablePreparedElement(el: PreparedElement): boolean {
  switch (el.kind) {
    case "text":
      return el.text.trim().length > 0;
    case "thinking":
      return el.thinking.trim().length > 0;
    // "injected" / "tool-invocation" / "tool-result-orphan" / "unknown" all
    // fall to the default: always renderable (mirrors pre-mt#2791 behavior).
    default:
      return true;
  }
}

// ── API-error text detection (mt#2793) ──────────────────────────────────────
//
// Harness-emitted failure text sometimes lands as an ordinary assistant text
// turn (e.g. "API Error: Connection closed mid-response.") rather than a
// tool-result error — it renders identically to normal prose and is easy to
// scroll past. Detection is intentionally conservative: an ANCHORED prefix
// match on the turn's TRIMMED text, not a substring match anywhere in the
// turn — a turn that merely discusses "the API Error" elsewhere in its text
// stays unstyled.
const API_ERROR_PREFIX = "API Error:";

function isApiErrorText(text: string): boolean {
  return text.trim().startsWith(API_ERROR_PREFIX);
}

function ElementView({
  element,
  entityIndex,
  expandSignal,
}: {
  element: PreparedElement;
  /** Known-entity id-set for linkification of bare refs and minsky:// URIs. */
  entityIndex: EntityIndex;
  expandSignal: ExpandSignal;
}) {
  switch (element.kind) {
    case "text": {
      // Assistant/user prose turns are Markdown — render via the shared <Prose>
      // (Markdown structure + entity-linkification). mt#2550.
      if (element.text.trim().length === 0) return null;
      // A harness-emitted "API Error: …" turn gets destructive-toned treatment
      // (semantic `destructive` token only, per src/cockpit/CLAUDE.md §status
      // colors) so a terminal failure is visible without reading every turn.
      if (isApiErrorText(element.text)) {
        return (
          <div role="alert" className="rounded border border-destructive/40 bg-destructive/5 px-2 py-1">
            <Prose entityIndex={entityIndex} className="text-destructive">
              {element.text}
            </Prose>
          </div>
        );
      }
      return <Prose entityIndex={entityIndex}>{element.text}</Prose>;
    }
    case "thinking":
      return element.thinking.trim().length > 0 ? (
        <ThinkingBlock thinking={element.thinking} entityIndex={entityIndex} />
      ) : null;
    case "tool-invocation":
      return (
        <ToolInvocation
          call={element.call}
          result={element.result}
          entityIndex={entityIndex}
          expandSignal={expandSignal}
        />
      );
    case "tool-result-orphan":
      return (
        <ToolResult element={element.result} callName={element.callName} entityIndex={entityIndex} />
      );
    case "injected":
      return (
        <InjectedContentBlock span={element.span} entityIndex={entityIndex} expandSignal={expandSignal} />
      );
    case "unknown":
      return (
        <div className="rounded border border-border/40 bg-muted/10 px-2 py-1 text-xs text-muted-foreground">
          unsupported block{element.rawType ? `: ${element.rawType}` : ""}
        </div>
      );
    default: {
      // Compiler-enforced exhaustiveness: adding a PreparedElement kind without
      // a render case is a type error here, not a silently-dropped block.
      const unhandled: never = element;
      return unhandled;
    }
  }
}

// Role → left accent + label styling for the thread.
const ROLE_STYLES: Record<ConversationTurn["role"], { accent: string; label: string }> = {
  user: { accent: "border-l-emerald-500/50", label: "user" },
  assistant: { accent: "border-l-sky-500/40", label: "assistant" },
  other: { accent: "border-l-border", label: "other" },
};

function TurnView({
  turn,
  entityIndex,
  expandSignal,
