            createdAt: prDetails.created_at,
            mergedAt: prDetails.merged_at || finalPullRequest.mergedAt,
            headBranch: prDetails.head?.ref || finalPullRequest.headBranch,

// Anchored to turn-start (`^`) only — see module docblock. The command
// wrapper (message/name/args) and the `<skill-format>` marker are all
// optional, so this also matches a bare "Base directory for this skill:"
// preamble with no preceding wrapper.
const SKILL_BODY_PREFIX_RE = new RegExp(
  `^(?:${tagBlock("command-message")}\\s*` +
    `(?:${tagBlock("command-name")}\\s*)?` +
    `(?:${tagBlock("command-args")}\\s*)?` +
    `(?:${tagBlock("skill-format")}\\s*)?` +
    `)?Base directory for this skill:\\s*(\\S+)`,
  "i"
);

// Anchored to turn-start (`^`) only. Tried AFTER SKILL_BODY_PREFIX_RE fails —
// a skill invocation also starts with `<command-message>`, so priority order
// matters (see matchTurnStartInjection).
const COMMAND_PREFIX_RE = new RegExp(
  `^${tagBlock("command-message", true)}\\s*` +
    `(?:${tagBlock("command-name", true)}\\s*)?` +
    `(?:${tagBlock("command-args")}\\s*)?`,
  "i"
);

// NOT anchored — matched wherever it appears (see module docblock). Built
// fresh per call in splitSystemReminderBlocks (global-flagged regexes carry
// mutable `lastIndex` state across `.exec()` calls; a shared module-level
// instance would leak state between the many turns this runs over per render).
function systemReminderRegex(): RegExp {
  return new RegExp(tagBlock("system-reminder", true), "gi");
}

// Boundary marker for a multi-skill-concatenated turn: once a skill-body
// span is detected, its content stops at the NEXT recognized turn-start
// anchor (another skill's `<command-message>`, or a `<system-reminder>`)
// rather than swallowing the rest of the turn.
const NEXT_BOUNDARY_RE = new RegExp(
  `(?:${tagOpen("command-message")}|${tagOpen("system-reminder")})`,
  "i"
);

function skillNameFromPath(path: string): string {
  const segments = path.split(/[\\/]/).filter((s) => s.length > 0);
  return segments[segments.length - 1] || path;
}

function findNextBoundary(text: string, fromIndex: number): number {
  const tail = text.slice(fromIndex);
  const match = NEXT_BOUNDARY_RE.exec(tail);
  return match ? fromIndex + match.index : text.length;
}

interface PrefixMatch {
  consumedLength: number;
  span: InjectedSpan;
}

function matchSkillBodyPrefix(text: string): PrefixMatch | null {
  const match = SKILL_BODY_PREFIX_RE.exec(text);
  if (!match) return null;
  const path = match[1] ?? "";
  const wrapperEnd = match[0].length;
  const end = findNextBoundary(text, wrapperEnd);
  return {
    consumedLength: end,
    span: {
      kind: "skill-body",
      label: `skill body: ${skillNameFromPath(path)}`,
      // Body only — the raw wrapper tags (command-message/name/args,
      // skill-format, the "Base directory..." line) are stripped from the
      // expand view, matching the "expanding shows the full Markdown"
      // acceptance criterion rather than raw XML + Markdown.
      content: text.slice(wrapperEnd, end).trim(),
    },
  };
}

function matchCommandOnlyPrefix(text: string): PrefixMatch | null {
  const match = COMMAND_PREFIX_RE.exec(text);
  if (!match) return null;
  const commandNameContent = match[2]?.trim();
  const commandMessageContent = match[1]?.trim();
  const name = commandNameContent || commandMessageContent || "unknown";
  return {
    consumedLength: match[0].length,
    span: {
      kind: "command",
      label: `command: ${name}`,
      content: match[0].trim(),
    },
  };
}

function matchTurnStartInjection(text: string): PrefixMatch | null {
  return matchSkillBodyPrefix(text) ?? matchCommandOnlyPrefix(text);
}

/**
 * Split `text` on `<system-reminder>` blocks wherever they occur, preserving
 * any surrounding prose as separate segments. Returns a single verbatim
 * `{ type: "prose", text }` segment when no reminder block is present — the
 * "renders exactly as today" fallback for the fully-unrecognized case.
 */
function splitSystemReminderBlocks(text: string): TextSegment[] {
  const re = systemReminderRegex();
  const matches: RegExpExecArray[] = [];
  let m: RegExpExecArray | null;
  while ((m = re.exec(text)) !== null) {
    matches.push(m);
    // A tag-pair match always consumes at least the tag markers, so this
    // can't zero-length-loop in practice — kept as a cheap safety net.
    if (m[0].length === 0) re.lastIndex += 1;
  }
  if (matches.length === 0) return [{ type: "prose", text }];

  const segments: TextSegment[] = [];
  let cursor = 0;
  for (const match of matches) {
    if (match.index > cursor) {
      const prose = text.slice(cursor, match.index);
      if (prose.trim().length > 0) segments.push({ type: "prose", text: prose });
    }
    segments.push({
      type: "injected",
      span: { kind: "system-reminder", label: "system reminder", content: (match[1] ?? "").trim() },
    });
    cursor = match.index + match[0].length;
  }
  if (cursor < text.length) {
    segments.push({ type: "prose", text: text.slice(cursor) });
  }
  return segments;
}

/**
 * Classify one user turn's raw text into an ordered list of prose/injected
 * segments. See module docblock for the detection rules and the "renders
 * exactly as today" fallback for unrecognized content.
 */
export function splitInjectedContent(text: string): TextSegment[] {
  if (!text) return [];

  const prefixSegments: TextSegment[] = [];
  let rest = text;
  let consumedAny = false;
  while (rest.length > 0) {
    const prefix = matchTurnStartInjection(rest);
    if (!prefix || prefix.consumedLength <= 0) break;
    prefixSegments.push({ type: "injected", span: prefix.span });
    rest = rest.slice(prefix.consumedLength);
    consumedAny = true;
  }

  if (!consumedAny) {
    // Fast path: nothing turn-start-anchored matched. Hand the ENTIRE
    // original text to the system-reminder scan, which itself returns it
    // verbatim (single segment) when no reminder is present either.
    return splitSystemReminderBlocks(text);
  }
  if (rest.length > 0) {
    prefixSegments.push(...splitSystemReminderBlocks(rest));

  useEffect(() => {
    if (expandSignal) setOpen(expandSignal.open);
  }, [expandEpoch]);

  return (
    <div className="rounded border border-border/40 bg-muted/10">
      <button
        type="button"
        onClick={() => setOpen((o) => !o)}
        aria-expanded={open}
        className="flex w-full items-center gap-2 px-2 py-1 text-left text-xs text-muted-foreground"
      >
        <span className="italic">{span.label}</span>
        <span className="text-muted-foreground/50">
          ({span.content.length.toLocaleString()} chars)
        </span>
        <span aria-hidden className="ml-auto text-muted-foreground/60">
          {open ? "▾" : "▸"}
        </span>
      </button>
      {open && (
        <div className="border-t border-border/40 px-2 py-1">
          <Prose entityIndex={entityIndex} className="text-muted-foreground/90">
            {span.content}
          </Prose>
        </div>
      )}
    </div>
  );
}

// ── Tool-invocation pairing (mt#2790) ───────────────────────────────────────────
//
// A pre-render assembly pass that merges each tool-call with its matching
// tool-result (found via `toolUseId`), so the pair renders as ONE block
// instead of two turn-level blocks (a call under ASSISTANT, a result under
// USER). Pairing is scoped to the turns actually being rendered ("the
// rendered window") — a result whose call fell outside that set (windowing/
// pagination cut it, or mt#2789's subagent-transcript duplication) is an
// ORPHAN and keeps the pre-redesign standalone treatment; it is never
// silently dropped.

type ToolCallElement = Extract<ConversationElement, { kind: "tool-call" }>;
type ToolResultElement = Extract<ConversationElement, { kind: "tool-result" }>;

/** One conversational sub-element after tool-invocation pairing. */
type PreparedElement =
  | { kind: "text"; text: string }
  | { kind: "thinking"; thinking: string }
  | { kind: "tool-invocation"; call: ToolCallElement; result?: ToolResultElement }
  | { kind: "tool-result-orphan"; result: ToolResultElement; callName: string | undefined }
  | { kind: "injected"; span: InjectedSpan }
  | { kind: "unknown"; rawType: string; raw: unknown };

interface PreparedTurn {
  blockId: string;
  role: ConversationRole;
  timestamp: string;
  elements: PreparedElement[];
  isSpawnBoundary: boolean;
  spawnAgentKind?: string;
}

/**
 * Merge tool-calls with their matching tool-results across `turns` (the
 * turns actually being rendered — see module docblock). `callNameByToolUseId`
 * is built over the FULL, unwindowed transcript (unchanged pre-existing
 * behavior) so an orphan can still show which tool it answers even when that
 * tool's call turn isn't in the current set.
 */
function pairToolInvocations(
  turns: ConversationTurn[],
  callNameByToolUseId: Map<string, string>
): PreparedTurn[] {
  const callById = new Map<string, ToolCallElement>();
  const resultById = new Map<string, ToolResultElement>();
  for (const turn of turns) {
    for (const el of turn.elements) {
      if (el.kind === "tool-call" && el.id) callById.set(el.id, el);
      if (el.kind === "tool-result" && el.toolUseId) resultById.set(el.toolUseId, el);
    }
  }

  return turns.map((turn) => {
    const elements: PreparedElement[] = [];

    // Injected-content detection is scoped to USER turns (mt#2791) — command
    // wrappers, skill-body preambles, and system reminders are ALWAYS
    // harness-injected into a user turn, never assistant-authored, so
    // scoping here (rather than substring-matching everywhere) keeps
    // detection conservative per the module's anchored-pattern design.
    // Non-user turns keep the pre-mt#2791 pass-through, unchanged below.
    if (turn.role !== "user") {
      for (const el of turn.elements) {
        switch (el.kind) {
          case "tool-call": {
            const result = el.id ? resultById.get(el.id) : undefined;
            elements.push({ kind: "tool-invocation", call: el, result });
            break;
          }
          case "tool-result": {
            const pairedInWindow = el.toolUseId ? callById.has(el.toolUseId) : false;
            if (pairedInWindow) break;
            elements.push({
              kind: "tool-result-orphan",
              result: el,
              callName: el.toolUseId ? callNameByToolUseId.get(el.toolUseId) : undefined,
            });
            break;
          }
          default:
            elements.push(el);
        }
      }
    } else {
      // Consecutive `text` elements are concatenated into one run BEFORE
      // injected-content detection (mt#2791). The harness sometimes splits
      // one logical injection across adjacent text sub-blocks in a turn's
      // message content array — e.g. a skill invocation arrives as TWO
      // parts: `<command-message>…</command-message><command-name>…</command-name>
      // <skill-format>true</skill-format>` as one block, then
      // "Base directory for this skill: <path>\n\n<body>" as the next
      // (verified against a live transcript). Splitting each part in
      // isolation misses the cross-element join: the first part fails the
      // skill-body pattern (no "Base directory..." follows it WITHIN that
      // block) and falls back to a bare "command:" match, leaking the raw
      // `<skill-format>` tag as literal prose between two mis-split blocks.
      // Concatenating the run first reconstructs the single contiguous
      // string the harness effectively injected, so the pair renders as ONE
      // correctly-labeled "skill body: <name>" block.
      let textRun = "";
      let hasTextRun = false;
      const flushTextRun = () => {
        if (!hasTextRun) return;
        for (const seg of splitInjectedContent(textRun)) {
          if (seg.type === "injected") {
            elements.push({ kind: "injected", span: seg.span });
          } else if (seg.text.trim().length > 0) {
            // A mixed turn splits: only the injected span collapses, the
            // genuine prose renders exactly as it would have unsplit.
            elements.push({ kind: "text", text: seg.text });
          }
        }
        textRun = "";
        hasTextRun = false;
      };

      for (const el of turn.elements) {
        switch (el.kind) {
          case "text":
            textRun += el.text;
            hasTextRun = true;
            break;
          case "tool-call": {
            flushTextRun();
            const result = el.id ? resultById.get(el.id) : undefined;
            elements.push({ kind: "tool-invocation", call: el, result });
            break;
          }
          case "tool-result": {
            flushTextRun();

/**
 * POST /api/agents/:id/focus (mt#2286).
 *
 * The Agents-view "go to" action for an EXTERNALLY-attached session: the
 * browser cannot raise an OS terminal directly, so this cockpit-server route
 * resolves the workspace session's live mt#2284 attachment(s) and delegates
 * to the mt#2285 focus-adapter orchestration (`focusAttachment`) in-process.
 *
 * Local-only (v0): an attachment recorded on a non-local host is reported as
 * `remote-host-unsupported` rather than attempted — the mt#2285 focus
 * adapters only make sense against a process on the SAME machine as this
 * cockpit daemon. Cross-host ("mesh") focus is out of scope for this task —
 * see the task spec's `## Scope`.
 *
 * HARD sandbox constraint (mirrors mt#2285's `executor.ts` docblock): this
 * module must never invoke a REAL focus action (AppleScript/tmux/wezterm/
 * kitty) from the implementation/test sandbox. Every test injects a mock
 * `CommandExecutor` via the `executor` option; production wires the real
 * `defaultCommandExecutor` (mt#2285) by omitting the option entirely (see
 * `focusAttachment`'s own default in `packages/domain/src/session/focus/registry.ts`).
 */
import type express from "express";
import { hostname as osHostname } from "node:os";
import type { PostgresJsDatabase } from "drizzle-orm/postgres-js";
import { log } from "@minsky/shared/logger";
import type { CommandExecutor } from "@minsky/domain/session/index";

export interface AgentFocusRouteOptions {
  /** Test seam — overrides the cockpit-wide SQL connection getter. */
  getDb?: () => Promise<PostgresJsDatabase | null>;
  /**
   * Test seam — overrides the real (mt#2285) focus executor. Production
   * MUST omit this so `focusAttachment` falls through to its own
   * `defaultCommandExecutor`; every test MUST supply a mock (sandbox rule
   * above).
   */
  executor?: CommandExecutor;
  /** Test seam — overrides `os.hostname()` for remote-host-rejection tests. */
  hostname?: () => string;
}

/** Mount POST /api/agents/:id/focus on `app`. */
export function mountAgentFocusRoutes(
  app: express.Express,
  opts: AgentFocusRouteOptions = {}
): void {
  const getHostname = opts.hostname ?? osHostname;

  app.post("/api/agents/:id/focus", async (req, res) => {
    const rawId = req.params.id;
    if (!rawId) {
      res.status(400).json({ error: "Session ID required" });
      return;
    }
    const sessionId = decodeURIComponent(rawId);

    try {
      const getDb = opts.getDb ?? (await import("../db-providers")).getContextInspectorDb;
      const db = await getDb();
      if (!db) {
        res.status(503).json({
          error: "Presence service unavailable — cannot resolve stored attachments.",
        });
        return;
      }

      const { buildPresenceClaimRepository } = await import("@minsky/domain/presence/index");
      const repo = buildPresenceClaimRepository(db);
      if (!repo) {
        res.status(503).json({
          error: "Presence service unavailable — cannot resolve stored attachments.",
        });
        return;
      }

      const { listSessionAttachments, isAttachmentConfirmedLive, focusAttachment } = await import(
        "@minsky/domain/session/index"
      );

      // Raw (not liveness-filtered) so a remote-host attachment can be
      // distinguished from "nothing attached at all" — isAttachmentConfirmedLive
      // already excludes non-local-host rows, which would otherwise collapse
      // both cases into the same generic "nothing attached" message.
      const raw = await listSessionAttachments(repo, sessionId);
      const localHost = getHostname();
      const liveLocal = raw.filter((a) => isAttachmentConfirmedLive(a, localHost));

      if (liveLocal.length === 0) {
        const remoteOnly = raw.some((a) => a.host && a.host !== localHost);
        if (remoteOnly) {
          res.json({
            success: false,
            outcomeKind: "remote-host-unsupported",
            message:
              `Session ${sessionId}'s attachment is on a different host — focusing a ` +
              "remote terminal is not supported yet (v0, local-only).",
          });
          return;
        }
        res.json({
          success: false,
          outcomeKind: "nothing-attached",
          message: `Nothing attached to session ${sessionId} — no live terminal to go to.`,
        });
        return;
      }

      // Most-recently-registered live attachment wins when several are
      // present — a single button has no room for a CLI-style `--attachment`
      // selector prompt (contrast `session focus`'s ambiguity handling,
      // src/adapters/shared/commands/session/focus-command.ts).
      const sorted = [...liveLocal].sort((a, b) => b.registeredAt.localeCompare(a.registeredAt));
      const target = sorted[0];
      if (!target) {
        // Unreachable given liveLocal.length > 0 above; keeps TS control-flow
        // analysis happy without a non-null assertion.
        res.status(500).json({ error: "Could not resolve an attachment to focus." });
        return;
      }

    case "attached-external":
      return { type: "focus", sessionId: agent.sessionId };
    case "in-cockpit":
      return {
        type: "navigate",
        path: pathForTab(basePathFor("workspace", agent.sessionId), "workspace", "conversation"),
      };
    case "detached":
    case null:
      // `null` (attachment lookup unavailable/degraded) is treated the same
      // as "detached" — fail closed rather than guessing whether there's
      // something to focus.
      return { type: "disabled", reason: "Nothing attached" };
  }
}

const ATTACH_STATE_CONFIG: Record<
  RowAttachState,
