 * dot (activity-recency) and the live-tail pulse (active-conversation), so it
 * intentionally stays subtle (muted, icon-only, no color-coding) in an
 * already-dense row.
 */
function AttachStateIndicator({ state }: { state: AgentRow["attachState"] }) {
