/// health endpoint answers and whether *anything* is listening on the port.
/// Health-OK always wins (it's the strongest signal it's our daemon), even if
/// the port also shows a listener.
fn decide_action(health_ok: bool, port_in_use: bool) -> DaemonAction {
    if health_ok {
        DaemonAction::Adopt
    } else if port_in_use {
        DaemonAction::Conflict
    } else {
        DaemonAction::Spawn
    }
}

/// True when enough time has elapsed since the last spawn to respawn again.
fn throttle_ok(last_spawn: Option<Instant>, now: Instant, min: Duration) -> bool {
    match last_spawn {
        Some(t) => now.duration_since(t) >= min,
        None => true,
    }
}

/// mt#2786: whether the supervisor should take over after an adopted (or
/// never-spawned) daemon has been unresponsive for a sustained window. The
/// original design NEVER respawned over an adopted daemon ("don't fight an
/// operator restarting it manually") — which left the cockpit down
/// indefinitely once an adopted daemon died (observed 2026-07-13: 9+ min dead
/// port, manual restart required). Takeover requires ALL of:
/// - the outage is sustained past ADOPTED_TAKEOVER_POLL_THRESHOLD (the 1-min
///   alert has already fired by then), AND
/// - the port is FREE — an operator mid-restart (or any replacement daemon)
///   holds the port, so this preserves the original conservatism, AND
/// - the respawn throttle permits.
fn should_takeover_adopted(consecutive_http_failed: u32, port_held: bool, throttle_ok: bool) -> bool {
    consecutive_http_failed > ADOPTED_TAKEOVER_POLL_THRESHOLD && !port_held && throttle_ok
}

// ---------------------------------------------------------------------------
// mt#2794: health-down/no-child poll arm, extracted for testability.
//
// The live `Some(Err(_)) | None` poll arm (below, in `run_supervisor`) needs
// an `&AppHandle` and a live `Sup` to actually spawn a daemon, toast a
// notification, or push a status/uptime label. None of that is available in
// a `cargo test` without a Tauri runtime. `handle_health_down_no_child`
// carries the ARM'S DECISION LOGIC (the mt#2786 takeover branch + its PR
// #1927 R1 pre-spawn recheck) without touching any of that: the two seams a
// test controls are `port_in_use` (stubbed port checks) and `effect`
// (records which live operation the arm would have performed instead of
// performing it). `NoChildCounters` carries the plain-data slice of `Sup`
// this arm reads/writes.
// ---------------------------------------------------------------------------

/// Watchdog counters the health-down/no-child poll arm reads and mutates,
/// pulled out of `Sup` into an owned value. `handle_health_down_no_child`
/// takes this instead of `&mut Sup` directly: the live call site also needs
/// a SEPARATE `&mut Sup` borrow inside its `effect` closure (for
/// `do_spawn` / `set_status` / `clear_uptime`), and Rust doesn't allow two
/// live mutable borrows of the same value at once. Callers move the
/// relevant fields out with `take_from` and copy them back with
/// `write_back_to` after the call; `last_spawn` is read-only here — the
/// real `do_spawn`, invoked through the `Spawn` effect, updates
/// `Sup::last_spawn` directly on its own `&mut Sup`.
struct NoChildCounters {
    consecutive_http_failed: u32,
    last_http_alert: Option<Instant>,
    last_spawn: Option<Instant>,
    restart_timestamps: Vec<Instant>,
    last_process_started_at_ms: Option<u64>,
}

impl NoChildCounters {
    fn take_from(sup: &mut Sup) -> Self {
        Self {
            consecutive_http_failed: sup.consecutive_http_failed,
            last_http_alert: sup.last_http_alert,
            last_spawn: sup.last_spawn,
            restart_timestamps: std::mem::take(&mut sup.restart_timestamps),
            last_process_started_at_ms: sup.last_process_started_at_ms,
        }
    }

    fn write_back_to(self, sup: &mut Sup) {
        sup.consecutive_http_failed = self.consecutive_http_failed;
        sup.last_http_alert = self.last_http_alert;
        sup.restart_timestamps = self.restart_timestamps;
        sup.last_process_started_at_ms = self.last_process_started_at_ms;
    }
}

/// A live effect `handle_health_down_no_child` asks its caller to perform.
/// Bundled into one enum (rather than four separate closures) so the call
/// site needs only ONE `FnMut` capturing `&mut Sup` / `&AppHandle` — Rust
/// doesn't allow several closures to each independently capture the same
/// `&mut` binding.
enum NoChildEffect<'a> {
    /// Fire the sustained-HTTP-failure toast with this message.
    Notify(&'a str),
    /// mt#2786 takeover: spawn a new daemon (`do_spawn` in the live loop).
    Spawn,
    /// Push this label to the status line.
    SetStatus(&'static str),
    /// Clear the uptime line (no daemon running).
    ClearUptime,
}

/// Body of the poll loop's `Some(Err(_)) | None` arm: no child of ours
/// (adopted daemon down, or never spawned). Split out (mt#2794, a PR #1927
/// follow-up) so the mt#2786 takeover branch is testable without a live
/// Tokio loop — `port_in_use` and `effect` are the seams a test stubs;
/// `counters` is the plain-data slice of `Sup` this arm touches.
///
/// `port_in_use` may be called TWICE in one invocation: once for the
/// takeover gate, once for the PR #1927 R1 pre-spawn recheck. A caller can
/// return a different result per call to model the port being bound in the
/// gap between the two checks.
///
/// Behavior-preserving versus the original inline arm, with one in-scope
/// fix (PR #1927 R2 non-blocking): the aborted-takeover path now also
/// emits `ClearUptime`, so an aborted takeover no longer leaves a stale
/// uptime line visible for one more poll cycle.
fn handle_health_down_no_child(
    counters: &mut NoChildCounters,
    poll_now: Instant,
    mut port_in_use: impl FnMut() -> bool,
    mut effect: impl FnMut(NoChildEffect),
) {
    // Don't IMMEDIATELY spawn over an adopted daemon — but see the mt#2786
    // takeover below. Apply the same sustained-HTTP-failure alert here: an
    // expected adopted daemon that stops responding is an alert-worthy
    // condition.
    if counters.consecutive_http_failed > HTTP_FAILURE_POLL_THRESHOLD {
        let cooldown_elapsed = counters
            .last_http_alert
            .map(|t| poll_now.duration_since(t) >= ALERT_COOLDOWN)
            .unwrap_or(true);
        if cooldown_elapsed {
            let sustained_secs =
                counters.consecutive_http_failed as u64 * POLL_INTERVAL.as_secs();
            let reason = format!(
                "Cockpit health endpoint has been unreachable for {sustained_secs}s — \
                 daemon may be down. Check logs: ~/.local/state/minsky/logs/cockpit-stderr.log",
            );
            effect(NoChildEffect::Notify(&reason));
            counters.last_http_alert = Some(poll_now);
            eprintln!("[watchdog] sustained HTTP-failure (no child) alert: {}", reason);
        }
    }

    // mt#2786: takeover-respawn. Once the outage is sustained (2× the alert
    // threshold) and nobody holds the port (an operator's replacement
    // daemon would), convert from adopted to spawned supervision instead of
    // staying "stopped" forever. Counts toward restart-storm accounting so
    // a flapping takeover still alerts.
    let port_held = port_in_use();
    if should_takeover_adopted(
        counters.consecutive_http_failed,
        port_held,
        throttle_ok(counters.last_spawn, poll_now, RESPAWN_THROTTLE),
    ) {
        // Final pre-spawn recheck (PR #1927 R1): shrink the race between the
        // poll-time port check and our spawn — an operator's replacement
        // daemon may have bound the port in the gap. If so, stand down; the

  const firstSegment = rest.split("/")[0];
  // Top-level files (e.g. asks.ts) have no family directory — no entry, no check.
  if (!firstSegment || firstSegment.endsWith(".ts") || firstSegment.endsWith(".js")) return null;
  return firstSegment;
}

function propertyKeyName(prop) {
  if (prop.type !== "Property") return null;
  if (prop.key?.type === "Identifier") return prop.key.name;
  if (prop.key?.type === "Literal" && typeof prop.key.value === "string") return prop.key.value;
  return null;
}

export default {
  meta: {
    type: "problem",
    docs: {
      description:
        "Flag a command params map declaring a family's alias entity-id name without the family's canonical name (mt#2780, Detector-A drift class)",
    },
    schema: [],
    messages: {
      aliasWithoutCanonical:
        "Entity-id param drift: this `{{family}}` family map declares '{{alias}}' without the family's canonical '{{canonical}}' (convention record: mt#2741). Declare '{{canonical}}' (optionally keeping '{{alias}}' as a back-compat alias alongside it).",
    },
  },

  create(context) {
    const filename = context.filename ?? context.getFilename();
    const family = familyForFilename(filename);
    const convention = family ? FAMILY_CONVENTIONS[family] : null;
    if (!convention) return {};

    /**
     * A param-map object literal is one that either sits under
     * `... satisfies CommandParameterMap` or is the value of a
     * `parameters:` property / `readonly parameters =` class field.
     */
    function checkMapObject(objectNode) {
      if (!objectNode || objectNode.type !== "ObjectExpression") return;

      const keys = [];
      let hasSpread = false;
      for (const prop of objectNode.properties) {
        if (prop.type === "SpreadElement") {
          hasSpread = true;
          continue;
        }
        const name = propertyKeyName(prop);
        if (name) keys.push({ name, node: prop.key });
      }

      const hasCanonical = keys.some((k) => k.name === convention.canonical);
      if (hasCanonical) return;
      // Canonical may arrive via a spread this per-file rule cannot see —
      // skip rather than risk a false positive.
      if (hasSpread) return;

      for (const alias of convention.aliases) {
        const hit = keys.find((k) => k.name === alias);
        if (hit) {
          context.report({
            node: hit.node,
            messageId: "aliasWithoutCanonical",
            data: { family, alias, canonical: convention.canonical },
          });
        }
      }
    }

    return {
      // `{ ... } satisfies CommandParameterMap`
      TSSatisfiesExpression(node) {
        const t = node.typeAnnotation;
        if (
          t?.type === "TSTypeReference" &&
          t.typeName?.type === "Identifier" &&
          t.typeName.name === "CommandParameterMap"
        ) {
          checkMapObject(node.expression);
        }
      },

      // `parameters: { ... }` in registration object literals
      "Property[key.name='parameters']"(node) {
        checkMapObject(node.value);
      },

      // `readonly parameters = { ... }` class fields
      "PropertyDefinition[key.name='parameters']"(node) {
        checkMapObject(node.value);
      },
    };
  },
};

        },
      ],
    },
  },
  // === FILE SIZE RULES — TSX/JSX parity (mt#2592) ===
  // The two `max-lines` blocks above (warn @ 400, error @ 1500) scope only to
  // `**/*.ts` / `**/*.js`, so React components had NO file-size guard at all
  // (src/cockpit/web/pages/PlantFlowPage.tsx grew to 1646 lines invisibly).
  // Mirror both tiers here, narrowly, as their own config objects — do NOT
  // fold `.tsx`/`.jsx` into the big `**/*.ts`/`**/*.js` block above, which
  // would pull 30+ unrelated rules (custom rules, unused-vars, etc.) into
  // TSX/JSX scope as an unintended scope expansion (see mt#2592 spec,
  // "Out of scope: non-size lint rules for .tsx"). Component files run
  // longer than plain TS modules per unit of logic because JSX markup is
  // more line-dense than typical TS syntax; the warn tier is pragmatically
  // set higher than the .ts/.js tier (800 vs 400) so that today's largest
  // properly-scoped cockpit widgets (e.g. Credentials.tsx at 688 lines)
  // don't need individual disables, while still catching genuinely
  // oversized components. The error tier stays at 1500, matching .ts/.js.
  //
  // NOTE on `skipComments`: unlike the `.ts`/`.js` tiers above, both `.tsx`
  // tiers set `skipComments: false`. Two reasons: (1) the codebase's larger
  // cockpit pages/widgets (e.g. PlantFlowPage.tsx) carry substantial
  // architecture-rationale JSDoc headers — skipping comments would let a
  // file's *code* bulk grow arbitrarily while its ESLint-counted size stayed
  // artificially low, defeating the guard's purpose; (2) with
  // `skipComments: true` mirrored exactly, PlantFlowPage.tsx's ESLint-counted
  // line count (~1349, comments/blanks excluded) falls UNDER the 1500 error
  // threshold despite a raw `wc -l` of 1646 — which would make the
  // file-level `eslint-disable max-lines` comment below register as an
  // "Unused eslint-disable directive" (itself a warning, failing the
  // zero-warning `lint:strict` / pre-commit gate). `skipBlankLines: true` is
  // kept since blank lines carry no content either way.
  //
  // NOTE on ESLint flat-config rule merging: because both tiers configure the
  // SAME rule name (`max-lines`) with the SAME `files` glob, ESLint's flat
  // config resolution has the LATER-declared block's rule settings entirely
  // replace the earlier one for any file matching both — there is no
  // independent coexistence of a "warn at 800" and "error at 1500" signal.
  // In practice only the error tier below is ever active. This exactly
  // mirrors the pre-existing (undocumented) behavior of the `.ts`/`.js`
  // blocks above, where the warn-@-400 tier is likewise always superseded by
  // the later error-@-1500 tier. Fixing that pre-existing two-tier-coexistence
  // gap is out of scope for mt#2592 (which only extends coverage to
  // `.tsx`/`.jsx`); the warn tier is kept here for documented intent/parity
  // and in case a future change (e.g. a custom multi-severity rule) makes
  // both tiers independently effective.
  {
    files: ["**/*.tsx", "**/*.jsx"],
    rules: {
      "max-lines": [
        "warn",
        {
          max: 800,
          skipBlankLines: true,
          skipComments: false,
        },
      ],
    },
  },
  {
    files: ["**/*.tsx", "**/*.jsx"],
    rules: {
      "max-lines": [
        "error",
        {
          max: 1500,
          skipBlankLines: true,
          skipComments: false,
        },
      ],
    },
  },
  // === SKIPPED TEST ENFORCEMENT (test files only) ===
  {
    files: ["**/*.test.ts", "**/*.spec.ts"],
    rules: {
      "custom/no-skipped-tests": "error", // Prevent .skip() and .todo() in test files (mt#1151)
    },
  },
  // === MAP-DERIVED COMMAND PARAM TYPES (mt#2779) + ENTITY-ID DRIFT (mt#2780) ===
  // Execute handlers in the shared-command tree must derive their param types
  // from the command's params map (InferParams<typeof map>) — hand-rolled
  // *Params interfaces let handlers read undeclared keys that compile cleanly
  // and are always undefined at runtime (the mt#2742 Detector-B class).
  // no-entity-id-param-drift covers the sibling Detector-A class: a family map
  // declaring the back-compat alias id-name (`task`) without the family's
  // canonical (`taskId`) — the mt#2741 drift shape, caught at authoring time.
  // Test files are excluded: partial-fixture casts are the legitimate seam.
  {
    files: ["src/adapters/shared/commands/**/*.ts"],
    ignores: ["**/*.test.ts"],
    rules: {
      "custom/no-hand-rolled-command-params": "error",
      "custom/no-entity-id-param-drift": "error",
    },
  },
];

/**
 * ToolPayload — content-type dispatcher for tool-call inputs and tool-result
 * content in the conversation view (mt#2552).
 *
 * Deterministic 2-way dispatch (see mt#2552 Implementation decisions):
 *   - JSON (structured value, or a string/text-block that JSON.parses to
 *     object/array) → a per-tool typed renderer if one is registered (Tier 3),
 *     else the generic `<JsonView>` (Tier 1 + Tier 2).
 *   - everything else → `<pre>` (unchanged raw text; no fuzzy prose detection).
 *
 * @see ../lib/tool-payload.ts — classifyToolPayload (the pure classifier)
 * @see ./JsonView.tsx — the generic tree + entity-enriched leaves
 */
import type { ReactNode } from "react";
import { Link } from "react-router-dom";
import { cn } from "../lib/utils";
import { JsonView } from "./JsonView";
import { classifyToolPayload } from "../lib/tool-payload";
import { entityToPath } from "../lib/entity-codec";
import { parseToolName } from "../lib/tool-name";
import type { EntityIndex } from "../lib/entity-linkifier";

// ── Tier-3 registry — per-tool typed renderers ──────────────────────────────────
//
// Keyed by BARE tool name (`tasks_list`, not `mcp__minsky__tasks_list`) — the
// dispatcher normalizes raw transcript names via parseToolName before lookup
// (mt#2787). A renderer returns a ReactNode for a richer, domain rendering, or
// `null` to fall back to the generic JsonView (so a shape mismatch degrades
// gracefully). Per mt#2552 principal direction the registry ships with a SMALL
// seed set as proof-of-pattern; broader per-tool coverage is added reactively
// for high-traffic tools — do NOT pre-build it.

export type ToolResultRenderer = (data: unknown, entityIndex?: EntityIndex) => ReactNode | null;

/** Extract a task-like array from common list-result shapes; null if it doesn't fit. */
function asTaskArray(data: unknown): Array<Record<string, unknown>> | null {
  const arr = Array.isArray(data)
    ? data
    : data && typeof data === "object" && Array.isArray((data as { tasks?: unknown }).tasks)
      ? (data as { tasks: unknown[] }).tasks
      : data && typeof data === "object" && Array.isArray((data as { results?: unknown }).results)
        ? (data as { results: unknown[] }).results
        : null;
  if (!arr || arr.length === 0) return null;
  const ok = arr.every(
    (t) => t !== null && typeof t === "object" && typeof (t as { id?: unknown }).id === "string"
  );
  return ok ? (arr as Array<Record<string, unknown>>) : null;
}

/** Seed renderer (proof-of-pattern): a compact, linked task list. */
function renderTasksList(data: unknown): ReactNode | null {
  const tasks = asTaskArray(data);
  if (!tasks) return null; // shape mismatch → generic tree
  return (
    <ul className="space-y-0.5 text-xs">
      {tasks.map((t, i) => {
        const id = String(t.id);
        const title = typeof t.title === "string" ? t.title : "";
        const status = typeof t.status === "string" ? t.status : "";
        return (
          <li key={i} className="flex items-baseline gap-2">
            <Link
              to={entityToPath("task", id)}
              className="font-mono text-primary underline-offset-2 hover:underline"
            >
              {id}
            </Link>
            {title && <span className="truncate text-foreground/80">{title}</span>}
            {status && <span className="ml-auto text-[10px] text-muted-foreground">{status}</span>}
          </li>
        );
      })}
    </ul>
  );
}

export const TOOL_RESULT_RENDERERS: Record<string, ToolResultRenderer> = {
  tasks_list: renderTasksList,
};

// ── Dispatcher ──────────────────────────────────────────────────────────────────

export interface ToolPayloadProps {
  value: unknown;
  /** MCP tool name — selects a Tier-3 renderer when one is registered. */
  toolName?: string;
  entityIndex?: EntityIndex;
  /** Wrapper styling (border/tone) supplied by the host (ToolCall vs ToolResult). */
  className?: string;
}

/**
 * Render a tool payload. Returns null for empty payloads (the caller renders
 * nothing). JSON → Tier-3 renderer or JsonView; non-JSON → `<pre>`.
 */
export function ToolPayload({ value, toolName, entityIndex, className }: ToolPayloadProps) {
  const classified = classifyToolPayload(value);

  if (classified.kind === "text") {
    if (classified.text.length === 0) return null;
    return (
      <pre
        className={cn(
          "max-h-48 overflow-auto whitespace-pre-wrap break-words border-t px-2 py-1 text-xs",
          className
        )}
      >
        {classified.text}
      </pre>
    );
  }

  // Registry keys are BARE tool names; transcripts carry the harness-prefixed
  // form (`mcp__minsky__tasks_list`), so normalize before lookup (mt#2787).
  const custom = toolName ? TOOL_RESULT_RENDERERS[parseToolName(toolName).name] : undefined;
  const rendered = custom ? custom(classified.data, entityIndex) : null;
  return (
    <div className={cn("max-h-72 overflow-auto border-t px-2 py-1", className)}>
      {rendered ?? <JsonView data={classified.data} entityIndex={entityIndex} />}
    </div>
  );
}

