/**
 * Locate a manifest node by dotted command-ID path (e.g., "tasks.dispatch"
 * → manifest.subcommands["tasks"].subcommands["dispatch"]). Returns undefined
 * if any segment doesn't match (the command may be lazy-loaded but not yet
 * wired into the Commander tree, or it may be hidden).
 */
function findNodeByCommandId(
  root: ManifestCommand,
  commandId: string
): ManifestCommand | undefined {
  const segments = commandId.split(".");
  let cur: ManifestCommand | undefined = root;
  for (const seg of segments) {
    if (!cur?.subcommands) return undefined;
    cur = cur.subcommands.find((s) => s.name === seg);
    if (!cur) return undefined;
  }
  return cur;
}

async function main() {
  const container = await createCliContainer();
  try {
    const cli = await createCli(container);

    // Pass 1: structural walk of the Commander tree.
    const manifest = walkCommand(cli);

    // Pass 2: enrich with Zod-derived enum values from the shared registry.
    let valuesInjected = 0;
    let valuesAttempted = 0;
    for (const cmd of sharedCommandRegistry.getAllCommands()) {
      const node = findNodeByCommandId(manifest, cmd.id);
      if (!node) continue; // command not in the visible Commander tree
      for (const [paramName, paramDef] of Object.entries(cmd.parameters || {})) {
        const values = extractEnumValues(paramDef.schema);
        if (!values || values.length === 0) continue;
        valuesAttempted++;
        const flagName = paramNameToFlag(paramName);
        if (injectValues(node, flagName, values)) valuesInjected++;
      }
    }

    // Generation banner for the generated-file-edit guard hook (CLAUDE.md).
    // The "do not edit directly" phrase matches the hook's verbal pattern.
    const wrapped = {
      _generated: "by scripts/build-completion-manifest.ts — do not edit directly",
      ...manifest,
    };

    const outPath = join(import.meta.dir, "..", "src", "generated", "completion-manifest.json");
    mkdirSync(dirname(outPath), { recursive: true });

    // Format the serialized manifest with the project's Prettier (resolving the
    // same .prettierrc.json config that `format:check` uses) so the generator's
    // own output byte-matches the committed copy. Without this, the raw
    // `JSON.stringify` output (expanded short arrays, etc.) diverges from the
    // Prettier-formatted committed file, so every `bun run build` re-dirties the
    // tracked file and blocks `git pull --ff-only` (mt#2732). Making the
    // generator the single source of canonical format means all invocation
    // paths (build / pre-commit / manual) emit identical output — no downstream
    // re-formatting pass is needed (the mt#2622 pre-commit prettier pass was
    // removed as redundant alongside this change).
    const rawJson = `${JSON.stringify(wrapped, null, 2)}\n`;
    const prettierConfig = await resolveConfig(outPath);
    const formatted = await prettierFormat(rawJson, { ...prettierConfig, parser: "json" });
    writeFileSync(outPath, formatted);

    console.log(
      `Wrote completion manifest: ${outPath}\n` +
        `  Enum-value injections: ${valuesInjected}/${valuesAttempted} (` +
        `${valuesAttempted - valuesInjected} options not found in Commander tree)`
    );
  } finally {
    await container.close();
  }
}

await main();

/**
 * Per-review LLM cost/token/cache emission to Braintrust (mt#2723).
 *
 * Cost observability lives on the chosen LLM-observability platform (Braintrust,
 * trace-shape doc 35e937f0; strategy parent mt#1778) rather than being
 * reconstructed from Postgres + bespoke audits (the 2026-07-09 pain). Reuses the
 * shared fire-and-forget `emitBraintrustEvent`.
 *
 * Emits ONLY for model-invoking reviews (input tokens present). The two pre-model
 * skip paths (routing-skip, concurrent-inflight) carry no token data and emit
 * nothing. Called from `recordReviewTiming` — the single per-review choke that
 * already fires exactly once per review at the right paths.
 *
 * Never throws and never blocks the review path (instrumentation discipline).
 */

import { emitBraintrustEvent, type BraintrustEvent } from "@minsky/domain/observability/braintrust";
import type { ReviewTimingInput } from "./review-timing";

/** Braintrust `metadata.source` tag for query filtering. */
export const REVIEW_COST_SOURCE = "minsky.reviewer.cost";

/** Injectable emitter seam for tests. */
export type EmitFn = (event: BraintrustEvent) => Promise<void>;

/**
 * Build the Braintrust cost event from a review-timing input, or null when the
 * input is not a model-invoking review (no input-token data → nothing to emit).
 */
export function buildReviewCostEvent(input: ReviewTimingInput): BraintrustEvent | null {
  if (input.inputTokens == null) return null;
  const inputTokens = input.inputTokens;
  const cachedTokens = input.cachedTokens ?? null;
  const cacheHitRatio = cachedTokens != null && inputTokens > 0 ? cachedTokens / inputTokens : null;
  return {
    input: {
      pr_owner: input.prOwner,
      pr_repo: input.prRepo,
      pr_number: input.prNumber,
      model: input.model,
      provider: input.provider,
    },
    metadata: {
      source: REVIEW_COST_SOURCE,
      input_tokens: inputTokens,
      output_tokens: input.outputTokens ?? null,
      reasoning_tokens: input.reasoningTokens ?? null,
      cached_tokens: cachedTokens,
      cache_hit_ratio: cacheHitRatio,
      cost_usd: input.costUsd ?? null,
      iteration_index: input.iterationIndex,
      scope_classification: input.scopeClassification,
    },
  };
}

/**
 * Emit the per-review cost event (fire-and-forget). No-op for non-model-invoking
 * inputs. Never throws — instrumentation must not affect the review path even if
 * the injected emitter fails.
 */
export async function emitReviewCostEvent(
  input: ReviewTimingInput,
  emit: EmitFn = emitBraintrustEvent
): Promise<void> {
  try {
    const event = buildReviewCostEvent(input);
    if (!event) return;
    await emit(event);
  } catch {
    // Instrumentation failures never affect the review path.
  }
}

