    //   - result.comparisonRan === true (the listCommitsAhead probe
    //     actually executed — guards against the budget-exhausted-
    //     before-comparison path that returns mainRef without running
    //     the comparison; PR #963 R1 BLOCKING #6 fix).
    // Failure to write is non-fatal: surfaced as a warning so the operator
    // knows the CAS check won't fire on the next push (no worse than the
    // pre-mt#1522 baseline).
    if (
      input.tool_name === "mcp__minsky__session_commit" &&
      result.mainRef &&
      result.comparisonRan === true
    ) {
      const capturedSha = resolveRefSha(repoDir, result.mainRef);
      if (capturedSha === null) {
        warnings.push(
          `Could not resolve ${result.mainRef} to SHA for CAS marker — push-time CAS check will bypass`
        );
      } else {
        const writeResult = writeFreshnessMarker(repoDir, {
          mainRef: result.mainRef,
          sha: capturedSha,
          toolName: input.tool_name,
          ts: new Date().toISOString(),
        });
        if (!writeResult.ok) {
          warnings.push(
            `Could not write freshness marker (${writeResult.reason ?? "(no reason)"}) — push-time CAS check will bypass`
          );

 * Resolve the on-disk git directory for `repoDir`, honoring git's `.git`-as-file
 * indirection convention. Three cases:
 *
 *   1. `<repoDir>/.git` is a directory — return that path (typical clone).
 *   2. `<repoDir>/.git` is a FILE whose contents are `gitdir: <path>` —
 *      parse and return the resolved target (typical `git worktree` checkout
 *      and certain submodule layouts). Relative `<path>` is resolved against
 *      `repoDir` per git's spec.
 *   3. `<repoDir>/.git` is missing or unparseable — fall back to
 *      `<repoDir>/.git` so callers' downstream `existsSync` probes return
 *      false naturally (no exception thrown for the missing-repo case).
 *
 * The fs surface is injectable for test purposes; defaults to real fs.
 *
 * @see mt#1739 — added to support worktree-based session layouts where the
 *   freshness-guard's mid-merge detection would otherwise miss markers
 *   living under the resolved gitdir, reintroducing the deadlock this fix
 *   exists to close. PR #1054 R1 BLOCKING #1.
 */
export function resolveGitDir(repoDir: string, fs: MergeDetectFs = DEFAULT_FS): string {
  const dotGit = join(repoDir, ".git");
  if (!fs.existsSync(dotGit)) {
    return dotGit;
  }
  try {
    if (fs.statSync(dotGit).isDirectory()) {
      return dotGit;
    }
    const content = fs.readFileSync(dotGit, "utf-8");
    const match = content.match(/^gitdir:\s*(.+?)\s*$/m);
    if (match && match[1]) {
      const target = match[1].trim();
      return isAbsolute(target) ? target : resolve(repoDir, target);
    }
  } catch {
    // Fall through — any stat/read error falls back to the conventional path,
    // which callers handle via existsSync returning false.
  }
  return dotGit;
}

export function detectMergeInProgress(
  repoDir: string,
  fs: MergeDetectFs = DEFAULT_FS
): string | null {
  const gitDir = resolveGitDir(repoDir, fs);
  for (const marker of MERGE_IN_PROGRESS_MARKERS) {
    if (fs.existsSync(join(gitDir, marker))) {
      return marker;
    }
  }
  return null;
}

/**
 * Resolve the repository ROOT for `startDir`: walk parent directories until
 * one contains a `.git` entry (directory OR `gitdir:`-file — `resolveGitDir`
 * handles the indirection afterwards), falling back to `startDir` when no
 * `.git` exists anywhere up the tree (missing-repo case; downstream probes
 * then fail closed-to-allow exactly as before).
 *
 * Why this exists (mt#2700): the entrypoint passed `input.cwd` straight into
 * `detectMergeInProgress` and `writeFreshnessMarker`, but `input.cwd` tracks
 * the harness SHELL's working directory, which is routinely a SUBDIRECTORY
 * of the repo (e.g. `<session>/cockpit-tray/src-tauri` during a build). The
 * git subprocess probes (`git -C <dir>`) walk up to the repo root on their
 * own, so the freshness comparison stayed correct — but the fs-only marker
 * probe does NOT walk up, so a genuine in-progress merge at the repo root
 * was invisible and the mt#1739 carve-out silently failed to fire,
 * reintroducing the merge-completion deadlock it exists to close (observed
 * 2026-07-08, mt#2675 convergence). Same class: the mt#1522 CAS marker was
 * written under the subdirectory instead of the repo root, silently
 * bypassing session_commit's push-time CAS read.
 *
 * fs-only by design (no subprocess): mid-merge detection runs BEFORE the
 * wall-clock budget guard, which is safe only while it stays `existsSync`
 * probes. Cost is one probe per path segment.
 */
export function findRepoRoot(startDir: string, fs: MergeDetectFs = DEFAULT_FS): string {
  let dir = resolve(startDir);
  for (;;) {
    if (fs.existsSync(join(dir, ".git"))) {
      return dir;
    }
    const parent = dirname(dir);
    if (parent === dir) {
      // Filesystem root reached without finding a repo — fall back to the
      // original directory so callers' downstream probes fail naturally.
      return resolve(startDir);
    }
    dir = parent;
  }
}

/**
 * Detect the current HEAD branch name in the given working directory.
 * Returns null if HEAD is detached or the command fails.
 */
export function detectCurrentBranch(repoDir: string): string | null {
  const result = execWithPath(["git", "-C", repoDir, "rev-parse", "--abbrev-ref", "HEAD"], {
    timeout: GIT_TIMEOUT_MS,
  });
  if (result.exitCode !== 0 || !result.stdout.trim() || result.stdout.trim() === "HEAD") {
    return null;
  }
  return result.stdout.trim();
}

/**
 * Check whether origin/<branch> exists as a remote ref.
 * Returns false if the probe fails (e.g. branch not pushed yet — fresh branch).
 */
export function remoteBranchExists(repoDir: string, branch: string): boolean {
  const result = execWithPath(["git", "-C", repoDir, "rev-parse", "--verify", `origin/${branch}`], {
    timeout: GIT_TIMEOUT_MS,
  });
  return result.exitCode === 0;
}

/**
 * Check whether origin/main (or a detected default branch) exists.
 * Returns the default remote ref name, or null if undetectable.
 */
export function detectDefaultRemoteBranch(repoDir: string): string | null {
  // Probe 1: symbolic ref (fastest, exact answer when set)
  const symbolic = execWithPath(
    ["git", "-C", repoDir, "symbolic-ref", "refs/remotes/origin/HEAD"],
    { timeout: GIT_TIMEOUT_MS }
  );
  if (symbolic.exitCode === 0 && symbolic.stdout.trim()) {
    return symbolic.stdout.trim().replace(/^refs\/remotes\//, "");
  }

  // Probe 2: `git remote show origin` — parses "HEAD branch: <name>".
  // Matches parallel-work-guard.detectDefaultBranch so repos lacking the
  // symbolic ref but with a queryable origin still detect the right default.
  const remoteShow = execWithPath(["git", "-C", repoDir, "remote", "show", "origin"], {
    timeout: GIT_TIMEOUT_MS,
  });
  if (remoteShow.exitCode === 0) {
    const headMatch = remoteShow.stdout.match(/^\s*HEAD branch:\s*(\S+)\s*$/m);
    if (headMatch && headMatch[1] !== "(unknown)") {
      return `origin/${headMatch[1]}`;
    }
  }

  // Probes 3 and 4: try common defaults explicitly
  for (const candidate of ["main", "master"]) {
    const probe = execWithPath(
      ["git", "-C", repoDir, "rev-parse", "--verify", `origin/${candidate}`],
      { timeout: GIT_TIMEOUT_MS }
    );
    if (probe.exitCode === 0) {
      return `origin/${candidate}`;
    }
  }

  return null;
}

