let lastEmittedSha: string | null = null;

/** Test seam: reset the module-level dedup state between tests. */
export function resetDeploySmokeSweepStateForTests(): void {
  lastEmittedSha = null;
}

// ---------------------------------------------------------------------------
// Injectable deps — production wiring vs. test fakes
// ---------------------------------------------------------------------------

export interface DeploySmokeSweepDeps {
  /** The commit SHA to check, or null when there is none to check (see module doc). */
  getCommitSha: () => string | null;
  /** Fetch check-runs for the given commit SHA. */
  fetchChecksForSha: (sha: string) => Promise<CheckRunLike[]>;
}

/**
 * Build the real production deps: `RAILWAY_GIT_COMMIT_SHA` for the commit,
 * and a config-driven TokenProvider + Octokit for the GitHub Checks API call
 * — mirrors `buildTokenProviderFromConfig` in
 * `src/adapters/shared/commands/pr-watch.ts` / `reviewer-watch.ts`, but
 * container-free (this sweeper has no `CommandExecutionContext`; it reads
 * project configuration directly, the same way `getRepositoryBackendFromConfig`
 * is designed to be called).
 *
 * Returns `null` when the project's repository backend isn't GitHub-configured
 * (nothing to query check-runs against).
 */
async function buildRealDeps(): Promise<DeploySmokeSweepDeps | null> {
  const { getRepositoryBackendFromConfig } = await import(
    "@minsky/domain/session/repository-backend-detection"
  );
  const { github } = await getRepositoryBackendFromConfig();
  if (!github) {
    log.debug("deploy-smoke-sweep: no GitHub repository backend configured, skipping");
    return null;
  }

  return {
    getCommitSha: () => {
      const sha = process.env.RAILWAY_GIT_COMMIT_SHA;
      return typeof sha === "string" && sha.trim().length > 0 ? sha.trim() : null;
    },
    fetchChecksForSha: async (sha: string): Promise<CheckRunLike[]> => {
      const { getConfiguration } = await import("@minsky/domain/configuration/index");
      const { createTokenProvider } = await import("@minsky/domain/auth");
      const { createOctokit } = await import("@minsky/domain/repository/github-pr-operations");
      const { getCheckRunsForRef } = await import("@minsky/domain/repository/github-pr-checks");

      const cfg = getConfiguration();
      const tokenProvider = createTokenProvider(cfg.github ?? {}, cfg.github?.token ?? "");
      const token = await tokenProvider.getServiceToken(`${github.owner}/${github.repo}`);
      const octokit = createOctokit(token);
      const result = await getCheckRunsForRef(github, sha, octokit);
      return result.checks;
    },
  };
}

/**
 * Sweep tick: check whether the bundle-boot-smoke check-run for this
 * process's own deployed commit has completed, and emit a best-effort
 * `deploy.smoke` system event (once per distinct commit) if so.
 *
 * Never throws — every failure path (no commit SHA, no GitHub backend, API
 * error, emit failure) logs and returns.
 *
 * @param persistenceProvider - held directly (not resolved from a DI
 *   container — sweepers have no `CommandExecutionContext`), per the mt#2537
 *   template's `emitSystemEventFromProvider` variant.
 * @param deps - injectable for tests; defaults to the real production path.
 */
export async function triggerDeploySmokeSweep(
  persistenceProvider: PersistenceProvider | undefined,
  deps?: DeploySmokeSweepDeps
): Promise<void> {
  try {
    const resolvedDeps = deps ?? (await buildRealDeps());
    if (!resolvedDeps) return;

    const sha = resolvedDeps.getCommitSha();
    if (!sha) {
      log.debug(
        "deploy-smoke-sweep: no RAILWAY_GIT_COMMIT_SHA (not a GitHub-triggered Railway deploy), skipping"
      );
      return;
    }
    if (sha === lastEmittedSha) return; // already emitted for this deploy's commit

    const checks = await resolvedDeps.fetchChecksForSha(sha);
    const status = deriveSmokeStatus(checks);
    if (status === null) {
      log.debug("deploy-smoke-sweep: bundle-boot-smoke not completed yet, will retry", { sha });
      return; // not completed (or not present) yet — retry next tick
    }

    await emitSystemEventFromProvider(persistenceProvider, {
      eventType: "deploy.smoke",
      payload: { phase: "smoke", sha, status },
    });
    lastEmittedSha = sha;
    log.debug("deploy-smoke-sweep: emitted deploy.smoke", { sha, status });
  } catch (err) {
    log.warn("deploy-smoke-sweep: sweep failed (best-effort, swallowed)", {
      error: err instanceof Error ? err.message : String(err),
    });
  }
}

 */
export function computeLogResult(
  entry: CalibrationLogEntry,
  content: string,
  exists: boolean,
  watermark: LogWatermark | undefined
): CalibrationLogResult {
  const allRecords = exists ? parseCalibrationLines(content, entry.kind) : [];
  const watermarkCount = watermark?.lastReviewedCount ?? 0;
  const totalFires = allRecords.length;
  const firesSinceLastReview = Math.max(0, totalFires - watermarkCount);
  const newRecords = allRecords.slice(watermarkCount);

  const distinctPhrases = extractDistinctPhrases(newRecords).size;
  // The review threshold is DIVERSITY-AWARE (spec Success Criterion #3): a log is
  // only "past threshold" — i.e. worth surfacing for review — when it has enough
  // fires AND enough distinct shapes. Ten identical fires are NOT a review signal,
  // they're a uniform pattern; keep collecting until diversity arrives.
  const atCountThreshold = firesSinceLastReview >= FIRES_THRESHOLD;
  const hasDiversity = distinctPhrases >= DIVERSITY_THRESHOLD;
  const pastThreshold = atCountThreshold && hasDiversity;
  // lowDiversity: hit the fire count but not the diversity bar (the "keep
  // collecting" state, distinct from below-count and from past-threshold).
  const lowDiversity = atCountThreshold && !hasDiversity;

  return {
    entry,
    exists,
    totalFires,
    firesSinceLastReview,
    distinctPhrases,
    atCountThreshold,
    lowDiversity,
    pastThreshold,
    // Records are surfaced once the COUNT bar is hit (so a reviewer can see why a
    // log is low-diversity), even though the Ask only fires on pastThreshold.
    newRecords: atCountThreshold ? newRecords : [],
    watermarkCount,
    openAskId: watermark?.openAskId,
  };
}

/**
 * Compute results for all entries in the registry.
 *
 * @param entries      - registry (defaults to CALIBRATION_LOG_REGISTRY)
 * @param readContent  - function to read a log file; returns null if absent
 * @param watermarks   - current watermark store
 */
export async function runSweep(
  entries: CalibrationLogEntry[],
  readContent: (path: string) => Promise<string | null>,
  watermarks: WatermarkStore
): Promise<CalibrationLogResult[]> {
  const results: CalibrationLogResult[] = [];
  for (const entry of entries) {
    const content = await readContent(entry.path);
    const exists = content !== null;
    const watermark = watermarks[entry.path];
    results.push(computeLogResult(entry, content ?? "", exists, watermark));
  }
  return results;
}

/**
 * Produce an updated watermark store by advancing marks for all logs that
 * have been acknowledged (acked).
 *
 * Only advances the mark for logs whose path is in `ackedPaths`.
 * Returns a new store (does not mutate the input).
 *
 * @param current    - current watermark store
 * @param results    - sweep results (used to read current total counts)
 * @param ackedPaths - set of log paths whose watermarks should be advanced
 * @param now        - timestamp string to use for lastReviewedAt
 * @param askId      - optional ID of the disposition Ask the /calibration-review
 *                     skill just filed covering ALL acked logs in this pass
 *                     (mt#2659). When provided, recorded as `openAskId` on every
 *                     advanced watermark so the cadence detector can suppress its
 *                     per-turn warning in favor of a single pending-ask line
 *                     until the ask is resolved (see `clearResolvedAskIds`).
 */
export function advanceWatermarks(
  current: WatermarkStore,
  results: CalibrationLogResult[],
  ackedPaths: Set<string>,
  now: string,
  askId?: string
): WatermarkStore {
  const updated: WatermarkStore = { ...current };
  for (const result of results) {
    if (ackedPaths.has(result.entry.path)) {
      updated[result.entry.path] = {
        lastReviewedCount: result.totalFires,
        lastReviewedAt: now,
        ...(askId ? { openAskId: askId } : {}),
      };
    }
  }
  return updated;
}

/**
 * Clear `openAskId` from any watermark entries whose recorded ask id is in
 * `resolvedAskIds` (mt#2659).
 *
 * Does NOT touch `lastReviewedCount` / `lastReviewedAt` — this is purely the
 * "ask closed → resume normal cadence" transition, used once the
 * /calibration-review skill confirms (via `asks_list`) that a previously-filed
 * disposition ask has reached a terminal state (responded / closed /
 * cancelled / expired). Returns a new store (does not mutate the input); a
 * no-op (returns `current` unchanged, same reference) when `resolvedAskIds`
 * is empty.
 */
export function clearResolvedAskIds(
  current: WatermarkStore,
  resolvedAskIds: ReadonlySet<string>
): WatermarkStore {
  if (resolvedAskIds.size === 0) return current;
  const updated: WatermarkStore = { ...current };
  for (const [path, wm] of Object.entries(current)) {
    if (wm.openAskId && resolvedAskIds.has(wm.openAskId)) {
      const { openAskId: _drop, ...rest } = wm;
      updated[path] = rest;
    }
  }
  return updated;
}

