 * Best-effort throughout: a missing session record, an unreachable review
 * backend, or a git failure degrades individual fields to null rather than
 * failing the whole probe — the point of the probe is "return whatever
 * recovery-relevant state IS available in one call," not "fail unless every
 * signal is present."
 */
async function buildSessionDispatchRecoveryProbe(
  sessionIdOrTaskId: string,
  sessionWorkspacePath: string,
  gitStatus: { staged: string[]; unstaged: string[]; untracked: string[] },
  container?: import("@minsky/domain/composition/types").AppContainerInterface
): Promise<import("@minsky/domain/session/dispatch-recovery-probe").DispatchRecoveryProbeResult> {
  const { buildDispatchRecoveryProbe, parseCommitsAheadOutput } = await import(
    "@minsky/domain/session/dispatch-recovery-probe"
  );
  type SessionRecordType = import("@minsky/domain/session/types").SessionRecord;

  const sessionProvider =
    container?.has("sessionProvider") === true ? container.get("sessionProvider") : undefined;

  let sessionRecord: SessionRecordType | null = null;
  if (sessionProvider) {
    try {
      sessionRecord =
        (await sessionProvider.getSession(sessionIdOrTaskId)) ??
        (await sessionProvider.getSessionByTaskId(sessionIdOrTaskId)) ??
        null;
    } catch {
      sessionRecord = null;
    }
  }

  const resolvedSessionId = sessionRecord?.sessionId ?? sessionIdOrTaskId;
  const baseBranch = sessionRecord?.pullRequest?.baseBranch ?? "main";

  // Commits-ahead-of-base: local-ref comparison (no fetch — a per-call network
  // fetch would defeat the "one cheap call" point of the probe; the comparison
  // is against the last-fetched origin ref, same honesty tradeoff as
  // inject-git-state.ts's "vs last-fetched origin/<X>" framing).
  let commitsAheadOfBase: number | null = null;
  try {
    const proc = Bun.spawn(["git", "rev-list", "--count", `origin/${baseBranch}..HEAD`], {
      cwd: sessionWorkspacePath,
      stdout: "pipe",
      stderr: "pipe",
    });
    const out = await new Response(proc.stdout).text();
    await proc.exited;
    commitsAheadOfBase = proc.exitCode === 0 ? parseCommitsAheadOutput(out) : null;
  } catch {
    commitsAheadOfBase = null;
  }

  // handoff.md — convention: .minsky/sessions/<sessionId>/handoff.md within the
  // session's OWN workspace (see CLAUDE.md operating-envelope handoff convention).
  let handoffFileContent: string | null = null;
  try {
    const handoffPath = `${sessionWorkspacePath}/.minsky/sessions/${resolvedSessionId}/handoff.md`;
    const handoffBunFile = Bun.file(handoffPath);
    handoffFileContent = (await handoffBunFile.exists()) ? await handoffBunFile.text() : null;
  } catch {
    handoffFileContent = null;
  }

  // PR + latest review state.
  const prInfo = sessionRecord?.pullRequest;
  let latestReview: {
    state: string;
    reviewerLogin: string | null;
    submittedAt: string | null;
  } | null = null;
  let reviewFetchError: string | null = null;

  if (sessionRecord && prInfo?.number && sessionProvider) {
    try {
      const { createRepositoryBackendFromSession } = await import(
        "@minsky/domain/session/repository-backend-detection"
      );
      const backend = await createRepositoryBackendFromSession(sessionRecord, sessionProvider);
      const reviews = await backend.review?.listReviews?.(prInfo.number);
      if (reviews && reviews.length > 0) {
        const last = reviews[reviews.length - 1];
        if (last) {
          latestReview = {
            state: last.state,
            reviewerLogin: last.reviewerLogin ?? null,
            submittedAt: last.submittedAt ?? null,
          };
        }
      }
    } catch (err) {
      reviewFetchError = getErrorMessage(err);
    }
  }

  return buildDispatchRecoveryProbe({
    session: resolvedSessionId,
    gitStatus,
    commitsAheadOfBase,
    baseBranch: prInfo?.baseBranch ?? baseBranch,
    pr: {
      number: prInfo?.number ?? null,
      url: prInfo?.url ?? null,
      state: prInfo?.state ?? null,
      latestReview,
      reviewFetchError,
    },
    handoffFileContent,
  });
}

 * Resolve the last-commit timestamp for a subagent session's git branch by
 * shelling `git log -1 --format=%ct` in its on-disk workspace. Fails open
 * (returns null) when the session directory doesn't exist (already cleaned
 * up) or the git call fails — this is a best-effort activity signal, not a
 * hard dependency.
 */
export async function getSessionLastCommitAtMs(
  subagentSessionId: string | null
): Promise<number | null> {
  if (!subagentSessionId) return null;
  const sessionDir = path.join(getSessionsDir(), subagentSessionId);
  try {
    if (!fs.existsSync(sessionDir)) return null;
    const proc = Bun.spawn(["git", "log", "-1", "--format=%ct"], {
      cwd: sessionDir,
      stdout: "pipe",
      stderr: "pipe",
    });
    const output = await new Response(proc.stdout).text();
    await proc.exited;
    if (proc.exitCode !== 0) return null;
    const epochSeconds = Number.parseInt(output.trim(), 10);
    if (!Number.isFinite(epochSeconds)) return null;
    return epochSeconds * 1000;
  } catch {
    return null;
  }
}

/** Write a snapshot to the cache file (atomic temp+rename via the shared lifecycle helper). */
export function writeDispatchWatchdogCache(
  snapshot: DispatchWatchdogSnapshot,
  cachePath: string = getDispatchWatchdogCachePath()
): boolean {
  try {
    const dir = path.dirname(cachePath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    atomicWriteJSON(cachePath, snapshot);
    return true;
  } catch (err) {
    log.warn("dispatch-watchdog: failed to write cache", {
      message: err instanceof Error ? err.message : String(err),
    });
    return false;
  }
}

/**
 * Build the real dependency set from the cockpit's persistence/task-service
 * singletons plus the git/session-workspace activity signal. Returns null
 * when the DB is unavailable (non-SQL provider) so the sweeper tick can
 * skip cleanly.
 */
export async function buildRealDispatchWatchdogDeps(): Promise<DispatchWatchdogDeps | null> {
  const { getServerTaskService } = await import("./db-providers");
  const { getSharedPersistenceService } = await import("./shared-persistence");

  const svc = await getSharedPersistenceService();
  const provider = svc.getProvider();
  const getRawSql =
    "getRawSqlConnection" in provider &&
    typeof (provider as { getRawSqlConnection?: unknown }).getRawSqlConnection === "function"
      ? (provider as { getRawSqlConnection: () => Promise<unknown> }).getRawSqlConnection.bind(
          provider
        )
      : null;
  if (!getRawSql) return null;

  const sql = (await getRawSql()) as
    | { unsafe: (query: string, params?: unknown[]) => Promise<Array<Record<string, unknown>>> }
    | null
    | undefined;
  if (!sql) return null;

  const taskService = await getServerTaskService();

  return {
    listInFlightInvocations: async () => {
      const rows = (await sql.unsafe(
        `SELECT task_id, subagent_session_id, agent_type, started_at
         FROM subagent_invocations
         WHERE ended_at IS NULL`
      )) as Array<{
        task_id: string;
        subagent_session_id: string | null;
        agent_type: string;
        started_at: string | Date;
      }>;
      return rows.map((r) => ({
        taskId: r.task_id,
        subagentSessionId: r.subagent_session_id,
        agentType: r.agent_type,
        startedAt: r.started_at instanceof Date ? r.started_at.toISOString() : r.started_at,
      }));
    },
    getTaskStatus: async (taskId: string) => {
      if (!taskService) return null;
      try {
        return (await taskService.getTaskStatus(taskId)) ?? null;
      } catch {
        return null;
      }
    },
    getLastCommitAtMs: getSessionLastCommitAtMs,
    getLastEventAtMs: async (taskId, subagentSessionId) => {
      const rows = (await sql.unsafe(LAST_EVENT_AT_QUERY, [taskId, subagentSessionId])) as Array<{
        latest_at: string | number | null;
      }>;
      const raw = rows?.[0]?.latest_at;
      if (raw === null || raw === undefined) return null;
      const ms = Number(raw);
      return Number.isFinite(ms) ? ms : null;
    },
  };
}

/**
 * Query for the last related `system_events` row's timestamp, converted to
 * epoch-milliseconds.
 *
 * `system_events.created_at` is `timestamp with time zone` — casting it
 * directly to `::bigint` (as the sibling `prod-state-cache.ts` query does for
 * `drizzle.__drizzle_migrations.created_at`, a genuinely bigint column there)
 * is an INVALID Postgres cast and errors at query time. `extract(epoch from
 * ...)` converts the timestamptz to a numeric epoch-SECONDS value first,
 * which is then scaled to milliseconds (matching the ms unit every other
 * activity-signal timestamp in this module uses) before the bigint cast.
 */
export const LAST_EVENT_AT_QUERY = `SELECT (extract(epoch from max(created_at)) * 1000)::bigint AS latest_at
         FROM system_events
         WHERE related_task_id = $1 OR ($2::text IS NOT NULL AND related_session_id = $2)`;

/**
 * Refresh the dispatch-watchdog cache once. Fail-open: any error logs and
 * returns false, leaving the last-good cache in place — matches
 * `refreshProdStateCache`'s contract.
 */
export async function refreshDispatchWatchdogCache(
  nowMs: number = Date.now(),
  staleMs: number = DISPATCH_WATCHDOG_STALE_MS,
  cachePath?: string
): Promise<boolean> {
  try {
    const deps = await buildRealDispatchWatchdogDeps();
    if (!deps) {
      log.debug("dispatch-watchdog: no SQL-capable DB, skipping refresh");
      return false;
    }
    const snapshot = await buildDispatchWatchdogSnapshot(deps, nowMs, staleMs);
    const wrote = writeDispatchWatchdogCache(snapshot, cachePath);
    if (wrote) {
      DispatchWatchdogSweepTracker.getInstance().recordTick(snapshot.flags.length, nowMs);
    } else {
      DispatchWatchdogSweepTracker.getInstance().recordError(nowMs);
    }
    return wrote;
  } catch (err) {
    DispatchWatchdogSweepTracker.getInstance().recordError(nowMs);
    log.warn("dispatch-watchdog: refresh failed", {
      message: err instanceof Error ? err.message : String(err),
    });

