 * Core hook logic, parameterized for testability.
 *
 * Strategy: if the working tree has tracked modifications, stash before pulling
 * and pop after. This handles the common case where local experimental files
 * (e.g., scripts/cli-entry.ts) block the ff-only pull. If stash pop conflicts,
 * warn explicitly but leave main advanced.
 */
export function runHook(
  exec: typeof execSync,
  cwd: string,
  writeStderr: (msg: string) => void,
  exit: (code: number) => void
): void {
  // Record current HEAD before pull
  const beforeResult = exec(["git", "rev-parse", "HEAD"], { cwd });
  const before = beforeResult.exitCode === 0 ? beforeResult.stdout : "unknown";

  // Check if working tree has tracked modifications
  const statusResult = exec(["git", "status", "--porcelain"], { cwd });
  const isDirty = statusResult.exitCode === 0 && statusResult.stdout.trim().length > 0;

  // Stash tracked modifications if dirty
  let stashed = false;
  if (isDirty) {
    const stashResult = exec(["git", "stash", "-m", "post-merge-pull: auto-stash"], { cwd });
    stashed = stashResult.exitCode === 0 && !stashResult.stdout.includes("No local changes");
  }

  // Pull latest main
  const pullResult = exec(["git", "pull", "--ff-only", "origin", "main"], { cwd });

  if (pullResult.exitCode !== 0) {
    // Restore stash before reporting failure
    if (stashed) {
      const restoreResult = exec(["git", "stash", "pop"], { cwd });
      if (restoreResult.exitCode !== 0) {
        writeStderr(
          "Pull failed and stash restoration had conflicts.\n" +
            "Your working tree may have conflict markers. The stash entry was kept.\n" +
            "Resolve conflicts, then run: git stash drop\n"
        );
        exit(1);
        return;
      }
    }

    const isStaleLock = STALE_LOCK_STDERR_MARKERS.every((marker) =>
      pullResult.stderr.includes(marker)
    );

    if (isStaleLock) {
      writeStderr(
        "Stale `.git/index.lock` blocking pull. " +
          "If no git process is running, remove it manually: `rm .git/index.lock`\n"
      );
    } else if (pullResult.stderr.includes(DIRTY_TREE_STDERR_MARKER)) {
      writeStderr(
        "Post-merge pull failed: local changes conflict even after stash attempt.\n" +
          "Run `git pull --ff-only origin main` manually after resolving.\n"
      );
    } else {
      if (pullResult.stderr) {
        writeStderr(`${pullResult.stderr}\n`);
      }
      if (pullResult.stdout) {
        writeStderr(`${pullResult.stdout}\n`);
      }
    }

    exit(1);
    return;
  }

  // Pop stash if we stashed
  if (stashed) {
    const popResult = exec(["git", "stash", "pop"], { cwd });
    if (popResult.exitCode !== 0) {
      writeStderr(
        "Post-merge pull succeeded but stash pop had conflicts.\n" +
          "Your working tree has conflict markers; the stash entry was kept.\n" +
          "Resolve the conflicts, then run: git stash drop\n"
      );
    }
  }

  // Record HEAD after pull
  const afterResult = exec(["git", "rev-parse", "HEAD"], { cwd });
  const after = afterResult.exitCode === 0 ? afterResult.stdout : "unknown";

  // If HEAD changed, check if src/ files were modified
  if (before !== after && before !== "unknown") {
    const diffResult = exec(["git", "diff", "--name-only", before, after, "--", "src/"], {
      cwd,
    });
    if (diffResult.stdout) {
      process.stdout.write(
        "\n⚠️  Minsky source code updated by this merge.\n" +
          "   The running MCP server is using stale code.\n" +
          "   Run: /mcp then reconnect minsky\n\n"
      );
    }
  }

  exit(0);
}

// Main entrypoint — only runs when executed directly, not when imported by tests
if (import.meta.main) {
  runHook(execSync, projectDir, (s) => process.stderr.write(s), process.exit.bind(process));
}

#!/usr/bin/env bun
// PostToolUse hook: Validate task spec structure after tasks_create
//
// Blocks task creation if the spec content is missing required sections.
// Short specs (under 100 chars) pass through — not all tasks need full structure.
//
// Required sections: ## Success Criteria, ## Acceptance Tests

import { readInput, writeOutput } from "./types";
import type { ToolHookInput } from "./types";

const input = await readInput<ToolHookInput>();

// Get spec content from the tool input (spec or deprecated description alias)
const specContent =
  (input.tool_input.spec as string | undefined) ??
  (input.tool_input.description as string | undefined) ??
  "";

// Short specs pass through — quick tasks don't need full structure
if (specContent.length < 100) {
  process.exit(0);
}

// Check for required sections
const missingHeadings: string[] = [];

if (!/^## Success Criteria/m.test(specContent)) {
  missingHeadings.push("## Success Criteria");
}

if (!/^## Acceptance Tests/m.test(specContent)) {
  missingHeadings.push("## Acceptance Tests");
}

if (missingHeadings.length > 0) {
  const title = (input.tool_input.title as string) ?? "unknown";
  writeOutput({
    hookSpecificOutput: {
      hookEventName: "PostToolUse",
      additionalContext: [
        `⚠️ Task "${title}" spec is missing required sections: ${missingHeadings.join(", ")}`,
        "",
        "Task specs over 100 chars must include:",
        "  - ## Success Criteria — measurable criteria for task completion",
        "  - ## Acceptance Tests — concrete tests to verify the work",
        "",
        "Please update the task spec with the missing sections using tasks_spec_edit.",
      ].join("\n"),
    },
  });
  process.exit(1);
}

process.exit(0);

#!/usr/bin/env bun
// PreToolUse hook: deny Agent prompts that dispatch session work
// without being generated by session.generate_prompt.
//
// Detection: prompt references a session directory path OR instructs the agent
// to call session write MCP tools (by fully-qualified tool name).
// Tool-generated prompts contain the "minsky:prompt:v1" watermark.
// Hand-crafted session prompts lack the watermark → deny.
//
// Read-only subagent types are exempt — they can't write files or call MCP tools.

import { readInput, writeOutput } from "./types";
import type { ToolHookInput } from "./types";

const input = await readInput<ToolHookInput>();
const prompt = (input.tool_input.prompt as string) ?? "";
const subagentType = (input.tool_input.subagent_type as string) ?? "";

// Read-only subagent types are exempt — they cannot modify session state
const readOnlyTypes = new Set(["Explore", "claude-code-guide", "auditor", "Plan"]);
if (readOnlyTypes.has(subagentType)) {
  process.exit(0);
}

// Detect session work by looking for session directory paths or
// fully-qualified MCP session write tool names (not plain English mentions).
const sessionPathPattern = /\.local\/state\/minsky\/sessions\//;
const sessionWriteTools = [
  "mcp__minsky__session_commit",
  "mcp__minsky__session_pr_create",
  "mcp__minsky__session_pr_edit",
  "mcp__minsky__session_pr_approve",
  "mcp__minsky__session_pr_merge",
];
const hasSessionPath = sessionPathPattern.test(prompt);
const hasSessionWriteTool = sessionWriteTools.some((tool) => prompt.includes(tool));
const isSessionWork = hasSessionPath || hasSessionWriteTool;
const hasWatermark = prompt.includes("minsky:prompt:v1");

if (isSessionWork && !hasWatermark) {
  writeOutput({
    hookSpecificOutput: {
      hookEventName: "PreToolUse",
      permissionDecision: "deny",
      permissionDecisionReason:
        "Agent prompt dispatches session work but was not generated by session.generate_prompt. " +
        "Use mcp__minsky__session_generate_prompt to generate the prompt, then pass its output " +
        "directly to the Agent tool without modification.",
    },
  });
  process.exit(0);
}

process.exit(0);

