// the review lacks a spec verification or documentation impact section,
// the review is stale (covers an older commit than PR HEAD),
// no CI check_runs fired on the PR HEAD (mt#1309 webhook-miss regression detection),
// the bundle-boot smoke check failed (mt#1787 dev-vs-deployed divergence detection),
// or any branch-protection-required status check did not conclude success
// (mt#1938 generalized CI-status enforcement).
// Ensures code review, spec verification, documentation impact assessment,
// review freshness, CI presence, bundle-boot health, AND CI status before merging.

import { readInput, writeOutput, execSync } from "./types";
import type { ToolHookInput } from "./types";

// ---------------------------------------------------------------------------
// CI check_runs presence — exported for tests
// ---------------------------------------------------------------------------

export interface CheckRunsParseSuccess {
  ok: true;
  count: number;
}
export interface CheckRunsParseFailure {
  ok: false;
  error: string;
}
export type CheckRunsParseResult = CheckRunsParseSuccess | CheckRunsParseFailure;

export interface CheckRunsPresenceResult {
  deny: boolean;
  reason?: string;
}

// Parse a `gh api repos/.../commits/<sha>/check-runs` response. Distinguishes
// API/parse failure (exit code != 0, timeout, empty/non-JSON body, missing
// fields) from "zero check_runs" so the merge-gate can give an accurate
// diagnosis.
//
// The response shape is GitHub's Checks API: { total_count, check_runs[] }.
// We always trust total_count when present (canonical, pagination-safe). The
// caller queries with ?per_page=1 to keep the call cheap; check_runs.length is
// only a defensive fallback for unexpected response shapes — it is NOT a valid
// substitute for total_count when pagination is in play.
export function parseCheckRunsResponse(result: {
  exitCode: number;
  stdout: string;
  stderr: string;
  timedOut?: boolean;
}): CheckRunsParseResult {
  if (result.timedOut) {
    return {
      ok: false,
      error: `gh api timed out: ${result.stderr || "(no stderr)"}`,
    };
  }
  if (result.exitCode !== 0) {
    return {
      ok: false,
      error: `gh api exited ${result.exitCode}: ${result.stderr || "(no stderr)"}`,
    };
  }
  const trimmed = result.stdout.trim();
  if (!trimmed) {
    return { ok: false, error: "gh api returned empty response" };
  }
  let parsed: unknown;
  try {
    parsed = JSON.parse(trimmed);
  } catch (e) {
    return {
      ok: false,
      error: `failed to parse gh api response as JSON: ${(e as Error).message}`,
    };
  }
  if (!parsed || typeof parsed !== "object") {
    return { ok: false, error: "gh api response is not an object" };
  }
  const obj = parsed as { total_count?: unknown; check_runs?: unknown };
  if (typeof obj.total_count === "number") {
    return { ok: true, count: obj.total_count };
  }

   * instead of `--numstat`). Per-path commit counts are still computed.
   */
  nameOnly?: boolean;
  /** Cap the number of files returned, sorted by total churn (insertions + deletions) descending. */
  limit?: number;
}

export interface FileChurnStat {
  path: string;
  /** Number of distinct commits in the window that touched this path. */
  commits: number;
  insertions: number;
  deletions: number;
}

export interface GitStatsResult {
  workdir: string;
  since?: string;
  until?: string;
  path?: string;
  nameOnly: boolean;
  /** Number of distinct commits observed in the window (across all paths). */
  totalCommits: number;
  files: FileChurnStat[];
}

const COMMIT_HASH_RE = /^[0-9a-f]{40}$/;

interface FileAccumulator {
  commits: Set<string>;
  insertions: number;
  deletions: number;
}

/**
 * Parse the output of `git log --pretty=format:%H` combined with either
 * `--numstat` or `--name-only`. Both formats interleave a 40-char commit
 * hash line with per-file lines for that commit (separated by a blank
 * line, which this parser ignores). `--numstat` lines are tab-separated
 * `<insertions>\t<deletions>\t<path>` (or `-\t-\t<path>` for binary files);
 * `--name-only` lines are bare paths.
 */
function parseLogOutput(output: string): {
  files: Map<string, FileAccumulator>;
  totalCommits: number;
} {
  const files = new Map<string, FileAccumulator>();
  const seenCommits = new Set<string>();
  let currentHash: string | null = null;

  for (const rawLine of output.split("\n")) {
    const line = rawLine.trim();
    if (!line) continue;

    if (!line.includes("\t") && COMMIT_HASH_RE.test(line)) {
      currentHash = line;
      seenCommits.add(line);
      continue;
    }

    if (!currentHash) continue;

    let filePath: string;
    let insertions = 0;
    let deletions = 0;

    if (line.includes("\t")) {
      // --numstat line: "<insertions>\t<deletions>\t<path>"
      const parts = line.split("\t");
      if (parts.length < 3) continue;
      const [insStr, delStr, ...pathParts] = parts;
      filePath = pathParts.join("\t");
      insertions = insStr === "-" ? 0 : parseInt(insStr ?? "0", 10) || 0;
      deletions = delStr === "-" ? 0 : parseInt(delStr ?? "0", 10) || 0;
    } else {
      // --name-only line: bare path
      filePath = line;
    }

    if (!filePath) continue;

    let entry = files.get(filePath);
    if (!entry) {
      entry = { commits: new Set(), insertions: 0, deletions: 0 };
      files.set(filePath, entry);
    }
    entry.commits.add(currentHash);
    entry.insertions += insertions;
    entry.deletions += deletions;
  }

  return { files, totalCommits: seenCommits.size };
}

/**
 * Compute per-path churn (commit count + insertions/deletions) over a
 * window, via `git log --numstat` (or `--name-only` when `nameOnly` is
 * set). Renames are intentionally NOT collapsed (`--no-renames` is always
 * passed) so results are deterministic regardless of the caller's
 * `diff.renames` config — a rename is counted as a full delete of the old
 * path plus a full add of the new path, which is defensible for churn
 * analysis (a rename is itself a churn event).
 */
export async function gitStatsImpl(
  options: GitStatsOptions,
  deps: GitStatsDependencies
): Promise<GitStatsResult> {
  const workdir = options.repoPath ?? validateProcess(process).cwd();
  const qWorkdir = shellQuote(workdir);
  const nameOnly = options.nameOnly ?? false;

  const args: string[] = ["git", "-C", qWorkdir, "log", "--no-renames"];
  args.push(nameOnly ? "--name-only" : "--numstat");
  args.push("--pretty=format:%H");

  if (options.since) {
    args.push(`--since=${shellQuote(options.since)}`);
  }
  if (options.until) {
    args.push(`--until=${shellQuote(options.until)}`);
  }
  if (options.author) {
    args.push(`--author=${shellQuote(options.author)}`);
  }
  if (options.path) {
    args.push("--", shellQuote(options.path));
  }

  const { stdout } = await deps.execAsync(args.join(" "));
  const { files: fileMap, totalCommits } = parseLogOutput(stdout);

  let files: FileChurnStat[] = Array.from(fileMap.entries()).map(([path, stat]) => ({
    path,
    commits: stat.commits.size,
    insertions: stat.insertions,
    deletions: stat.deletions,
  }));

  files.sort((a, b) => {
    const churnDiff = b.insertions + b.deletions - (a.insertions + a.deletions);
    return churnDiff !== 0 ? churnDiff : b.commits - a.commits;
  });

  if (typeof options.limit === "number" && options.limit >= 0) {
    files = files.slice(0, options.limit);
  }

  return {
    workdir,
    since: options.since,
    until: options.until,
    path: options.path,
    nameOnly,
    totalCommits,
    files,
  };
}

 */
async function resolveSessionToRepo(
  session: string | undefined,
  repo: string | undefined,
  container?: AppContainerInterface
): Promise<string | undefined> {
  if (session && !repo && container?.has("sessionProvider")) {
    const sessionProvider = container.get("sessionProvider");
    return await sessionProvider.getSessionWorkdir(session);
  }
  return repo;
}

