 *   data: <json>\n
 *   \n
 */
function writeSseEvent(res: express.Response, event: SseEvent): void {
  res.write(`id: ${event.id}\n`);
  res.write(
    `data: ${JSON.stringify({ channel: event.channel, payload: event.payload, at: event.at })}\n`
  );
  res.write("\n");
}

