export function createCockpitServer(opts: CockpitServerOptions = {}): express.Express {
  // Resolve the effective registry (builtins + any test-injected widgets).
  // The registry is the single source of truth for which widgets exist; a
  // registered widget's data endpoint is always served. There is no per-widget
  // enable flag — capability (does the widget exist) is decoupled from layout
  // (which cards the home dashboard renders, decided on the frontend). See mt#2294.
  const effectiveRegistry: WidgetRegistry = {
    ...WIDGET_REGISTRY,
    ...(opts.overrideRegistry ?? {}),
  };

  // AskRepository override for tests
  const askRepoOverride = opts.overrideAskRepository ?? null;

  // SseBroker override for tests
  const sseBrokerOverride = opts.overrideSseBroker ?? null;

  // Credential module override for tests
  const credModuleOverride = opts.overrideCredentialModule ?? null;

  // Every registered widget is available; the data endpoint is registry-gated.
  const availableWidgets = new Map<string, WidgetModule>(Object.entries(effectiveRegistry));

  // Inform basic-health of the loaded widget count
  setLoadedWidgetCount(availableWidgets.size);

  const app = express();
  app.use(express.json());

  // Preview-mode guard (mt#2096): block mutation endpoints in preview deploys.
  // Defense-in-depth API layer — paired with a read-only Supabase DB role.
  if (process.env.MINSKY_COCKPIT_PREVIEW === "true") {
    app.use("/api", (req, res, next) => {
      if (req.method === "GET" || req.method === "HEAD" || req.method === "OPTIONS") {
        next();
        return;
      }
      res.status(403).json({
        error: "Preview mode: mutations are disabled",
        preview: true,
      });
    });
  }

  // --- API endpoints ---

  /** GET /api/health */
  app.get("/api/health", (_req, res) => {
    const uptimeSec = Math.floor((Date.now() - serverStartTime) / 1000);
    let version = "unknown";
    try {
      // Attempt to read version from package.json relative to project root
      const pkgPath = path.join(__dirname, "..", "..", "package.json");
      const raw = String(fs.readFileSync(pkgPath));
      const pkg = JSON.parse(raw) as { version?: string };
      version = pkg.version ?? "unknown";
    } catch {
      // fallback: unknown
    }
    // Transcript watcher observability (mt#2320 SC2/SC5): the watcher runs in
    // THIS cockpit process, so its tracker singleton is readable here directly
    // (it is intentionally not on debug_systemInfo, which is a different
    // process). Exposes aggregate counters + the per-session freshness registry.
    const watcherTracker = TranscriptWatcherTracker.getInstance();
    // Transcript sweep backstop observability (mt#2321 SC3): the sweep also runs
    // in THIS cockpit process. Aggregate counters only; no raw error strings
    // (redaction policy — same as the watcher tracker above, per reviewer R1 on
    // mt#2320).
    const sweepTracker = TranscriptSweepTracker.getInstance();

    // mt#2578 watchdog TS slice: update the consecutive-degraded counter.
    // "ok" resets; anything else (degraded, unreachable, or unexpected) increments.
    const dbStatus = getDbStatus();
    if (dbStatus === "ok") {
      consecutiveDegradedCount = 0;
    } else {
      consecutiveDegradedCount++;
    }

    res.json({
      status: "ok",
      version,
      commit: getGitCommit(),
      uptimeSec,
      // gh#1761: last-known DB connection status. "ok" after a successful init;
      // "degraded" when a circuit-breaker or auth error has been received and
      // the retry loop is running; "unreachable" before any init attempt.
      // Read-only: does NOT probe the DB on every health poll.
      db: dbStatus,
      // mt#2578 watchdog fields — consumed by the tray's self-health watchdog.
      // processStartedAtMs: monotonic epoch-ms of when THIS process started.
      // A change between successive polls means the daemon restarted.
      processStartedAtMs: serverStartTime,
      // consecutiveDegraded: how many consecutive /api/health calls have seen
      // db !== "ok". Resets to 0 on "ok". Read-only mirror of consecutiveDegradedCount.
      consecutiveDegraded: consecutiveDegradedCount,
      transcriptWatcher: {
        ...watcherTracker.getSummary(),
        activeSessions: watcherTracker.getActiveSessions(),
      },
      transcriptSweep: sweepTracker.getSummary(),
    });
  });

  /** GET /api/widgets — metadata for every registered widget */
  app.get("/api/widgets", (_req, res) => {
    const widgets = Array.from(availableWidgets.values()).map((w) => ({
      id: w.id,
      title: w.title,
      updateMode: w.updateMode,
    }));
    res.json(widgets);
  });

  /** GET /api/widget/:id/data — registry-gated; 404 only for unregistered ids */
  app.get("/api/widget/:id/data", async (req, res) => {
    const widget = availableWidgets.get(req.params.id);
    if (!widget) {
      res.status(404).json({ error: "Widget not found" });
      return;
    }
    try {
      const query: Record<string, string> = {};
      for (const [k, v] of Object.entries(req.query)) {
        if (typeof v === "string") query[k] = v;
      }
      const data = await widget.fetch({ id: req.params.id, query });
      res.json(data);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      res.json({ state: "degraded", reason: `Widget crashed: ${message}` });
    }
  });

  /**
   * GET /api/tasks/ids — uncapped ids-only endpoint for the linkifier (mt#2518 R5).
   *
   * Returns: { ids: string[] } containing EVERY task id with no count cap.
   * Task ids are tiny (~2 KB for ~2K tasks) so fetching all is cheap.
   * This is the correct fetch target for the entity-index linkifier in
   * ConversationView — it must have a comprehensive id-set so every real
   * mt#NNNN reference in a transcript can be linked.
   *
   * The normal /api/tasks list carries a 500-cap (correct for the list UI)
   * and returns full objects. This route is ids-only and uncapped: it is NOT
   * a general-purpose task-list replacement.
   *
   * IMPORTANT: registered BEFORE /api/tasks/:id so "ids" is not interpreted
   * as a task id parameter by Express's first-match-wins routing.
   */
  app.get("/api/tasks/ids", async (req, res) => {
    try {
      const taskService = await getServerTaskService();
      if (!taskService) {
        res.status(503).json({
          error: "Task service unavailable — persistence provider not ready",
        });
        return;

  const getTokenProvider = deps.getTokenProvider ?? defaultGetTokenProvider;

  // Parameter schema enforces the outer cap of 1800s; clamp defensively here.
  const timeoutMs = clamp(params.timeoutSeconds ?? 600, 1, 1800) * 1000;
  // Polling interval: 15s default, clamped [5, 60] so callers can't hammer
  // the API (lower bound) or wait forever between checks (upper bound).
  const intervalMs = clamp(params.intervalSeconds ?? 15, 5, 60) * 1000;

  const start = now();

  // Validate explicit `params.since` up front. The default-`since`
  // resolution (PR `created_at`) happens AFTER backend creation since it
  // requires a backend call (`getPullRequestCreatedAt`). The explicit path
  // is validated here so caller-supplied bad timestamps fail fast.
  if (params.since !== undefined && Number.isNaN(Date.parse(params.since))) {
    throw new ValidationError(`Invalid --since timestamp: ${params.since}`);
  }

  try {
    // Resolve the reviewer filter ONCE up front. A TokenRole identifier
    // (`"reviewer"` / `"implementer"`) is converted to the configured App's
    // login here; literal logins pass through unchanged. Role-config errors
    // surface before any session/backend lookups so we fail fast on misconfig.
    const resolvedReviewer = await resolveReviewerFilter(params.reviewer, getTokenProvider);

    const resolvedContext = await resolveSessionContextWithFeedback({
      sessionId: params.sessionId,
      task: params.task,
      repo: params.repo,
      sessionProvider: sessionDB,
      allowAutoDetection: true,
    });

    const sessionRecord = await sessionDB.getSession(resolvedContext.sessionId);
    if (!sessionRecord) {
      throw new ResourceNotFoundError(`Session '${resolvedContext.sessionId}' not found`);
    }

    const prNumber = sessionRecord.pullRequest?.number;
    if (!prNumber) {
      throw new ResourceNotFoundError(
        `No pull request found for session '${resolvedContext.sessionId}'. ` +
          `Use 'minsky session pr create' to create a PR first.`
      );
    }

    const backend = await createBackend(sessionRecord, sessionDB);
    if (!backend.review.listReviews) {
      throw new MinskyError(
        `Repository backend does not support listing reviews. ` +
          `session_pr_wait_for_review requires a backend implementing ReviewOperations.listReviews.`
      );
    }

    // Resolve the `since` threshold (mt#2043):
    //   - explicit `params.since` wins; backend lookup is skipped.
    //   - otherwise look up PR `created_at` via the backend so pre-existing
    //     reviews match by default.
    //   - if the backend doesn't implement `getPullRequestCreatedAt`, fall
    //     back to call start (the previous default — preserves behavior on
    //     non-GitHub backends that haven't implemented the new method yet).
    let since: number;
    if (params.since !== undefined) {
      since = Date.parse(params.since);
    } else if (backend.review.getPullRequestCreatedAt) {
      const createdAt = await backend.review.getPullRequestCreatedAt(prNumber);
      const createdMs = Date.parse(createdAt);
      if (Number.isNaN(createdMs)) {
        // Backend returned a malformed timestamp — surface defensively
        // rather than silently coercing to call start. The agent's spec
        // promise is "default since = PR created_at"; if the backend can't
        // produce a usable value, the caller should know.
        throw new MinskyError(
          `Backend returned unparseable PR created_at: "${createdAt}". ` +
            `Pass an explicit \`since\` to bypass the default lookup.`
        );
      }
      since = createdMs;
    } else {
      // Non-GitHub backend with no PR-creation-time exposure. Falls back to
      // call-start semantics (the pre-mt#2043 default).
      since = start;
    }

    const sinceIso = new Date(since).toISOString();

    // Resolve the PR's current HEAD sha (mt#2586). When present, only reviews
    // submitted against this commit satisfy the wait, so a stale review of a
    // superseded commit no longer resolves a re-review wait. Skipped when the
    // caller opts out (requireCurrentHead === false) or the backend does not
    // implement getPullRequestHeadSha — in which case the `since` filter governs.
    let headSha: string | undefined;
    if (params.requireCurrentHead !== false && backend.review.getPullRequestHeadSha) {
      headSha = await backend.review.getPullRequestHeadSha(prNumber);
    }

    const deadline = start + timeoutMs;
    let pollCount = 0;
    // Track the most recent poll's reviews so the timeout payload can
    // surface them with per-entry rejection reasons (mt#2043).
    let lastReviews: ReviewListEntry[] = [];

    const buildTimeoutResult = (): SessionPrWaitForReviewTimeout => ({
      matched: false,
      elapsedMs: now() - start,
      pollCount,
      lastSeenReviews: annotateReviewRejections(lastReviews, since, resolvedReviewer, headSha),
      sinceUsed: sinceIso,
    });

    while (true) {
      // After the first poll, the sleep may have brought us exactly to (or
      // past) the deadline. Re-check before polling again so we never start
      // an API call that would overshoot the configured timeout. The
      // `pollCount > 0` guard guarantees at least one poll even on zero
      // or sub-interval budgets — the contract is "one check minimum."
      if (pollCount > 0 && now() >= deadline) {
        return buildTimeoutResult();
      }

      pollCount += 1;
      const reviews = await backend.review.listReviews(prNumber);
      lastReviews = reviews;
      const match = findMatchingReview(reviews, since, resolvedReviewer, headSha);
      if (match) {
        return {
          matched: true,
          review: match,
          elapsedMs: now() - start,
          pollCount,
        };
      }

      const remaining = deadline - now();
      if (remaining <= 0) {
        return buildTimeoutResult();
      }

      const sleepMs = Math.min(intervalMs, remaining);
      log.debug(
        `session_pr_wait_for_review: PR #${prNumber} poll ${pollCount} no match; ` +
          `sleeping ${Math.round(sleepMs / 1000)}s (${Math.round(remaining / 1000)}s remaining)`
      );
      await sleep(sleepMs);
    }
  } catch (error) {
    if (
      error instanceof ResourceNotFoundError ||
      error instanceof ValidationError ||
      error instanceof MinskyError
    ) {
      throw error;
    }
    throw new MinskyError(`Failed to wait for PR review: ${getErrorMessage(error)}`);
  }
}

/**
 * SEEDED BUG TARGET (mt#1515): off-by-one
 * DO NOT USE IN PRODUCTION.
 */

export function findFirstPositive(arr: number[]): number | undefined {
  // BUG: should be i < arr.length (strict less-than), not i <= arr.length.
  // The inclusive upper bound reads arr[arr.length] which is always undefined,
  // so the function may return undefined even when a positive element exists
  // at the last index.
  for (let i = 0; i <= arr.length; i++) {
    if (arr[i] > 0) return arr[i];
  }
  return undefined;
}

export function sumPositive(arr: number[]): number {
  let total = 0;
  // Same off-by-one: i <= arr.length causes arr[arr.length] (undefined) to
  // be coerced to NaN, which propagates through the addition.
  for (let i = 0; i <= arr.length; i++) {
    if (typeof arr[i] === "number" && arr[i] > 0) {
      total += arr[i];
    }
  }
  return total;
}

/**
 * SEEDED BUG TARGET (mt#1515): null-deref
 * DO NOT USE IN PRODUCTION.
 */

interface User {
  id: number;
  name: string;
  email: string | null;
}

export function formatGreeting(user: User | null): string {
  // BUG: accessing user.name without null check. When user is null this
  // throws "Cannot read properties of null (reading 'name')".
  return `Hello, ${user.name}!`;
}

export function getUserEmail(user: User | null): string {
  // Same bug: no null guard before accessing user.email.
  if (user.email !== null) {
    return user.email;
  }
  // BUG: user could be null here; accessing user.name throws.
  return user.name;
}

